  // Authentification locale par PIN (Lot 4A) — état renderer, en mémoire uniquement, jamais
  // persisté. `authSession` est le miroir de contrôle de l'UI : il n'est marqué `verified` qu'après
  // une vérification réussie côté main process (et un commit autoritaire). Perdu à chaque
  // rechargement du renderer -> réauthentification forcée. `authState` cache l'état des credentials
  // (présence d'un PIN, mustChange) tel que rapporté par le main, sans aucun secret.
  let authSession = { userId: "", verified: false };
  let authState = { available: false, users: {}, hasRecovery: false };
  let userSwitchInProgress = false;
  const history = { undo: [], redo: [] };
  const navigationHistory = { back: [], forward: [] };
  let contextTarget = null;
  let contextSelection = null;

  function showStartupScreen() {
    if (!app) return;
    app.innerHTML = `<div class="startup-screen">
      <div class="startup-card">
        <strong>Chargement de MonGestaClub...</strong>
        <span>Préparation des données du club...</span>
      </div>
    </div>`;
  }

  function startupMeasure(label, task) {
    const start = performance.now();
    console.time?.(`MonGestaClub ${label}`);
    try {
      return task();
    } finally {
      console.timeEnd?.(`MonGestaClub ${label}`);
      console.debug?.(`MonGestaClub ${label}: ${Math.round(performance.now() - start)} ms`);
    }
  }

  async function startupMeasureAsync(label, task) {
    const start = performance.now();
    console.time?.(`MonGestaClub ${label}`);
    try {
      return await task();
    } finally {
      console.timeEnd?.(`MonGestaClub ${label}`);
      console.debug?.(`MonGestaClub ${label}: ${Math.round(performance.now() - start)} ms`);
    }
  }

  function clone(value) {
    return JSON.parse(JSON.stringify(value));
  }

  function repairLegacyAccentText(value) {
    return String(value ?? "")
      .normalize("NFC")
      .replace(/\bL&dat\b/g, "Lédat")
      .replace(/\bFran‡aise\b/g, "Française")
      .replace(/\bfran‡aise\b/g, "française");
  }

  function normalizeProductText(value) {
    const oldName = ["Bu", "do"].join("");
    const oldProduct = [oldName, "Gestion"].join("\\s*");
    const oldProductHyphen = [oldName, "Gestion"].join("-");
    return asText(value)
      .replace(new RegExp(`\\b${oldProduct}\\b`, "gi"), "MonGestaClub")
      .replace(new RegExp(`\\b${oldProductHyphen}\\b`, "gi"), "MonGestaClub");
  }

  function repairLegacyAccentData(value, seen = new WeakSet()) {
    if (!value || typeof value !== "object") return value;
    if (seen.has(value)) return value;
    seen.add(value);
    if (Array.isArray(value)) {
      value.forEach((item, index) => {
        value[index] = typeof item === "string" ? repairLegacyAccentText(item) : repairLegacyAccentData(item, seen);
      });
      return value;
    }
    Object.keys(value).forEach((key) => {
      const item = value[key];
      value[key] = typeof item === "string" ? repairLegacyAccentText(item) : repairLegacyAccentData(item, seen);
    });
    return value;
  }

  function loadState() {
    const clubPayload = activeClubPayloadFromStorage();
    if (clubPayload?.state) return normalizeState(clubPayload.state);
    const seed = clone(window.MONGESTACLUB_SEED || {});
    try {
      const stored = appStorage.getItem(STORAGE_KEY) || appStorage.getItem(LEGACY_STORAGE_KEY);
      if (stored) {
        const normalized = normalizeState(JSON.parse(stored));
        return normalized;
      }
    } catch (error) {
      console.warn(error);
    }
    return normalizeState(seed);
  }

  function loadSettings() {
    const clubPayload = activeClubPayloadFromStorage();
    if (clubPayload?.settings) return normalizeSettings(clubPayload.settings);
    try {
      const stored = appStorage.getItem(SETTINGS_KEY) || appStorage.getItem(LEGACY_SETTINGS_KEY);
      if (stored) {
        const normalized = normalizeSettings(JSON.parse(stored));
        return normalized;
      }
    } catch (error) {
      console.warn(error);
    }
    return normalizeSettings({});
  }

  function parseJsonSafe(text, fallback = null) {
    if (!text) return fallback;
    try {
      return JSON.parse(text);
    } catch (error) {
      console.warn(error);
      return fallback;
    }
  }

  function rawClubStoreFromStorage() {
    return parseJsonSafe(appStorage.getItem(CLUBS_KEY), null);
  }

  function activeClubPayloadFromStorage() {
    const raw = rawClubStoreFromStorage();
    if (!raw || typeof raw !== "object") return null;
    const clubs = Array.isArray(raw.clubs) ? raw.clubs : [];
    const activeClubId = asText(appStorage.getItem(ACTIVE_CLUB_KEY) || raw.activeClubId || clubs.find((club) => club && club.archived !== true)?.id || clubs[0]?.id);
    return activeClubId ? raw.data?.[activeClubId] || null : null;
  }

  function ensureClubStoreInitialized() {
    try {
      const rawStore = rawClubStoreFromStorage();
      let store = normalizeClubStore(rawStore);
      let storeChanged = !rawStore || rawStore.version !== 1 || !Array.isArray(rawStore.clubs);
      if (!store.clubs.length) {
        backupLegacyLocalStorageBeforeClubMigration();
        const club = defaultClubIdentity(settings, state);
        const clubId = club.id;
        const scopedState = scopeStateToClub(normalizeState(clone(state)), clubId);
        const scopedSettings = settingsForClub(normalizeSettings(settings), club);
        store = {
          version: 1,
          migratedAt: new Date().toISOString(),
          activeClubId: clubId,
          clubs: [club],
          data: {
            [clubId]: {
              state: scopedState,
              settings: scopedSettings,
            },
          },
        };
        storeChanged = true;
      }
      store = normalizeClubStore(store);
      if (!store.activeClubId) {
        store.activeClubId = store.clubs.find((club) => !club.archived)?.id || store.clubs[0]?.id || "";
        storeChanged = true;
      }
      if (!store.activeClubId) throw new Error("Aucun club actif disponible.");
      for (const club of store.clubs) {
        const previousPayload = store.data[club.id];
        const previousPayloadJson = JSON.stringify(previousPayload || null);
        const nextPayload = previousPayload ? clone(previousPayload) : {
          state: normalizeState({}),
          settings: settingsForClub(normalizeSettings({}), club),
        };
        nextPayload.state = scopeStateToClub(normalizeState(nextPayload.state || {}), club.id);
        nextPayload.settings = settingsForClub(normalizeSettings(nextPayload.settings || {}), club);
        if (previousPayloadJson !== JSON.stringify(nextPayload)) storeChanged = true;
        store.data[club.id] = nextPayload;
      }
      if (storeChanged) {
        writeClubStore(store);
      } else {
        clubStore = store;
        if (store.activeClubId && appStorage.getItem(ACTIVE_CLUB_KEY) !== store.activeClubId) {
          appStorage.setItem(ACTIVE_CLUB_KEY, store.activeClubId);
        }
      }
      const activePayload = store.data[store.activeClubId];
      settings = normalizeSettings(activePayload.settings || settings);
      state = normalizeState(activePayload.state || state);
      return store;
    } catch (error) {
      console.error(error);
      ui.migrationError = "La migration multi-clubs a échoué. Les anciennes données n'ont pas été supprimées.";
      return normalizeClubStore(null);
    }
  }

  function normalizeClubStore(source = {}) {
    const rawClubs = Array.isArray(source?.clubs) ? source.clubs : [];
    const seen = new Set();
    const clubs = rawClubs.map(normalizeClubIdentity).filter((club) => {
      if (!club.id || seen.has(club.id)) return false;
      seen.add(club.id);
      return true;
    });
    const data = source?.data && typeof source.data === "object" ? { ...source.data } : {};
    const storedActive = asText(source?.activeClubId || appStorage.getItem(ACTIVE_CLUB_KEY));
    const activeClubId = clubs.some((club) => club.id === storedActive && !club.archived)
      ? storedActive
      : clubs.find((club) => !club.archived)?.id || clubs[0]?.id || "";
    return {
      version: 1,
      migratedAt: asText(source?.migratedAt || ""),
      activeClubId,
      clubs,
      data,
    };
  }

  function writeClubStore(store) {
    const normalized = normalizeClubStore(store);
    appStorage.setItem(CLUBS_KEY, JSON.stringify(normalized));
    if (normalized.activeClubId) appStorage.setItem(ACTIVE_CLUB_KEY, normalized.activeClubId);
    clubStore = normalized;
    return normalized;
  }

  // Fusion à l'import d'une sauvegarde, avec RESTAURATION réelle sur conflit de même ID (contrat
  // produit documenté dans l'aide : « Importer JSON restaure une sauvegarde précédemment exportée »).
  // - Club présent uniquement en local : conservé tel quel.
  // - Club présent uniquement dans la sauvegarde : ajouté avec ses données.
  // - Même clubId des deux côtés : l'identité et les données métier de la sauvegarde REMPLACENT la
  //   version locale (sinon l'import ne restaurerait jamais un club déjà existant modifié/dégradé
  //   localement — seuls les clubs entièrement absents localement en bénéficiaient auparavant).
  //   Les secrets locaux (settings.security par club) restent protégés en amont par
  //   preserveLocalSecurityOnImport, qui réinjecte la valeur locale avant cette fusion : ce
  //   remplacement ne les expose donc jamais à ceux (vidés) de la sauvegarde.
  function mergeImportedClubStore(importedStore) {
    const localStore = normalizeClubStore(clubStore || rawClubStoreFromStorage());
    if (!importedStore || !Array.isArray(importedStore.clubs)) return localStore;

    const importedClubIds = new Set(importedStore.clubs.map((club) => club.id).filter(Boolean));
    const localOnlyClubs = localStore.clubs.filter((club) => !importedClubIds.has(club.id));
    const mergedClubs = [...localOnlyClubs, ...importedStore.clubs.filter((club) => club.id)];

    const mergedData = { ...localStore.data };
    importedStore.clubs.forEach((club) => {
      if (club.id && importedStore.data?.[club.id]) mergedData[club.id] = importedStore.data[club.id];
    });

    // Club actif : priorité au local s'il reste valide (non archivé) après fusion, sinon celui de
    // la sauvegarde s'il est valide, sinon le premier club non archivé, sinon le premier club.
    const isValidActive = (id) => mergedClubs.some((club) => club.id === id && !club.archived);
    const resolvedActiveClubId = isValidActive(localStore.activeClubId)
      ? localStore.activeClubId
      : isValidActive(importedStore.activeClubId)
        ? importedStore.activeClubId
        : mergedClubs.find((club) => !club.archived)?.id || mergedClubs[0]?.id || "";

    return normalizeClubStore({
      ...localStore,
      clubs: mergedClubs,
      data: mergedData,
      activeClubId: resolvedActiveClubId,
    });
  }

  function backupLegacyLocalStorageBeforeClubMigration() {
    if (appStorage.getItem(CLUB_MIGRATION_BACKUP_KEY)) return;
    const backup = {
      kind: "mongestaclub-pre-multiclub-backup",
      version: 1,
      createdAt: new Date().toISOString(),
      values: {
        [STORAGE_KEY]: appStorage.getItem(STORAGE_KEY),
        [SETTINGS_KEY]: appStorage.getItem(SETTINGS_KEY),
        [LEGACY_STORAGE_KEY]: appStorage.getItem(LEGACY_STORAGE_KEY),
        [LEGACY_SETTINGS_KEY]: appStorage.getItem(LEGACY_SETTINGS_KEY),
      },
    };
    appStorage.setItem(CLUB_MIGRATION_BACKUP_KEY, JSON.stringify(backup));
  }

  function defaultClubIdentity(sourceSettings = {}, sourceState = {}) {
    const now = new Date().toISOString();
    const name = normalizeProductText(asText(sourceSettings.clubName || sourceSettings.name || "Mon club")) || "Mon club";
    const shortName = asText(sourceSettings.clubShortName || "").trim() || initialsForText(name) || "Club";
    const theme = themes.some((item) => item.id === sourceSettings.theme) ? sourceSettings.theme : "graphite";
    return normalizeClubIdentity({
      id: sourceSettings.clubId || id("club"),
      name,
      shortName,
      subtitle: asText(sourceSettings.clubSubtitle || "Gestion de club"),
      logoDataUrl: isLogoDataUrl(sourceSettings.logoDataUrl) ? sourceSettings.logoDataUrl : "",
      colors: {
        primary: "#1f2937",
        secondary: "#f59e0b",
        accent: "#22c55e",
      },
      theme,
      mainDiscipline: asText(sourceState.tariffs?.disciplines?.[0]?.name || ""),
      disciplines: (sourceState.tariffs?.disciplines || []).map((row) => asText(row.name)).filter(Boolean),
      season: normalizeSeasonSettings(sourceSettings.season),
      admin: {},
      contact: { country: "France" },
      managers: defaultClubManagers(),
      payments: {
        acceptedModes: ["cash", "check", "card"],
        maxSplitPayments: normalizePaymentCheckCount(sourceSettings.paymentCheckCount),
        maxChecks: normalizePaymentCheckCount(sourceSettings.paymentCheckCount),
        checkOrder: "",
        iban: "",
        bic: "",
        bankName: "",
        defaultConditions: "",
        scheduleMessage: "",
      },
      documents: {
        prefix: shortName.toUpperCase().replace(/[^A-Z0-9]/g, "").slice(0, 6) || "MGC",
        numberingFormat: `${shortName.toUpperCase().replace(/[^A-Z0-9]/g, "").slice(0, 6) || "MGC"}-2026-0001`,
        footer: "",
        legalMentions: "",
        paymentTerms: "",
        defaultMessage: "",
      },
      archived: false,
      createdAt: now,
      updatedAt: now,
    });
  }

  function defaultClubManagers() {
    return ["president", "treasurer", "secretary", "registrations", "shop", "payments", "admin"].map((role) => ({
      id: id("manager"),
      role,
      function: clubManagerLabels()[role] || role,
      lastName: "",
      firstName: "",
      email: "",
      phone: "",
      notes: "",
    }));
  }

  function clubManagerLabels() {
    return {
      president: "Président",
      treasurer: "Trésorier",
      secretary: "Secrétaire",
      registrations: "Responsable inscriptions",
      shop: "Responsable boutique",
      payments: "Responsable paiements",
      admin: "Responsable administratif",
    };
  }

  function normalizeClubIdentity(source = {}) {
    const now = new Date().toISOString();
    const name = asText(source.name || source.clubName || "Mon club") || "Mon club";
    const shortName = asText(source.shortName || source.sigle || initialsForText(name) || "Club");
    const managerRows = Array.isArray(source.managers) ? source.managers : defaultClubManagers();
    return {
      id: asText(source.id || source.clubId || id("club")),
      name,
      shortName,
      subtitle: asText(source.subtitle || source.clubSubtitle || "Gestion de club"),
      logoDataUrl: isLogoDataUrl(source.logoDataUrl) ? source.logoDataUrl : "",
      colors: {
        primary: cssColorToHex(source.colors?.primary, "#1f2937"),
        secondary: cssColorToHex(source.colors?.secondary, "#f59e0b"),
        accent: cssColorToHex(source.colors?.accent, "#22c55e"),
      },
      theme: themes.some((item) => item.id === source.theme) ? source.theme : "graphite",
      mainDiscipline: asText(source.mainDiscipline),
      disciplines: uniqueValues(Array.isArray(source.disciplines) ? source.disciplines : asText(source.disciplines).split(/[,;\n]/)),
      season: normalizeSeasonSettings(source.season),
      admin: {
        legalStatus: asText(source.admin?.legalStatus),
        rna: asText(source.admin?.rna),
        siret: asText(source.admin?.siret),
        siren: asText(source.admin?.siren),
        apeNaf: asText(source.admin?.apeNaf),
        vatNumber: asText(source.admin?.vatNumber),
        vatRegime: asText(source.admin?.vatRegime),
        vatMention: asText(source.admin?.vatMention || (isVatRegimeExempt(source.admin?.vatRegime) ? "TVA non applicable, art. 293 B du CGI" : "")),
        creationDate: dateInputValue(source.admin?.creationDate),
        federation: asText(source.admin?.federation),
        federationNumber: asText(source.admin?.federationNumber),
        approvalNumber: asText(source.admin?.approvalNumber),
      },
      contact: {
        address: asText(source.contact?.address),
        address2: asText(source.contact?.address2),
        postalCode: postalCodeValue(source.contact?.postalCode),
        city: asText(source.contact?.city),
        country: asText(source.contact?.country || "France"),
        phone: asText(source.contact?.phone),
        email: asText(source.contact?.email),
        website: asText(source.contact?.website),
        social: asText(source.contact?.social),
      },
      managers: managerRows.map((manager, index) => ({
        id: asText(manager.id || id("manager")),
        role: asText(manager.role || Object.keys(clubManagerLabels())[index] || "admin"),
        function: asText(manager.function || clubManagerLabels()[manager.role] || manager.role),
        lastName: asText(manager.lastName),
        firstName: asText(manager.firstName),
        email: asText(manager.email),
        phone: asText(manager.phone),
        notes: asText(manager.notes),
      })),
      payments: {
        acceptedModes: Array.isArray(source.payments?.acceptedModes) ? uniqueValues(source.payments.acceptedModes.map(normalizePaymentModeKey).filter(Boolean)) : ["cash", "check", "card"],
        maxSplitPayments: normalizePaymentCheckCount(source.payments?.maxSplitPayments ?? source.payments?.paymentCheckCount),
        maxChecks: normalizePaymentCheckCount(source.payments?.maxChecks ?? source.payments?.maxSplitPayments),
        checkOrder: asText(source.payments?.checkOrder),
        iban: asText(source.payments?.iban),
        bic: asText(source.payments?.bic),
        bankName: asText(source.payments?.bankName),
        defaultConditions: asText(source.payments?.defaultConditions),
        scheduleMessage: asText(source.payments?.scheduleMessage),
      },
      documents: {
        prefix: asText(source.documents?.prefix || "MGC"),
        numberingFormat: asText(source.documents?.numberingFormat || "MGC-2026-0001"),
        footer: asText(source.documents?.footer),
        legalMentions: asText(source.documents?.legalMentions),
        paymentTerms: asText(source.documents?.paymentTerms),
        defaultMessage: asText(source.documents?.defaultMessage),
      },
      archived: Boolean(source.archived),
      createdAt: source.createdAt || now,
      updatedAt: source.updatedAt || now,
    };
  }

  function initialsForText(value) {
    return asText(value).split(/\s+/).map((part) => part.charAt(0)).join("").slice(0, 6).toUpperCase();
  }

  function activeClubId() {
    return clubStore?.activeClubId || appStorage.getItem(ACTIVE_CLUB_KEY) || "";
  }

  function activeClub() {
    const store = clubStore || normalizeClubStore(rawClubStoreFromStorage());
    return store.clubs.find((club) => club.id === store.activeClubId) || store.clubs[0] || null;
  }

  function settingsForClub(sourceSettings = {}, club = activeClub()) {
    const normalized = normalizeSettings(sourceSettings);
    if (!club) return normalized;
    return normalizeSettings({
      ...normalized,
      clubId: club.id,
      clubName: club.name,
      clubSubtitle: club.subtitle,
      logoDataUrl: club.logoDataUrl || normalized.logoDataUrl,
      theme: club.theme || normalized.theme,
      paymentCheckCount: club.payments?.maxSplitPayments || normalized.paymentCheckCount,
      season: club.season || normalized.season,
    });
  }

  function updateActiveClubFromSettings(store = clubStore) {
    if (!store?.activeClubId) return store;
    const index = store.clubs.findIndex((club) => club.id === store.activeClubId);
    if (index < 0) return store;
    const club = normalizeClubIdentity({
      ...store.clubs[index],
      name: settings.clubName || store.clubs[index].name,
      subtitle: settings.clubSubtitle || store.clubs[index].subtitle,
      logoDataUrl: settings.logoDataUrl || "",
      theme: settings.theme,
      season: settings.season,
      payments: {
        ...store.clubs[index].payments,
        maxSplitPayments: settings.paymentCheckCount,
      },
      updatedAt: new Date().toISOString(),
    });
    store.clubs[index] = club;
    return store;
  }

  // options.rebrand = true : duplication d'un club. On garde TOUTES les lignes du state
  // source (même si leur clubId est celui d'un autre club) et on les ré-estampille avec le
  // nouveau clubId. Les ids internes sont conservés → relations intactes ; le stockage par
  // club étant séparé, la copie reste totalement indépendante de l'original.
  function scopeStateToClub(sourceState, clubId, options = {}) {
    const scoped = normalizeState(clone(sourceState || {}));
    const keep = options.rebrand ? () => true : (row) => !asText(row.clubId) || row.clubId === clubId;
    const stamp = (row) => {
      if (!row || typeof row !== "object") return row;
      row.clubId = clubId;
      if (Array.isArray(row.payments)) row.payments.forEach((payment) => payment.clubId = clubId);
      if (Array.isArray(row.paymentsSnapshot)) row.paymentsSnapshot.forEach((payment) => payment.clubId = clubId);
      if (row.event?.payments) row.event.payments.forEach((payment) => payment.clubId = clubId);
      if (row.lodging?.payments) row.lodging.payments.forEach((payment) => payment.clubId = clubId);
      return row;
    };
    scoped.contacts.members = (scoped.contacts.members || []).filter(keep).map(stamp);
    scoped.contacts.prospects = (scoped.contacts.prospects || []).filter(keep).map(stamp);
    scoped.memberships = (scoped.memberships || []).filter(keep).map(stamp);
    scoped.shopOrders = (scoped.shopOrders || []).filter(keep).map(stamp);
    scoped.invoices = (scoped.invoices || []).filter(keep).map(stamp);
    scoped.tariffs.articles = (scoped.tariffs.articles || []).filter(keep).map(stamp);
    scoped.tariffs.disciplines = (scoped.tariffs.disciplines || []).filter(keep).map(stamp);
    scoped.tariffs.insurance = (scoped.tariffs.insurance || []).filter(keep).map(stamp);
    scoped.tariffs.stages = (scoped.tariffs.stages || []).filter(keep).map(stamp);
    scoped.notes = (scoped.notes || []).filter(keep).map(stamp);
    scoped.coaches = (scoped.coaches || []).filter(keep).map(stamp);
    scoped.coachReplacements = (scoped.coachReplacements || []).filter(keep).map(stamp);
    scoped.rooms = (scoped.rooms || []).filter(keep).map(stamp);
    scoped.roomReplacements = (scoped.roomReplacements || []).filter(keep).map(stamp);
    scoped.expenses = (scoped.expenses || []).filter(keep).map(stamp);
    scoped.creditNotes = (scoped.creditNotes || []).filter(keep).map(stamp);
    scoped.groups = (scoped.groups || []).filter(keep).map(stamp);
    scoped.planningCourses = (scoped.planningCourses || []).filter(keep).map(stamp);
    scoped.planningExceptions = (scoped.planningExceptions || []).filter(keep).map(stamp);
    scoped.attendanceSessions = (scoped.attendanceSessions || []).filter(keep).map(stamp);
    scoped.memoRows = (scoped.memoRows || []).filter(keep).map(stamp);
    scoped.activityLog = (scoped.activityLog || []).filter(keep).map(stamp);
    scoped.seasonArchives = (scoped.seasonArchives || []).filter(keep).map(stamp);
    scoped.stageRegistrations = Object.fromEntries(Object.entries(scoped.stageRegistrations || {}).map(([stageId, rows]) => [
      stageId,
      (rows || []).filter(keep).map(stamp),
    ]));
    scoped.meta = { ...(scoped.meta || {}), clubId };
    return scoped;
  }

  function stampRecordClubId(row, clubId = activeClubId()) {
    if (!row || typeof row !== "object" || !clubId) return row;
    row.clubId = clubId;
    if (Array.isArray(row.payments)) row.payments.forEach((payment) => stampRecordClubId(payment, clubId));
    if (Array.isArray(row.paymentsSnapshot)) row.paymentsSnapshot.forEach((payment) => stampRecordClubId(payment, clubId));
    if (row.event?.payments) row.event.payments.forEach((payment) => stampRecordClubId(payment, clubId));
    if (row.lodging?.payments) row.lodging.payments.forEach((payment) => stampRecordClubId(payment, clubId));
    return row;
  }

  function saveCurrentClubPayload(options = {}) {
    const store = normalizeClubStore(rawClubStoreFromStorage() || clubStore);
    const clubId = store.activeClubId;
    if (!clubId) throw new Error("Aucun club actif : impossible d'enregistrer.");
    updateActiveClubFromSettings(store);
    const club = store.clubs.find((row) => row.id === clubId);
    store.data[clubId] = {
      state: scopeStateToClub(state, clubId),
      settings: settingsForClub(settings, club),
    };
    writeClubStore(store);
    if (options.reloadActive !== false) {
      settings = normalizeSettings(store.data[clubId].settings);
      state = normalizeState(store.data[clubId].state);
    }
    return store;
  }

  function normalizeSettings(source = {}) {
    const oldThemeId = ["bu", "do"].join("");
    const legacyThemeMap = { dark: "classic", light: "classic", [oldThemeId]: "classic", [`${oldThemeId}-dark`]: "classic-dark" };
    const theme = legacyThemeMap[source.theme] || source.theme;
    const logoDataUrl = isLogoDataUrl(source.logoDataUrl) ? source.logoDataUrl : "";
    const rawClubName = asText(source.clubName || "MonGestaClub");
    const clubName = normalizeProductText(rawClubName);
    return {
      theme: themes.some((item) => item.id === theme) ? theme : "graphite",
      ...source,
      theme: themes.some((item) => item.id === theme) ? theme : "graphite",
      defaultVatRate: source.defaultVatRate === undefined ? 20 : Math.max(0, asNumber(source.defaultVatRate)),
      paymentCheckCount: normalizePaymentCheckCount(source.paymentCheckCount),
      clubName,
      clubSubtitle: asText(source.clubSubtitle || "Gestion de club"),
      initialSetupDone: source.initialSetupDone === undefined ? Boolean(source.security?.createdAt) : Boolean(source.initialSetupDone),
      logoDataUrl,
      themeColors: normalizeThemeColors(source.themeColors),
      themeAnimations: Boolean(source.themeAnimations),
      // Axe "Disposition" indépendant du thème de couleurs. Défaut : moderne (rendu actuel).
      layout: source.layout === "classic" ? "classic" : "modern",
      sidebarHidden: Boolean(source.sidebarHidden),
      topbarHidden: Boolean(source.topbarHidden),
      menuOrder: normalizeMenuOrder(source.menuOrder),
      display: normalizeDisplaySettings(source.display),
      smtp: normalizeSmtpSettings(source.smtp),
      security: normalizeSecuritySettings(source.security),
      season: normalizeSeasonSettings(source.season),
      emailTemplates: normalizeEmailTemplates(source.emailTemplates),
      typography: normalizeTypographySettings(source.typography),
      postitStyles: normalizePostitStyles(source.postitStyles),
      // Assistant MonGestaClub — réglages par club (choix + drapeaux « déjà vu »).
      // La progression n'est jamais stockée ici : elle est recalculée depuis state.
      assistant: normalizeAssistantSettings(source.assistant),
      // Fonctionnalités utilisées par le club (Lot 1 — fondation invisible, encore INERTE).
      // Placée APRÈS `...source` : la valeur normalisée écrase toujours la brute, donc chaque
      // réassemblage de settings (settingsForClub, saveClub, import, duplication…) reproduit la
      // même structure déterministe. Aucune logique de l'app ne consulte encore ce champ.
      features: normalizeFeaturesSettings(source.features),
    };
  }

