  function emailTemplateCustomFields(templateKey = "") {
    return emailTemplateCustomVariableDefinitions()[templateKey] || genericEmailTemplateCustomVariableDefinitions();
  }

  function configurableEmailTemplateDefinitions() {
    const defs = emailTemplateDefinitions();
    const base = Object.fromEntries(Object.entries(defs).filter(([key]) => key !== "license"));
    const custom = Object.fromEntries(Object.entries(settings?.emailTemplates || {})
      .filter(([key]) => !defs[key])
      .map(([key, row]) => [key, {
        label: asText(row.label) || "Modèle personnalisé",
        note: asText(row.note) || "Modèle personnalisé du club actif.",
        subject: asText(row.subject),
        body: asText(row.body),
        variables: asText(row.variables) || "{contactNom}, {contactPrenom}, {clubNom}, {titre}, {detail}, {message}, {note}, {complement}, {signatureLibre}, {date}",
        custom: true,
      }]));
    return { ...base, ...custom };
  }

