  function computedThemeColor(field) {
    const raw = getComputedStyle(document.documentElement).getPropertyValue(field.css).trim();
    return cssColorToHex(raw, cssColorToHex(field.fallback, "#000000"));
  }

  // Vidage de données par module, regroupé par catégorie. Chaque entrée décrit précisément ce qui
  // est supprimé ET ce qui est préservé (factures et autres snapshots restent intacts). Les
  // dépendances par identifiant (groupId, coachId, roomId, courseId…) sont nettoyées dans
  // applyResetScope pour ne jamais laisser de référence cassée. Ne concerne QUE le club actif.
  // Vidage par module métier. Chaque scope porte un libellé + un détail précis (ce qui est
  // supprimé ET conservé). Les scopes marqués `advanced: true` ne s'affichent que dans la section
  // repliée « Maintenance avancée » (opérations techniques granulaires). Les dépendances par
  // identifiant sont nettoyées dans applyResetScope ; les snapshots (factures…) sont préservés.
  function resetScopeGroups() {
    return [
      { group: "Contacts", scopes: [
        { key: "members", label: "Membres", detail: "Supprime tous les membres, leurs adhésions ET leurs feuilles de présence (les présences ne conservent pas le nom : elles deviendraient orphelines). Les non-adhérents ne sont pas touchés. Les factures, commandes et inscriptions déjà enregistrées restent consultables (elles conservent leur copie du contact)." },
        { key: "prospects", label: "Non-adhérents", detail: "Supprime tous les non-adhérents (prospects). Les commandes boutique liées sont détachées de leur fiche mais restent consultables. Le reste n'est pas touché." },
        { key: "memberships", label: "Adhésions seules", advanced: true, detail: "Supprime toutes les adhésions aux disciplines. Les fiches contacts (membres et non-adhérents) restent. Les factures déjà émises restent intactes." },
      ]},
      { group: "Facturation", scopes: [
        { key: "invoices", label: "Factures", detail: "Supprime toutes les factures. Les contacts, adhésions, commandes et paiements ne sont pas touchés." },
      ]},
      { group: "Boutique", scopes: [
        { key: "boutique", label: "Boutique", detail: "Supprime les articles ET les commandes boutique (catalogue + ventes + mouvements de stock)." },
        { key: "boutique-orders", label: "Commandes boutique seules", advanced: true, detail: "Supprime toutes les commandes boutique (et donc l'historique des mouvements de stock). Les articles du catalogue restent." },
        { key: "boutique-articles", label: "Articles boutique seuls", advanced: true, detail: "Supprime tous les articles du catalogue boutique. Les commandes déjà passées restent consultables (elles conservent le libellé et le prix de chaque ligne)." },
      ]},
      { group: "Stages", scopes: [
        { key: "stages", label: "Stages", detail: "Supprime tous les stages (tarifs / événements) ET leurs inscriptions. Les factures déjà émises restent intactes." },
        { key: "stage-registrations", label: "Inscriptions stages seules", advanced: true, detail: "Supprime toutes les inscriptions aux stages. Les stages (tarifs / événements) restent." },
      ]},
      { group: "Sport", scopes: [
        { key: "disciplines", label: "Disciplines", detail: "Supprime toutes les disciplines, leurs assurances et les adhésions liées. Les fiches contacts restent. Le planning conserve le nom de discipline déjà enregistré sur chaque créneau." },
        { key: "groups", label: "Groupes", detail: "Supprime tous les groupes. Les adhérents et le planning restent, mais ne sont plus rattachés à un groupe (référence nettoyée)." },
        { key: "coaches", label: "Coachs", detail: "Supprime tous les coachs ET leurs remplacements. Les créneaux du planning et les groupes perdent leur coach (référence nettoyée, le nom saisi librement est conservé s'il existe). Les contacts et factures ne sont pas touchés." },
        { key: "rooms", label: "Salles", detail: "Supprime toutes les salles ET leurs remplacements. Les créneaux du planning perdent leur salle (référence nettoyée, le lieu saisi librement est conservé s'il existe)." },
        { key: "planning", label: "Planning", detail: "Supprime tous les créneaux du planning, leurs exceptions (annulations / notes de date) ET les décisions de remplacement liées. Les présences déjà enregistrées restent." },
        { key: "attendance", label: "Présences", detail: "Supprime toutes les feuilles de présence enregistrées. Le planning et les adhérents restent." },
        { key: "documents", label: "Documents", detail: "Supprime les documents joints et les infos licence / certificat médical des adhérents et non-adhérents. Les fiches contacts et le reste restent." },
        { key: "coach-replacements", label: "Remplacements coachs", advanced: true, detail: "Supprime uniquement les décisions de remplacement de coachs. Les coachs et le planning restent." },
        { key: "room-replacements", label: "Remplacements salles", advanced: true, detail: "Supprime uniquement les décisions de remplacement de salles. Les salles et le planning restent." },
        { key: "planning-exceptions", label: "Exceptions planning", advanced: true, detail: "Supprime uniquement les exceptions de planning (annulations, notes, horaires / coachs / salles ponctuels). Les créneaux restent." },
      ]},
      { group: "Comptabilité", scopes: [
        { key: "comptabilite", label: "Comptabilité", detail: "Supprime les dépenses ET les avoirs, et remet tous les paiements encaissés (adhésions, commandes, stages) en « à encaisser ». Les factures déjà émises et les montants attendus restent intacts." },
        { key: "expenses", label: "Dépenses seules", advanced: true, detail: "Supprime toutes les dépenses saisies. Les recettes et paiements ne sont pas touchés." },
        { key: "accounting", label: "Paiements encaissés seuls", advanced: true, detail: "Vide tous les paiements enregistrés (adhésions, commandes, stages). Les fiches et montants attendus restent ; tout repasse en « à encaisser ». Les factures ne sont pas touchées." },
        { key: "creditNotes", label: "Avoirs seuls", advanced: true, detail: "Supprime tous les avoirs. Les factures et paiements ne sont pas touchés." },
      ]},
      { group: "Outils", scopes: [
        { key: "notes", label: "Notes", detail: "Vide les notes libres." },
        { key: "history", label: "Historique", detail: "Vide le journal d'activité (historique des actions)." },
        { key: "memos", label: "Mémos / post-its", advanced: true, detail: "Supprime tous les mémos rattachés aux fiches." },
        { key: "season-archives", label: "Archives de saison", advanced: true, detail: "Supprime les archives de saison enregistrées dans ce club." },
      ]},
      { group: "Tout", scopes: [
        { key: "all", label: "Tout vider", detail: "Supprime TOUTES les données de ce club : contacts, adhésions, factures, avoirs, boutique, stages, disciplines, groupes, coachs, salles, planning, présences, dépenses, notes, mémos, historique, archives. Les paramètres du club et le club lui-même restent. Action irréversible." },
      ]},
    ];
  }

  function resetScopeInfo(scope) {
    for (const grp of resetScopeGroups()) {
      const found = grp.scopes.find((entry) => entry.key === scope);
      if (found) return found;
    }
    return { key: scope, label: "Réinitialiser", detail: "Cette action vide les données concernées." };
  }

  function bindDialogDelegates(targetDialog = dialog) {
    if (!targetDialog || targetDialog.dataset.delegatesReady === "1") return;
    targetDialog.dataset.delegatesReady = "1";
    targetDialog.addEventListener("click", async (event) => {
      const paymentTab = event.target.closest("[data-payment-tab]");
      if (paymentTab) {
        event.preventDefault();
        event.stopPropagation();
        selectPaymentTab(paymentTab);
        return;
      }
      const showAllBtn = event.target.closest("[data-payment-show-all]");
      if (showAllBtn) {
        event.preventDefault();
        event.stopPropagation();
        showAllPayments(showAllBtn);
        return;
      }
      const actionTarget = event.target.closest("[data-action]");
      if (actionTarget && !actionTarget.matches("input, select, textarea")) {
        event.preventDefault();
        event.stopPropagation();
        await handleAction(actionTarget);
      }
    });
    targetDialog.addEventListener("change", (event) => {
      const target = event.target;
      if (target.dataset.identityPhotoFile !== undefined) {
        updateIdentityPhotoFile(target);
      }
      if (target.dataset.identityAvatarChoice !== undefined) {
        setIdentityPhotoInForm(target.closest("form"), target.closest("form")?.querySelector("[data-identity-photo-value]")?.value || "");
      }
      if (target.dataset.articleImageFile !== undefined) {
        // En création (brouillon), on ajoute les photos directement au brouillon local pour
        // permettre leur classement immédiat ; sinon, prévisualisation différée (commit au save).
        if (target.dataset.articleDraft !== undefined) addDraftArticleImages(target);
        else previewArticleImageFiles(target);
      }
      if (target.name === "contactDocuments") {
        previewContactDocumentFiles(target);
      }
    });
  }

  function createStackedDialog() {
    const stacked = document.createElement("dialog");
    stacked.className = "dialog stacked-dialog";
    stacked.addEventListener("close", () => stacked.remove(), { once: true });
    bindDialogDelegates(stacked);
    document.body.appendChild(stacked);
    return stacked;
  }

  function dialogForNewWindow() {
    return dialog.open ? createStackedDialog() : dialog;
  }

  function dialogForContainer(container = dialog) {
    if (container?.matches?.("dialog")) return container;
    return container?.closest?.("dialog") || dialog;
  }

  function focusDialogControl(container = dialog, selector = "[autofocus], input:not([type='hidden']):not([disabled]), select:not([disabled]), textarea:not([disabled]), button:not([disabled])") {
    const targetDialog = dialogForContainer(container);
    const target = container.querySelector(selector);
    if (!target) return;
    const run = () => {
      window.monGestaClubShell?.focusApp?.().catch?.(() => {});
      targetDialog.setAttribute("tabindex", "-1");
      window.focus?.();
      targetDialog.focus?.();
      target.focus?.({ preventScroll: true });
      if (typeof target.select === "function" && target.matches("input, textarea")) target.select();
    };
    requestAnimationFrame(run);
    setTimeout(run, 0);
    setTimeout(run, 60);
    setTimeout(run, 360);
  }

  function resetFloatingDialogPosition(targetDialog = dialog) {
    targetDialog.classList.remove("is-moved", "is-dragging", "is-collapsed");
    targetDialog.style.left = "";
    targetDialog.style.top = "";
    targetDialog.style.margin = "";
    targetDialog.style.width = "";
    targetDialog.style.position = "";
  }

  function clampDialogPosition(value, min, max) {
    return Math.max(min, Math.min(value, Math.max(min, max)));
  }

  function makeDialogDraggable(targetDialog = dialog) {
    const header = targetDialog.querySelector(".dialog-header");
    if (!header || header.dataset.dragReady === "1") return;
    header.dataset.dragReady = "1";
    header.title = "Cliquer pour replier / déplier. Maintenir pour déplacer.";
    // Résout dynamiquement le dialogue hôte au moment de l'événement : l'en-tête peut être
    // déplacé d'un <dialog> à un autre lors de la réduction/réouverture des grandes fenêtres.
    const hostDialog = () => header.closest("dialog") || targetDialog;

    let dragState = null;
    let suppressHeaderClick = false;
    const stopDrag = () => {
      if (dragState?.moved) suppressHeaderClick = true;
      hostDialog().classList.remove("is-dragging");
      dragState = null;
      document.removeEventListener("pointermove", moveDialog);
      document.removeEventListener("pointerup", stopDrag);
      document.removeEventListener("pointercancel", stopDrag);
      if (suppressHeaderClick) setTimeout(() => {
        suppressHeaderClick = false;
      }, 0);
    };
    const moveDialog = (event) => {
      if (!dragState) return;
      if (Math.abs(event.clientX - dragState.x) > 4 || Math.abs(event.clientY - dragState.y) > 4) {
        dragState.moved = true;
      }
      const d = hostDialog();
      const width = d.offsetWidth;
      const height = d.offsetHeight;
      const maxLeft = window.innerWidth - width - 8;
      const maxTop = window.innerHeight - Math.min(height, window.innerHeight - 16) - 8;
      const left = clampDialogPosition(dragState.left + event.clientX - dragState.x, 8, maxLeft);
      const top = clampDialogPosition(dragState.top + event.clientY - dragState.y, 8, maxTop);
      d.style.left = `${Math.round(left)}px`;
      d.style.top = `${Math.round(top)}px`;
    };

    header.addEventListener("pointerdown", (event) => {
      if (event.button !== 0) return;
      if (event.target.closest("button, input, select, textarea, a, label, [contenteditable='true']")) return;
      const d = hostDialog();
      const rect = d.getBoundingClientRect();
      d.classList.add("is-moved", "is-dragging");
      d.style.position = "fixed";
      d.style.margin = "0";
      d.style.width = `${Math.round(rect.width)}px`;
      d.style.left = `${Math.round(rect.left)}px`;
      d.style.top = `${Math.round(rect.top)}px`;
      dragState = { x: event.clientX, y: event.clientY, left: rect.left, top: rect.top, moved: false };
      document.addEventListener("pointermove", moveDialog);
      document.addEventListener("pointerup", stopDrag);
      document.addEventListener("pointercancel", stopDrag);
      event.preventDefault();
    });
    header.addEventListener("click", (event) => {
      if (event.target.closest("button, input, select, textarea, a, label, [contenteditable='true']")) return;
      if (suppressHeaderClick) return;
      const d = hostDialog();
      d.classList.toggle("is-collapsed");
      const collapsed = d.classList.contains("is-collapsed");
      header.title = collapsed ? "Cliquer pour déplier. Maintenir pour déplacer." : "Cliquer pour replier / déplier. Maintenir pour déplacer.";
    });
    targetDialog.addEventListener("close", stopDrag, { once: true });
  }

  // =========================================================================
  // RÉDUCTION DES GRANDES FENÊTRES (showDialog) — barre des fenêtres réduites
  // Purement UX : on déplace le nœud <form> vivant (valeurs saisies préservées)
  // vers une réserve cachée, on ferme le <dialog> sans déclencher onCancel, et on
  // affiche une pastille en bas. La réouverture réinsère le form dans un <dialog>.
  // Aucune donnée, aucun calcul, aucune règle métier touchés.
  // =========================================================================
  const minimizedWindows = [];
  let minimizedSeq = 0;

  const MINIMIZED_EMOJI = [
    [/facture|avoir|règlement|reglement|paiement/i, "📄"],
    [/contact/i, "📇"],
    [/inscription/i, "📝"],
    [/groupe/i, "👥"],
    [/créneau|creneau|feuille d'appel|date|séance|seance/i, "🗓️"],
    [/salle/i, "🏠"],
    [/coach/i, "🧑‍🏫"],
    [/stage/i, "🎟️"],
    [/dépense|depense/i, "💶"],
    [/article|stock|commande/i, "🛒"],
    [/club|thème|theme/i, "🏫"],
    [/mail|e-mail/i, "✉️"],
  ];

  function minimizedEmojiFor(title) {
    const t = asText(title);
    for (const [re, emoji] of MINIMIZED_EMOJI) if (re.test(t)) return emoji;
    return "🪟";
  }

  function minimizedLabelFor(title, form) {
    const val = (sel) => asText(form?.querySelector?.(sel)?.value);
    const detail = val("input[name='name']")
      || [val("input[name='lastName']"), val("input[name='firstName']")].filter(Boolean).join(" ")
      || val("input[name='number']")
      || val("input[name='label']")
      || "";
    const base = asText(title) || "Fenêtre";
    return detail ? `${base} : ${detail}` : base;
  }

  function ensureMinimizedStash() {
    let stash = document.getElementById("mgc-min-stash");
    if (!stash) {
      stash = document.createElement("div");
      stash.id = "mgc-min-stash";
      stash.hidden = true;
      document.body.appendChild(stash);
    }
    return stash;
  }

  function ensureMinimizedBar() {
    let bar = document.getElementById("mgc-min-bar");
    if (!bar) {
      bar = document.createElement("div");
      bar.id = "mgc-min-bar";
      bar.className = "mgc-min-bar";
      bar.setAttribute("role", "region");
      bar.setAttribute("aria-label", "Fenêtres réduites");
      document.body.appendChild(bar);
    }
    return bar;
  }

  function renderMinimizedBar() {
    const bar = ensureMinimizedBar();
    bar.innerHTML = "";
    if (!minimizedWindows.length) { bar.classList.remove("is-visible"); return; }
    bar.classList.add("is-visible");
    minimizedWindows.forEach((entry) => {
      const chip = document.createElement("div");
      chip.className = "mgc-min-chip";
      const open = document.createElement("button");
      open.type = "button";
      open.className = "mgc-min-open";
      open.title = "Rouvrir cette fenêtre";
      open.setAttribute("aria-label", `Rouvrir : ${entry.label}`);
      open.innerHTML = `<span class="mgc-min-emoji" aria-hidden="true">${esc(entry.emoji)}</span><span class="mgc-min-label">${esc(entry.label)}</span>`;
      open.addEventListener("click", () => entry.restore());
      const close = document.createElement("button");
      close.type = "button";
      close.className = "mgc-min-close";
      close.textContent = "✕";
      close.title = "Fermer cette fenêtre";
      close.setAttribute("aria-label", `Fermer : ${entry.label}`);
      close.addEventListener("click", (event) => { event.stopPropagation(); entry.closeForGood(); });
      chip.appendChild(open);
      chip.appendChild(close);
      bar.appendChild(chip);
    });
  }

  function registerMinimizedWindow(entry) {
    if (!minimizedWindows.includes(entry)) minimizedWindows.push(entry);
    renderMinimizedBar();
  }

  function unregisterMinimizedWindow(entry) {
    const idx = minimizedWindows.indexOf(entry);
    if (idx >= 0) minimizedWindows.splice(idx, 1);
    renderMinimizedBar();
  }

  // =========================================================================
  // DÉDUPLICATION DES FICHES : une même fiche (clé = type:id) n'existe qu'en
  // un exemplaire. L'appelant pose la clé via setNextWindowKey() avant showDialog
  // (uniquement en édition ; en création la clé est nulle → plusieurs autorisés).
  // showDialog consomme la clé : si une fenêtre de même clé existe, il l'active
  // (restaure si réduite, sinon focus) et ne crée rien.
  // =========================================================================
  const keyedWindows = new Map();
  let pendingWindowKey = null;
  function setNextWindowKey(key) { pendingWindowKey = key || null; }

  function showFloatingDialog(focusContainer = dialog, selector = "", targetDialog = dialogForContainer(focusContainer)) {
    resetFloatingDialogPosition(targetDialog);
    targetDialog.showModal();
    makeDialogDraggable(targetDialog);
    if (selector) focusDialogControl(focusContainer, selector);
    else focusDialogControl(focusContainer);
  }

  function requestDialogConfirmation(title, message, confirmLabel = "Continuer", danger = false) {
    return new Promise((resolve) => {
      let settled = false;
      const targetDialog = dialogForNewWindow();
      targetDialog.classList.remove("has-identity-photo");
      targetDialog.innerHTML = `<form class="password-confirm-form">
        <div class="dialog-header"><h2>${esc(title)}</h2><button class="icon" type="button" data-dialog-close title="Fermer" aria-label="Fermer">×</button></div>
        <div class="dialog-body">
          <div class="dialog-section">
            ${message.split("\n").filter(Boolean).map((line) => `<p>${esc(line)}</p>`).join("")}
          </div>
        </div>
        <div class="dialog-footer">
          <span></span>
          <div class="dialog-footer-actions">
            <button type="button" data-dialog-close>Annuler</button>
            <button class="${danger ? "danger" : "primary"}" type="submit" data-confirm-submit>${esc(confirmLabel)}</button>
          </div>
        </div>
      </form>`;
      const finish = (value) => {
        if (settled) return;
        settled = true;
        resolve(value);
      };
      targetDialog.querySelectorAll("[data-dialog-close]").forEach((button) => button.addEventListener("click", () => {
        finish(false);
        targetDialog.close();
      }));
      targetDialog.addEventListener("close", () => finish(false), { once: true });
      const form = targetDialog.querySelector("form");
      form.addEventListener("submit", (event) => {
        event.preventDefault();
        finish(true);
        targetDialog.close();
      });
      showFloatingDialog(form, "[data-confirm-submit]", targetDialog);
    });
  }

  // Dialogue à choix multiple. choices : [{ key, label, danger?, primary? }].
  // Résout avec la clé choisie, ou "" si annulé / fermé.
  function requestChoice({ title = "Choisir", message = "", bodyHtml = "", choices = [] } = {}) {
    return new Promise((resolve) => {
      let settled = false;
      const targetDialog = dialogForNewWindow();
      targetDialog.classList.remove("has-identity-photo");
      targetDialog.innerHTML = `<form class="password-confirm-form">
        <div class="dialog-header"><h2>${esc(title)}</h2><button class="icon" type="button" data-dialog-close title="Fermer" aria-label="Fermer">×</button></div>
        <div class="dialog-body">
          <div class="dialog-section">
            ${bodyHtml || message.split("\n").filter(Boolean).map((line) => `<p>${esc(line)}</p>`).join("")}
          </div>
        </div>
        <div class="dialog-footer">
          <span></span>
          <div class="dialog-footer-actions">
            <button type="button" data-dialog-close>Annuler</button>
            ${choices.map((choice) => `<button type="button" class="${choice.danger ? "danger" : (choice.primary ? "primary" : "")}" data-choice-key="${esc(choice.key)}">${esc(choice.label)}</button>`).join("")}
          </div>
        </div>
      </form>`;
      const finish = (value) => {
        if (settled) return;
        settled = true;
        resolve(value);
      };
      targetDialog.querySelectorAll("[data-choice-key]").forEach((button) => button.addEventListener("click", () => {
        const key = button.dataset.choiceKey;
        finish(key);
        targetDialog.close();
      }));
      targetDialog.querySelectorAll("[data-dialog-close]").forEach((button) => button.addEventListener("click", () => {
        finish("");
        targetDialog.close();
      }));
      targetDialog.addEventListener("close", () => finish(""), { once: true });
      const form = targetDialog.querySelector("form");
      form.addEventListener("submit", (event) => event.preventDefault());
      showFloatingDialog(form, "[data-choice-key]", targetDialog);
    });
  }

  function requestTextInput({ title = "Saisir", label = "Valeur", placeholder = "", value = "", confirmLabel = "Valider", help = "" } = {}) {
    return new Promise((resolve) => {
      let settled = false;
      const targetDialog = dialogForNewWindow();
      targetDialog.classList.remove("has-identity-photo");
      targetDialog.innerHTML = `<form class="password-confirm-form">
        <div class="dialog-header"><h2>${esc(title)}</h2><button class="icon" type="button" data-dialog-close title="Fermer" aria-label="Fermer">×</button></div>
        <div class="dialog-body">
          <div class="dialog-section">
            <label>${esc(label)}<input type="text" name="textValue" value="${esc(value)}" placeholder="${esc(placeholder)}" autofocus /></label>
            ${help ? `<p class="muted">${esc(help)}</p>` : ""}
          </div>
        </div>
        <div class="dialog-footer">
          <span></span>
          <div class="dialog-footer-actions"><button type="button" data-dialog-close>Annuler</button><button class="primary" type="submit">${esc(confirmLabel)}</button></div>
        </div>
      </form>`;
      const finish = (result) => {
        if (settled) return;
        settled = true;
        resolve(result);
      };
      targetDialog.querySelectorAll("[data-dialog-close]").forEach((button) => button.addEventListener("click", () => {
        finish(null);
        targetDialog.close();
      }));
      targetDialog.addEventListener("close", () => finish(null), { once: true });
      const form = targetDialog.querySelector("form");
      form.addEventListener("submit", (event) => {
        event.preventDefault();
        const result = asText(form.elements.textValue?.value).trim();
        if (!result) {
          form.elements.textValue?.focus();
          return;
        }
        finish(result);
        targetDialog.close();
      });
      showFloatingDialog(form, "input[name='textValue']", targetDialog);
    });
  }

  function requestConfirm({ title = "Confirmer", message = "", confirmLabel = "Confirmer", danger = false } = {}) {
    return requestDialogConfirmation(title, message, confirmLabel, danger);
  }

  async function requestPasswordConfirmation(title, message) {
    if (!hasAppPassword()) return true;
    return new Promise((resolve) => {
      let settled = false;
      dialog.innerHTML = `<form class="password-confirm-form">
        <div class="dialog-header"><h2>${esc(title)}</h2><button class="icon" type="button" data-dialog-close title="Fermer" aria-label="Fermer">×</button></div>
        <div class="dialog-body">
          <div class="dialog-section">
            <p>${esc(message)}</p>
            <label>Mot de passe<input type="password" name="password" autocomplete="current-password" autofocus /></label>
            <div class="form-error" hidden data-password-error></div>
          </div>
        </div>
        <div class="dialog-footer">
          <span></span>
          <div class="dialog-footer-actions"><button type="button" data-dialog-close>Annuler</button><button class="primary" type="submit">Valider</button></div>
        </div>
      </form>`;
      // On résout SUR l'événement "close" (et non avant) : ainsi la suite (ex. ouvrir un
      // autre dialogue qui réutilise le même <dialog>) s'exécute après que l'événement close
      // a été consommé, et ce dialogue suivant ne se referme plus tout seul.
      let result = false;
      const settle = () => {
        if (settled) return;
        settled = true;
        resolve(result);
      };
      dialog.querySelectorAll("[data-dialog-close]").forEach((button) => button.addEventListener("click", () => {
        result = false;
        dialog.close();
      }));
      dialog.addEventListener("close", settle, { once: true });
      const form = dialog.querySelector("form");
      form.addEventListener("submit", async (event) => {
        event.preventDefault();
        const password = asText(new FormData(form).get("password"));
        if (await verifyAppPassword(password)) {
          result = true;
          dialog.close();
          return;
        }
        const error = form.querySelector("[data-password-error]");
        error.hidden = false;
        error.textContent = "Mot de passe incorrect.";
        focusDialogControl(form, "input[name='password']");
      });
      showFloatingDialog(form, "input[name='password']");
    });
  }

  async function requestProtectedDangerAction(title, message, confirmLabel = "Confirmer") {
    const needsPassword = hasAppPassword();
    return new Promise((resolve) => {
      let settled = false;
      if (dialog.open) dialog.close();
      dialog.classList.remove("has-identity-photo");
      dialog.innerHTML = `<form class="password-confirm-form danger-confirm-form">
        <div class="dialog-header"><h2>${esc(title)}</h2><button class="icon" type="button" data-dialog-close title="Fermer" aria-label="Fermer">×</button></div>
        <div class="dialog-body">
          <div class="dialog-section">
            ${message.split("\n").filter(Boolean).map((line) => `<p>${esc(line)}</p>`).join("")}
            ${needsPassword ? `<label>Mot de passe<input type="password" name="password" autocomplete="current-password" autofocus /></label><div class="form-error" hidden data-password-error></div>` : ""}
          </div>
        </div>
        <div class="dialog-footer">
          <span></span>
          <div class="dialog-footer-actions">
            <button type="button" data-dialog-close>Annuler</button>
            <button class="danger" type="submit" data-confirm-submit>${esc(confirmLabel)}</button>
          </div>
        </div>
      </form>`;
      const finish = (value) => {
        if (settled) return;
        settled = true;
        resolve(value);
      };
      dialog.querySelectorAll("[data-dialog-close]").forEach((button) => button.addEventListener("click", () => {
        finish(false);
        dialog.close();
      }));
      dialog.addEventListener("close", () => finish(false), { once: true });
      const form = dialog.querySelector("form");
      form.addEventListener("submit", async (event) => {
        event.preventDefault();
        if (needsPassword) {
          const password = asText(new FormData(form).get("password"));
          if (!(await verifyAppPassword(password))) {
            const error = form.querySelector("[data-password-error]");
            error.hidden = false;
            error.textContent = "Mot de passe incorrect.";
            focusDialogControl(form, "input[name='password']");
            return;
          }
        }
        finish(true);
        dialog.close();
      });
      showFloatingDialog(form, needsPassword ? "input[name='password']" : "[data-confirm-submit]");
    });
  }

  // Affiche le code de récupération une seule fois dans un dialogue (Paramètres > Sécurité).
  function showRecoveryCodeDialog(code, title = "Code de récupération", intro = "") {
    const targetDialog = dialogForNewWindow();
    targetDialog.classList.remove("has-identity-photo");
    targetDialog.innerHTML = `<div>
      <div class="dialog-header"><h2>${esc(title)}</h2><button class="icon" type="button" data-dialog-close title="Fermer" aria-label="Fermer">×</button></div>
      <div class="dialog-body"><div class="dialog-section recovery-dialog-body">
        ${intro ? `<p class="muted">${esc(intro)}</p>` : ""}
        ${recoveryCodeCardHtml(code)}
      </div></div>
      <div class="dialog-footer"><span></span><div class="dialog-footer-actions"><button class="primary" type="button" data-dialog-close>J'ai noté ce code</button></div></div>
    </div>`;
    targetDialog.querySelectorAll("[data-dialog-close]").forEach((b) => b.addEventListener("click", () => targetDialog.close()));
    bindRecoveryCopy(targetDialog);
    showFloatingDialog(targetDialog, "[data-dialog-close]", targetDialog);
  }

  async function updateAppPasswordFrom(button) {
    const panel = button.closest(".security-settings-panel");
    const wasProtected = hasAppPassword();
    const currentPassword = asText(panel?.querySelector("[data-security-current]")?.value);
    const newPassword = asText(panel?.querySelector("[data-security-new]")?.value);
    const confirmation = asText(panel?.querySelector("[data-security-confirm]")?.value);
    if (hasAppPassword() && !(await verifyAppPassword(currentPassword))) {
      alert("Le mot de passe actuel est incorrect.");
      return;
    }
    if (newPassword.length < PASSWORD_MIN_LENGTH) {
      alert(`Le nouveau mot de passe doit contenir au moins ${PASSWORD_MIN_LENGTH} caractères.`);
      return;
    }
    if (newPassword !== confirmation) {
      alert("Les deux mots de passe ne correspondent pas.");
      return;
    }
    await setAppPassword(newPassword);
    // Création OU changement : on (re)génère un code de récupération et on l'affiche une seule fois.
    const code = await generateAndStoreRecoveryCode();
    ui.saveMessage = wasProtected ? "Mot de passe mis à jour" : "Mot de passe créé";
    render();
    showRecoveryCodeDialog(code, wasProtected ? "Mot de passe mis à jour" : "Mot de passe créé",
      "Mot de passe enregistré. Voici votre code de récupération : il permettra de réinitialiser le mot de passe en cas d'oubli. Notez-le, il ne sera plus affiché.");
  }

  // Régénère le code de récupération depuis Paramètres > Sécurité (exige le mot de passe actuel).
  async function regenerateRecoveryCodeFrom(button) {
    if (!hasAppPassword()) {
      alert("Créez d'abord un mot de passe.");
      return;
    }
    const panel = button.closest(".security-settings-panel");
    const currentPassword = asText(panel?.querySelector("[data-security-current]")?.value);
    if (!(await verifyAppPassword(currentPassword))) {
      alert("Saisis d'abord le mot de passe actuel dans le champ « Mot de passe actuel ». Il est incorrect ou vide.");
      return;
    }
    if (hasRecoveryCode() && !(await requestConfirm({
      title: "Nouveau code de récupération",
      message: "Générer un nouveau code de récupération ?\n\nL'ancien code ne fonctionnera plus. Le nouveau code ne sera affiché qu'une seule fois.",
      confirmLabel: "Générer un nouveau code",
    }))) return;
    const code = await generateAndStoreRecoveryCode();
    ui.saveMessage = "Code de récupération régénéré";
    render();
    showRecoveryCodeDialog(code, "Code de récupération", "Voici votre nouveau code de récupération. Il remplace l'ancien et ne sera plus affiché. Notez-le en lieu sûr.");
  }

  // Suppression du mot de passe (si l'utilisateur préfère ne pas en avoir).
  // Exige le mot de passe actuel + une confirmation.
  async function removeAppPasswordFrom(button) {
    if (!hasAppPassword()) return;
    const panel = button.closest(".security-settings-panel");
    const currentPassword = asText(panel?.querySelector("[data-security-current]")?.value);
    if (!(await verifyAppPassword(currentPassword))) {
      alert("Saisis d'abord le mot de passe actuel dans le champ « Mot de passe actuel ». Il est incorrect ou vide.");
      return;
    }
    if (!(await requestConfirm({
      title: "Supprimer le mot de passe",
      message: "Retirer le mot de passe du logiciel ?\n\nLe logiciel ne le demandera plus au démarrage ni avant le vidage des données, et les menus protégés ne seront plus protégés. Tu pourras en recréer un à tout moment.",
      confirmLabel: "Supprimer le mot de passe",
      danger: true,
    }))) return;
    removeAppPassword();
    ui.saveMessage = "Mot de passe supprimé";
    alert("Le mot de passe a été supprimé. Le logiciel ne le demandera plus.");
    render();
  }

  async function runResetScope(scope) {
    // Garde de MUTATION (Lot 2B) : un vidage destructif de données Boutique est une mutation Boutique.
    // Bloqué quand la fonctionnalité est désactivée, pour ne jamais détruire l'historique qui doit
    // rester conservé et restituable après réactivation. Le scope global "all" n'est pas concerné.
    if (["boutique", "boutique-orders", "boutique-articles"].includes(scope) && !ensureFeatureEnabledForMutation("shop")) return;
    // Lot 2D — un vidage destructif CIBLÉ de données Stages est une mutation Stages : bloqué quand la
    // fonctionnalité est désactivée, pour ne jamais détruire l'historique qui doit rester conservé et
    // restituable après réactivation. Le scope global "all" (vidage complet explicitement confirmé)
    // n'est jamais concerné : désactiver une fonctionnalité ≠ masquer ≠ supprimer les données.
    if (["stages", "stage-registrations"].includes(scope) && !ensureFeatureEnabledForMutation("stages")) return;
    const info = resetScopeInfo(scope);
    const message = `${info.detail}\nSeul le club actif est concerné. Les autres clubs ne sont pas touchés.\nPense à exporter une sauvegarde JSON avant de supprimer. Action irréversible.`;
    // Club ciblé (Lot 2D) : capturé AVANT la confirmation protégée, qui est asynchrone (saisie du mot
    // de passe). Sans cela, un changement de club pendant la confirmation ferait porter le vidage sur
    // le club devenu actif — la promesse « Seul le club actif est concerné » est celle affichée à
    // l'ouverture. Un club différent au moment de valider = annulation, sans recordHistory ni persist.
    const targetClubId = activeClubId();
    if (!(await requestProtectedDangerAction(`Vider : ${info.label}`, message, `Vider ${info.label.toLowerCase()}`))) return;
    if (activeClubId() !== targetClubId) { ui.saveMessage = "Opération annulée : le club actif a changé."; render(); return; }
    recordHistory();
    applyResetScope(scope);
    persist(`Vidage : ${info.label}`);
    render();
    showInfoDialog("Vidage effectué", `<p><strong>${esc(info.label)}</strong> : données vidées pour le club actif.</p>`);
  }

  function waitForDialogClosed() {
    if (!dialog.open) return Promise.resolve();
    return new Promise((resolve) => {
      const done = () => resolve();
      dialog.addEventListener("close", done, { once: true });
      setTimeout(done, 80);
    });
  }

  // Vide un module en NETTOYANT les références par identifiant (groupId, coachId, roomId, courseId)
  // pour ne jamais laisser de lien cassé. Les snapshots (factures, libellés/ prix de ligne, copie
  // du contact dans une commande) sont préservés : les pages restent ouvrables après vidage.
  function applyResetScope(scope) {
    if (scope === "all") {
      state = normalizeState({
        contacts: { members: [], prospects: [] },
        memberships: [],
        shopOrders: [],
        invoices: [],
        stageRegistrations: {},
        tariffs: { disciplines: [], insurance: [], stages: [], articles: [] },
        notes: [{ id: id("note"), title: "", content: "", updatedAt: new Date().toISOString() }],
        meta: {},
      });
      return;
    }
    // ----- Contacts -----
    if (scope === "members") {
      state.contacts.members = [];
      state.memberships = [];
      // Les feuilles de présence ne stockent que memberId + statut (pas le nom) : sans membres ni
      // adhésions, elles deviendraient orphelines (illisibles). On les supprime donc avec les membres.
      state.attendanceSessions = [];
    }
    if (scope === "prospects") {
      state.contacts.prospects = [];
      (state.shopOrders || []).forEach((order) => { if (order.prospectContactId) order.prospectContactId = ""; });
    }
    if (scope === "memberships") {
      state.memberships = [];
    }
    // ----- Facturation -----
    if (scope === "invoices") state.invoices = [];
    if (scope === "creditNotes") state.creditNotes = [];
    // ----- Boutique -----
    if (scope === "boutique-orders") state.shopOrders = [];
    if (scope === "boutique-articles") state.tariffs.articles = [];
    if (scope === "boutique") { state.shopOrders = []; state.tariffs.articles = []; }
    // ----- Stages -----
    if (scope === "stage-registrations") state.stageRegistrations = {};
    if (scope === "stages") {
      state.stageRegistrations = {};
      state.tariffs.stages = [];
      ui.stageId = "";
    }
    // ----- Sport -----
    if (scope === "disciplines") {
      state.memberships = [];
      state.tariffs.disciplines = [];
      state.tariffs.insurance = [];
    }
    if (scope === "groups") {
      state.groups = [];
      (state.memberships || []).forEach((m) => { if (m.groupId) m.groupId = ""; });
      (state.planningCourses || []).forEach((c) => { if (c.groupId) c.groupId = ""; });
    }
    if (scope === "coaches") {
      state.coaches = [];
      state.coachReplacements = [];
      (state.planningCourses || []).forEach((c) => { if (c.coachId) c.coachId = ""; });
      (state.groups || []).forEach((g) => { if (g.coachId) g.coachId = ""; });
    }
    if (scope === "coach-replacements") state.coachReplacements = [];
    if (scope === "rooms") {
      state.rooms = [];
      state.roomReplacements = [];
      (state.planningCourses || []).forEach((c) => { if (c.roomId) c.roomId = ""; });
    }
    if (scope === "room-replacements") state.roomReplacements = [];
    if (scope === "planning") {
      state.planningCourses = [];
      state.planningExceptions = [];
      state.coachReplacements = [];
      state.roomReplacements = [];
    }
    if (scope === "planning-exceptions") state.planningExceptions = [];
    if (scope === "attendance") state.attendanceSessions = [];
    if (scope === "documents") {
      const clearDocs = (person) => {
        if (!person || typeof person !== "object") return;
        person.documents = [];
        person.documentsText = "";
        person.licenseNumber = ""; person.licenseFederation = "";
        person.licenseStartDate = ""; person.licenseEndDate = "";
        person.medicalCertificateDate = ""; person.medicalCertificateEndDate = "";
        person.parentalAuthorization = false; person.imageRights = false;
        person.rulesSigned = false; person.insurance = false;
      };
      (state.contacts.members || []).forEach(clearDocs);
      (state.contacts.prospects || []).forEach(clearDocs);
      (state.memberships || []).forEach(clearDocs);
    }
    // ----- Comptabilité -----
    const resetAllPayments = () => {
      (state.memberships || []).forEach((row) => row.payments = []);
      (state.shopOrders || []).forEach((row) => row.payments = []);
      Object.values(state.stageRegistrations || {}).flat().forEach((row) => {
        if (row.event) row.event.payments = [];
        if (row.lodging) row.lodging.payments = [];
      });
    };
    if (scope === "expenses") state.expenses = [];
    if (scope === "accounting") resetAllPayments();
    // Bouton métier « Comptabilité » : dépenses + avoirs + remise à zéro des paiements.
    // Les factures émises et les montants attendus restent intacts (snapshots préservés).
    if (scope === "comptabilite") {
      state.expenses = [];
      state.creditNotes = [];
      resetAllPayments();
    }
    // ----- Outils -----
    if (scope === "notes") {
      state.notes = [{ id: id("note"), title: "", content: "", updatedAt: new Date().toISOString() }];
      ui.noteId = state.notes[0].id;
    }
    if (scope === "memos") state.memoRows = [];
    if (scope === "history") state.activityLog = [];
    if (scope === "season-archives") state.seasonArchives = [];
  }

  function field(name, label, value = "", type = "text", extra = "") {
    return `<label>${labelHtml(label)}<input name="${esc(name)}" type="${type}" value="${esc(value ?? "")}" ${extra} /></label>`;
  }

  function selectField(name, label, value, options) {
    return `<label>${labelHtml(label)}<select name="${esc(name)}">${options.map((option) => `<option value="${esc(option)}" ${asText(option) === asText(value) ? "selected" : ""}>${esc(option)}</option>`).join("")}</select></label>`;
  }

  function textareaField(name, label, value = "", placeholder = "") {
    return `<label class="wide">${labelHtml(label)}<textarea name="${esc(name)}"${placeholder ? ` placeholder="${esc(placeholder)}"` : ""}>${esc(value ?? "")}</textarea></label>`;
  }

  function labelHtml(label) {
    const text = asText(label);
    if (!text.endsWith("*")) return esc(text);
    // Le label étant en display:grid, on enveloppe texte + astérisque dans UN seul élément
    // pour que le « * » reste sur la même ligne que le libellé (sinon il saute à la ligne).
    return `<span class="field-label-text">${esc(text.slice(0, -1).trim())} <span class="required-star">*</span></span>`;
  }

  function validateRequiredContactLike(data, fields, message) {
    // Tokens "virtuels" (pas des noms de champ réels) : mobileOrPhone = mobile OU fixe ;
    // contactMethod = e-mail OU mobile OU fixe (au moins un moyen de contact).
    const pseudoTokens = ["mobileOrPhone", "contactMethod"];
    const missing = fields.filter((fieldName) => !pseudoTokens.includes(fieldName) && !asText(data.get(fieldName)));
    const phoneMissing = fields.includes("mobileOrPhone") && !asText(data.get("mobile") || data.get("phone"));
    const contactMethodMissing = fields.includes("contactMethod") && !asText(data.get("email") || data.get("mobile") || data.get("phone"));
    if (missing.length || phoneMissing || contactMethodMissing) {
      alert(message || "Veuillez remplir tous les champs obligatoires avant d'enregistrer.");
      return false;
    }
    return true;
  }

  function postalCodeValue(value) {
    return asText(value).replace(/\D/g, "").slice(0, 5);
  }

  function uniqueValues(values) {
    const seen = new Set();
    return values.map(asText).filter(Boolean).filter((value) => {
      const key = normalizedPersonText(value);
      if (seen.has(key)) return false;
      seen.add(key);
      return true;
    });
  }

  function sortedCommunes(rows = []) {
    return [...rows].sort((a, b) => (asNumber(b.population) - asNumber(a.population)) || asText(a.nom).localeCompare(asText(b.nom), "fr"));
  }

  function communeCityNames(rows = []) {
    return uniqueValues(sortedCommunes(rows).map((row) => row.nom));
  }

  function communePostalCodes(rows = []) {
    return uniqueValues(sortedCommunes(rows).flatMap((row) => Array.isArray(row.codesPostaux) ? row.codesPostaux : []));
  }

  async function fetchCommunes(url, cache, key) {
    if (cache.has(key)) return cache.get(key);
    if (typeof fetch !== "function") return [];
    try {
      const response = await fetch(url);
      if (!response.ok) return [];
      const rows = await response.json();
      const normalized = Array.isArray(rows) ? rows.filter((row) => row && typeof row === "object") : [];
      cache.set(key, normalized);
      return normalized;
    } catch (error) {
      return [];
    }
  }

  function communesByPostalCode(postalCode) {
    const code = postalCodeValue(postalCode);
    if (code.length !== 5) return Promise.resolve([]);
    const url = `https://geo.api.gouv.fr/communes?codePostal=${encodeURIComponent(code)}&fields=nom,codesPostaux,population&boost=population&limit=20`;
    return fetchCommunes(url, addressLookupCache.postal, code);
  }

  function communesByCity(city) {
    const query = asText(city).trim();
    if (query.length < 3) return Promise.resolve([]);
    const key = normalizedPersonText(query);
    const url = `https://geo.api.gouv.fr/communes?nom=${encodeURIComponent(query)}&fields=nom,codesPostaux,population&boost=population&limit=12`;
    return fetchCommunes(url, addressLookupCache.city, key);
  }

  function ensureDatalist(input, prefix) {
    if (!input) return null;
    let listId = input.getAttribute("list");
    let list = listId ? document.getElementById(listId) : null;
    if (!list) {
      listId = `${prefix}-${id("list")}`;
      list = document.createElement("datalist");
      list.id = listId;
      input.setAttribute("list", listId);
      input.insertAdjacentElement("afterend", list);
    }
    return list;
  }

  function setDatalistOptions(list, values = []) {
    if (!list) return;
    list.innerHTML = uniqueValues(values).map((value) => `<option value="${esc(value)}"></option>`).join("");
  }

  function cityChoiceLabel(row = {}) {
    const codes = communePostalCodes([row]);
    return `${asText(row.nom)}${codes.length ? ` (${codes.join(", ")})` : ""}`;
  }

  function setupAddressAutocomplete(container = dialog) {
    const forms = container?.matches?.("form") ? [container] : [...(container?.querySelectorAll?.("form") || [])];
    forms.forEach((form) => {
      const postalInput = form.elements.postalCode;
      const cityInput = form.elements.city;
      if (!(postalInput instanceof HTMLInputElement) || !(cityInput instanceof HTMLInputElement)) return;
      if (postalInput.dataset.addressAutocompleteBound === "1" && cityInput.dataset.addressAutocompleteBound === "1") return;
      postalInput.dataset.addressAutocompleteBound = "1";
      cityInput.dataset.addressAutocompleteBound = "1";
      postalInput.setAttribute("autocomplete", "postal-code");
      cityInput.setAttribute("autocomplete", "address-level2");
      postalInput.setAttribute("inputmode", "numeric");
      const cityList = ensureDatalist(cityInput, "city-list");
      const postalList = ensureDatalist(postalInput, "postal-list");
      const cityChoice = document.createElement("select");
      cityChoice.className = "address-city-choice";
      cityChoice.hidden = true;
      cityChoice.setAttribute("aria-label", "Choisir une ville correspondant au code postal");
      document.body.appendChild(cityChoice);
      let postalTimer = 0;
      let cityTimer = 0;
      let postalToken = 0;
      let cityToken = 0;
      let lastAutoPostal = postalCodeValue(postalInput.value);
      let lastAutoCity = asText(cityInput.value);

      const hideCityChoices = () => {
        cityChoice.hidden = true;
        cityChoice.innerHTML = "";
      };

      const placeCityChoices = () => {
        const rect = cityInput.getBoundingClientRect();
        cityChoice.style.left = `${Math.round(rect.left + window.scrollX)}px`;
        cityChoice.style.top = `${Math.round(rect.bottom + window.scrollY + 5)}px`;
        cityChoice.style.width = `${Math.round(rect.width)}px`;
      };

      const setPostalValue = (value) => {
        const postal = postalCodeValue(value);
        if (!postal) return;
        postalInput.value = postal;
        lastAutoPostal = postal;
      };

      const setCityValue = (value) => {
        const city = asText(value);
        cityInput.value = city;
        lastAutoCity = city;
      };

      const showCityChoices = (rows, postal) => {
        const sortedRows = sortedCommunes(rows);
        if (sortedRows.length <= 1) {
          hideCityChoices();
          return;
        }
        cityChoice.innerHTML = `<option value="">Choisir la commune...</option>${sortedRows.map((row, index) => `<option value="${esc(row.nom)}" data-index="${index}">${esc(cityChoiceLabel(row))}</option>`).join("")}`;
        placeCityChoices();
        cityChoice.hidden = false;
        cityChoice.onchange = () => {
          if (!cityChoice.value) return;
          const selected = sortedRows[asNumber(cityChoice.selectedOptions[0]?.dataset.index)];
          if (!selected) return;
          setCityValue(selected.nom);
          setPostalValue(postal || communePostalCodes([selected])[0] || postalInput.value);
          cityChoice.value = selected.nom;
        };
      };

      const completeFromPostal = async (force = false) => {
        const postal = postalCodeValue(postalInput.value);
        if (postal.length !== 5) {
          hideCityChoices();
          return;
        }
        if (postalInput.value !== postal) postalInput.value = postal;
        const token = ++postalToken;
        const rows = await communesByPostalCode(postal);
        if (token !== postalToken || postalCodeValue(postalInput.value) !== postal) return;
        const cities = communeCityNames(rows);
        setDatalistOptions(cityList, cities);
        showCityChoices(rows, postal);
        if (!cities.length) return;
        const currentCity = normalizedPersonText(cityInput.value);
        const currentIsValid = cities.some((city) => normalizedPersonText(city) === currentCity);
        if (cities.length === 1) {
          setCityValue(cities[0]);
          hideCityChoices();
          return;
        }
        if (!currentIsValid && (!currentCity || normalizedPersonText(lastAutoCity) === currentCity || force)) {
          setCityValue("");
        }
      };

      const completeFromCity = async (force = false) => {
        const city = asText(cityInput.value).trim();
        if (city.length < 3) return;
        const cityKey = normalizedPersonText(city);
        const token = ++cityToken;
        const rows = await communesByCity(city);
        if (token !== cityToken || normalizedPersonText(cityInput.value) !== cityKey) return;
        const exactRows = rows.filter((row) => normalizedPersonText(row.nom) === cityKey);
        const candidates = exactRows.length ? exactRows : rows;
        const codes = communePostalCodes(candidates);
        setDatalistOptions(postalList, codes);
        if (!codes.length) return;
        const currentPostal = postalCodeValue(postalInput.value);
        const shouldUpdatePostal = exactRows.length || force || codes.length === 1 || !currentPostal || currentPostal === lastAutoPostal;
        if (shouldUpdatePostal) {
          setPostalValue(codes[0]);
        }
        if (force && candidates[0]?.nom && exactRows.length) {
          setCityValue(candidates[0].nom);
        }
      };

      postalInput.addEventListener("input", () => {
        if (postalCodeValue(postalInput.value) !== lastAutoPostal) lastAutoPostal = "";
        clearTimeout(postalTimer);
        postalTimer = setTimeout(() => completeFromPostal(false), 220);
      });
      postalInput.addEventListener("change", () => completeFromPostal(true));
      postalInput.addEventListener("blur", () => completeFromPostal(true));
      cityInput.addEventListener("input", () => {
        if (normalizedPersonText(cityInput.value) !== normalizedPersonText(lastAutoCity)) lastAutoCity = "";
        hideCityChoices();
        clearTimeout(cityTimer);
        cityTimer = setTimeout(() => completeFromCity(false), 220);
      });
      cityInput.addEventListener("change", () => completeFromCity(true));
      cityInput.addEventListener("blur", () => completeFromCity(true));
      dialog.addEventListener("close", () => cityChoice.remove(), { once: true });
      window.addEventListener("resize", hideCityChoices, { once: true });
      dialog.querySelector(".dialog-body")?.addEventListener("scroll", hideCityChoices, { once: true });
      if (postalCodeValue(postalInput.value).length === 5) completeFromPostal(false);
      else if (asText(cityInput.value).trim().length >= 3) completeFromCity(false);
    });
  }

  function paymentSelectField(name, label, value = "") {
    return `<label>${esc(label)}<input name="${esc(name)}" list="paymentStateList" value="${esc(value ?? "")}" /></label>`;
  }

  function readonlyMoneyField(label, value, attr = "") {
    return `<label>${esc(label)}<input type="text" value="${esc(money(value))}" readonly ${attr} /></label>`;
  }

  function paymentDueField(prefix, total = 0, payments = []) {
    return readonlyMoneyField("Reste dû", Math.max(0, asNumber(total) - paidAmount(payments)), `data-payment-due-prefix="${esc(prefix)}"`);
  }

  function paymentBalanceFields(prefix, total = 0, payments = []) {
    const expected = asNumber(total);
    const due = Math.max(0, expected - paidAmount(payments || []));
    return `<div class="payment-balance-grid">
      <label>Reste à payer<input type="text" value="${esc(money(due))}" readonly data-payment-balance-due-prefix="${esc(prefix)}" /></label>
    </div>`;
  }

  function paymentDateField(name, label, payment = {}) {
    return `<label>${esc(label)}<input name="${esc(name)}" type="date" value="${esc(dateInputValue(payment.date || (parseDate(payment.state) ? payment.state : "")))}" /></label>`;
  }

  function paymentFields(prefix, payments = [], total = 0, defaultTaxRate = effectiveDefaultVatRate()) {
    const count = effectivePaymentCount(payments, total);
    const paymentRows = paymentIndexes(count).map((index) => (payments || [])[index] || {});
    return `<div class="dialog-section payment-form-compact" data-payment-prefix="${esc(prefix)}" data-payment-total="${esc(asNumber(total))}" data-payment-count="${esc(count)}">
      ${paymentBalanceFields(prefix, total, paymentRows)}
      <div class="payment-overpay-warning" data-payment-overpay hidden></div>
      ${paymentDrawer(paymentRows, {
        mode: "form",
        prefix,
        total,
        defaultTaxRate,
        maxChecks: count,
        title: "Paiements",
      })}
    </div>`;
  }

  function insuranceChoiceOptions(selected = "") {
    return [`<option value="">Aucune assurance</option>`]
      .concat(insuranceChoices().map((choice) => {
        const label = [choice.category, choice.label].filter(Boolean).join(" - ");
        return `<option value="${esc(choice.key)}" ${choice.key === selected ? "selected" : ""}>${esc(label || "Assurance")}</option>`;
      }))
      .join("");
  }

  function paymentAmountInput(form, prefix, index) {
    return form.elements[`${prefix}${index}Amount`] || null;
  }

  function paymentTaxInput(form, prefix, index) {
    return form.elements[`${prefix}${index}TaxRate`] || null;
  }

  function paymentMethodInput(form, prefix, index) {
    return form.elements[`${prefix}${index}Check`] || null;
  }

  function paymentBlock(form, prefix) {
    return [...form.querySelectorAll("[data-payment-prefix]")]
      .find((block) => block.dataset.paymentPrefix === prefix) || null;
  }

  // Nombre de créneaux de paiement EFFECTIF pour une inscription donnée. Le réglage global
  // « Paiement en plusieurs fois » (paymentCheckCount) sert de base, mais ne doit JAMAIS rendre
  // un solde impossible à régler : si des paiements existent déjà et qu'un reste est dû, on garantit
  // toujours au moins un créneau de plus pour le complément (borné par MAX_PAYMENT_CHECK_COUNT).
  function effectivePaymentCount(payments = [], total = 0) {
    const filled = (payments || []).filter(hasPaymentContent).length;
    const due = asNumber(total) - paidAmount(payments || []);
    const needed = filled + (due > 0.005 ? 1 : 0);
    return normalizePaymentCheckCount(Math.max(paymentCheckCount(), needed));
  }

  // Compte effectif lu sur le bloc rendu (data-payment-count) ; repli sur le réglage global.
  // Garantit que rendu, recalcul live, validation et sauvegarde itèrent le MÊME nombre de créneaux.
  function paymentBlockCount(formElement, prefix) {
    const block = formElement && paymentBlock(formElement, prefix);
    const n = block ? Math.round(asNumber(block.dataset.paymentCount)) : 0;
    return n > 0 ? normalizePaymentCheckCount(n) : paymentCheckCount();
  }
  function paymentBlockIndexes(formElement, prefix) {
    return paymentIndexes(paymentBlockCount(formElement, prefix));
  }

  function setAutoPaymentAmount(input, amount) {
    if (!input) return;
    input.value = amount > 0 ? String(Math.round(amount * 100) / 100) : "";
    input.dataset.autoAmount = "true";
    input.dataset.manualEmpty = "";
  }

  function clearAutoPaymentAmount(input) {
    if (input?.dataset.autoAmount !== "true") return;
    input.value = "";
    input.dataset.autoAmount = "";
  }

  function canAutoFillPaymentAmount(input, changedInput = null) {
    return Boolean(input && input !== changedInput && input.dataset.userAmountEdited !== "true");
  }

  // Helper DOM (pas seulement l'objet paiement, car un montant "réel" et un montant "suggéré
  // jamais touché" sont indiscernables au niveau de l'objet seul) : une ligne de formulaire est
  // purement automatique si elle ne contient AUCUNE donnée métier saisie (state/date/checkNumber)
  // et que son seul montant éventuel n'est qu'une suggestion jamais validée ni modifiée
  // manuellement (data-auto-amount="true" ET data-user-amount-edited absent). C'est la SEULE
  // condition qui autorise un recalcul de visibilité à vider les champs d'une ligne — jamais une
  // ligne Refusée/Annulée/Payée/En cours/À encaisser, ni un montant/date/numéro de chèque saisi.
  function isFormPaymentRowPurelyAutomatic(form, prefix, index, payment) {
    if (asText(payment.state) || asText(payment.date) || asText(payment.checkNumber)) return false;
    if (!asNumber(payment.amount)) return true;
    const amountInput = form.elements[`${prefix}${index}Amount`];
    if (!amountInput) return false;
    return amountInput.dataset.autoAmount === "true" && amountInput.dataset.userAmountEdited !== "true";
  }

  function setDefaultPaymentTaxRate(form, prefix, rate = effectiveDefaultVatRate()) {
    paymentBlockIndexes(form, prefix).forEach((index) => {
      const input = paymentTaxInput(form, prefix, index);
      if (!input) return;
      if (!asText(input.value) || input.dataset.autoTax === "true") {
        input.value = String(Math.round(Math.max(0, asNumber(rate)) * 100) / 100);
        input.dataset.autoTax = "true";
      }
    });
  }

  function paymentObjectFromForm(form, prefix, index) {
    const payment = {
      check: form.elements[`${prefix}${index}Check`]?.value || defaultPaymentMethod(index),
      checkNumber: asText(form.elements[`${prefix}${index}CheckNumber`]?.value),
      amount: asNumber(form.elements[`${prefix}${index}Amount`]?.value),
      taxRate: Math.max(0, asNumber(form.elements[`${prefix}${index}TaxRate`]?.value)),
      date: form.elements[`${prefix}${index}Date`]?.value || "",
      state: form.elements[`${prefix}${index}State`]?.value || "",
    };
    // Garde côté sauvegarde : une ligne VALIDÉE et toujours verrouillée (data-payment-locked) restaure
    // ses valeurs canoniques. Ainsi, même si un champ a été modifié de force, on n'enregistre jamais une
    // modification incohérente d'un paiement validé. L'annulation retire ce verrou (ligne réinitialisée).
    const row = paymentBlock(form, prefix)?.querySelector(`[data-payment-row="${index}"]`);
    if (row && row.dataset.paymentLocked === "1") {
      payment.check = asText(row.dataset.lockedCheck) || payment.check;
      payment.checkNumber = asText(row.dataset.lockedChecknumber);
      payment.amount = asNumber(row.dataset.lockedAmount);
      payment.taxRate = Math.max(0, asNumber(row.dataset.lockedTax));
      payment.date = asText(row.dataset.lockedDate);
      payment.state = asText(row.dataset.lockedState) || "Payé";
    }
    return normalizeImmediatePayment(payment);
  }

  function formPaymentRows(form, prefix) {
    return paymentBlockIndexes(form, prefix).map((index) => paymentObjectFromForm(form, prefix, index));
  }

  // Verrouille/déverrouille une ligne de paiement (form) selon son statut. Une ligne VALIDÉE devient
  // non éditable (readonly + tabindex + classe .locked) et mémorise ses valeurs canoniques pour la
  // garde côté sauvegarde. Synchronisé à chaque rafraîchissement -> une ligne validée via « Payer »
  // se verrouille immédiatement, une ligne annulée se déverrouille.
  function syncFormPaymentRowLock(row, payment, locked) {
    if (!row) return;
    row.classList.toggle("locked", locked);
    const fields = [...row.querySelectorAll("input, select")].filter((el) => el.type !== "hidden");
    if (locked) {
      row.dataset.paymentLocked = "1";
      row.dataset.lockedCheck = asText(payment.check);
      row.dataset.lockedChecknumber = asText(payment.checkNumber);
      row.dataset.lockedAmount = String(asNumber(payment.amount));
      row.dataset.lockedTax = String(Math.max(0, asNumber(payment.taxRate)));
      row.dataset.lockedDate = asText(payment.date);
      row.dataset.lockedState = asText(payment.state) || "Payé";
      fields.forEach((el) => { el.setAttribute("readonly", "readonly"); el.setAttribute("tabindex", "-1"); });
    } else {
      delete row.dataset.paymentLocked;
      fields.forEach((el) => { el.removeAttribute("readonly"); el.removeAttribute("tabindex"); });
    }
  }

  function updatePaymentSplitDisplay(form, prefix) {
    const block = paymentBlock(form, prefix);
    if (!block) return;
    const rows = formPaymentRows(form, prefix);
    const total = asNumber(block.dataset.paymentTotal);
    const isFormMode = !!block.querySelector(".payment-drawer.form");
    const blockIdx = paymentBlockIndexes(form, prefix);
    const showNextIfPartial = !isFormMode || rows.some(hasPaymentContent) || blockIdx.some((index) => {
      const input = paymentAmountInput(form, prefix, index);
      return input && (input.dataset.autoAmount === "true" || input.dataset.userAmountEdited === "true");
    });
    const baseVisibleCount = visiblePaymentCount(rows, total, paymentBlockCount(form, prefix), showNextIfPartial);
    // Complète le calcul pur (basé sur les données, cf. hasSignificantPaymentIntent) avec deux
    // signaux fiables UNIQUEMENT au niveau du DOM : un moyen de paiement explicitement choisi par
    // l'utilisateur PENDANT ce dialogue (data-user-method-edited — utile même quand la valeur
    // choisie est identique au défaut, auquel cas rien ne le distingue plus au niveau de l'objet
    // seul) et une TVA réellement spécifique posée au rendu (data-tax-significant — comparaison de
    // valeur au taux par défaut réellement applicable, PAS data-auto-tax qui devient toujours vrai
    // dès qu'une ligne a été sauvegardée au moins une fois par ce formulaire, cf. commentaire dans
    // compactPaymentEditor). Cette complétion ne peut qu'ÉTENDRE visibleCount, jamais le réduire :
    // aucune ligne significative au DOM n'est masquée.
    let domSignificantHighest = -1;
    blockIdx.forEach((index) => {
      const methodInput = paymentMethodInput(form, prefix, index);
      const taxInput = paymentTaxInput(form, prefix, index);
      const domSignificant = (methodInput && methodInput.dataset.userMethodEdited === "true")
        || (taxInput && taxInput.dataset.taxSignificant === "true");
      if (domSignificant) domSignificantHighest = index;
    });
    const visibleCount = Math.max(baseVisibleCount, domSignificantHighest + 1);
    blockIdx.forEach((index) => {
      const payment = paymentObjectFromForm(form, prefix, index);
      const chip = block.querySelector(`[data-payment-tab="${index}"]`);
      const status = paymentDisplayStatus(payment, asNumber(payment.amount), "form");
      const amount = asNumber(payment.amount);
      if (chip) {
        chip.hidden = index >= visibleCount;
        const filled = hasPaymentContent(payment);
        const method = paymentMethodLabel(payment, index);
        chip.className = `payment-mini-chip ${filled ? "filled" : ""} ${chip.classList.contains("active") ? "active" : ""} ${statusClass(status)}`;
        chip.title = `Paiement ${method}${amount ? ` · ${compactMoney(amount)}` : ""}${status ? ` · ${statusLabel(status)}` : ""}`;
        const methodLabel = chip.querySelector("b");
        if (methodLabel) methodLabel.textContent = method;
        const amountLabel = chip.querySelector("span");
        if (amountLabel) amountLabel.textContent = amount ? compactMoney(amount) : "-";
        let dot = chip.querySelector("i");
        if (status && !dot) {
          dot = document.createElement("i");
          dot.setAttribute("aria-hidden", "true");
          chip.appendChild(dot);
        }
        if (!status && dot) dot.remove();
      }
      const row = block.querySelector(`[data-payment-row="${index}"]`);
      if (row) {
        row.hidden = index >= visibleCount;
        const immediate = isImmediatePayment(payment);
        row.classList.toggle("immediate-payment", immediate);
        const label = row.querySelector(".payment-label");
        if (label) label.textContent = paymentMethodLabel(payment, index);
        const dateInput = form.elements[`${prefix}${index}Date`];
        const dateLabel = row.querySelector(".payment-date-field");
        if (dateLabel?.firstChild) dateLabel.firstChild.textContent = immediate ? "Payé le" : "Encaisser le";
        const checkNumberInput = form.elements[`${prefix}${index}CheckNumber`];
        if (immediate && checkNumberInput) checkNumberInput.value = "";
        const hiddenState = form.elements[`${prefix}${index}State`];
        const manualState = row.querySelector("[data-form-payment-state]");
        // État canonique de référence AVANT toute mutation ci-dessous : sert à ne jamais effacer
        // silencieusement un marqueur "Annulé"/"Refusé" persisté (le champ caché reste la source de
        // vérité, mais le select manuel doit rester synchrone -> pas de confusion visuelle avec une
        // ligne vide). "Refusé" n'est plus jamais réinitialisé automatiquement pour une méthode
        // immédiate : cette réinitialisation (ancien comportement) effaçait silencieusement une
        // donnée métier réelle à chaque recalcul, y compris à la simple ouverture du formulaire —
        // exactement la suppression interdite par la décision produit. Un utilisateur qui souhaite
        // réellement changer le statut d'une ligne reste libre de le faire via le select manuel.
        const isCancelled = hiddenState ? paymentStateValue({ state: hiddenState.value }) === "Annulé" : false;
        const isRefused = hiddenState ? paymentStateValue({ state: hiddenState.value }) === "Refusé" : false;
        if (immediate) {
          if (manualState && !isCancelled && !isRefused) manualState.value = "";
        } else if (hiddenState && paymentStateValue({ state: hiddenState.value }) === "Payé" && paymentStatus(payment) !== "OK") {
          hiddenState.value = "";
        }
        // Régénère les <option> du select manuel si nécessaire : la liste rendue initialement
        // (paymentStateOptions au premier rendu) ne contient "Annulé" que si la ligne l'était déjà à
        // ce moment-là ; sans cela, une simple affectation de .value échouerait silencieusement (aucune
        // <option value="Annulé"> présente pour méthode immédiate OU chèque après ce point du cycle).
        if (manualState && isCancelled && manualState.value !== "Annulé") {
          manualState.innerHTML = paymentStateOptions("Annulé", amount);
        }
        const payButton = row.querySelector(".payment-ok");
        if (payButton) {
          const paid = status === "OK";
          payButton.textContent = paid ? "Annuler paiement" : "Payer";
          payButton.classList.toggle("cancel-payment", paid);
          payButton.title = paid
            ? "Annuler la validation du paiement"
            : amount > 0 ? "Valider le paiement" : "Impossible de marquer payé avec une somme à zéro";
        }
        // Verrou de la ligne selon le statut (validée -> non éditable ; non validée -> éditable).
        syncFormPaymentRowLock(row, payment, status === "OK");
        // Une ligne devenue superflue (index >= visibleCount, ex. une échéance ultérieure alors
        // qu'une ligne antérieure couvre déjà le total) ne peut être vidée QUE si elle est
        // purement automatique (voir isFormPaymentRowPurelyAutomatic) : jamais une ligne
        // Refusée/Annulée/Payée/En cours/À encaisser, ni une saisie manuelle (montant, date,
        // numéro de chèque). visiblePaymentCount garantit déjà qu'une ligne significative reste de
        // toute façon toujours < visibleCount (donc jamais masquée) ; ce garde-fou supplémentaire
        // protège aussi contre un désaccord ponctuel entre les deux calculs.
        if (index >= visibleCount && isFormPaymentRowPurelyAutomatic(form, prefix, index, payment)) {
          const amountInput = form.elements[`${prefix}${index}Amount`];
          if (checkNumberInput) checkNumberInput.value = "";
          if (amountInput) amountInput.value = "";
          if (dateInput) dateInput.value = "";
          if (hiddenState) hiddenState.value = "";
          if (manualState) manualState.value = "";
        }
      }
      const statusBox = block.querySelector(`[data-payment-row="${index}"] .computed-payment-status`);
      if (statusBox) statusBox.innerHTML = `<span>État</span>${computedPaymentStatus(status, "form")}`;
    });
    updatePaymentDueDisplay(form, prefix);
  }

  function updatePaymentDueDisplay(form, prefix) {
    const block = paymentBlock(form, prefix);
    const total = asNumber(block?.dataset.paymentTotal);
    const rows = formPaymentRows(form, prefix);
    const dueInputs = form.querySelectorAll(`[data-payment-due-prefix="${CSS.escape(prefix)}"], [data-payment-balance-due-prefix="${CSS.escape(prefix)}"]`);
    const due = money(Math.max(0, total - paidAmount(rows)));
    dueInputs.forEach((input) => {
      input.value = due;
    });
    const overpayBox = block?.querySelector("[data-payment-overpay]");
    if (overpayBox) {
      const covered = paymentCoverageAmount(rows, paymentBlockCount(form, prefix));
      const over = covered - total;
      // Un total à 0 € (ex. remise totale) avec un paiement manuel resté positif est un trop-perçu
      // à part entière : ne plus l'exclure via un total > 0, sinon le bandeau reste muet dans ce cas.
      if (over > 0.005) {
        overpayBox.hidden = false;
        overpayBox.textContent = `Attention : les paiements saisis (${money(covered)}) dépassent le total attendu (${money(total)}) de ${money(over)}.`;
      } else {
        overpayBox.hidden = true;
        overpayBox.textContent = "";
      }
    }
  }

  function setupAutoPaymentSplit(form, prefix, total = 0) {
    const block = paymentBlock(form, prefix);
    if (block) block.dataset.paymentTotal = String(asNumber(total));
    const inputs = paymentBlockIndexes(form, prefix).map((index) => paymentAmountInput(form, prefix, index));
    inputs.forEach((input) => {
      if (!input || input.dataset.autoSplitReady) return;
      input.dataset.autoSplitReady = "true";
      input.addEventListener("input", () => {
        input.dataset.autoAmount = "";
        input.dataset.userAmountEdited = "true";
        input.dataset.manualEmpty = asText(input.value) ? "" : "true";
        distributePaymentSplit(form, prefix, input);
      });
      input.addEventListener("change", () => {
        input.dataset.manualEmpty = asText(input.value) ? "" : "true";
        distributePaymentSplit(form, prefix, input);
      });
    });
    paymentBlockIndexes(form, prefix).map((index) => paymentTaxInput(form, prefix, index)).forEach((input) => {
      if (!input || input.dataset.autoTaxReady) return;
      input.dataset.autoTaxReady = "true";
      input.addEventListener("input", () => {
        input.dataset.autoTax = "";
      });
    });
    // Marqueur DOM non persistant : pose data-user-method-edited UNIQUEMENT sur un véritable
    // événement "change" déclenché par l'utilisateur sur le select du moyen — jamais au rendu
    // initial ni lors d'une affectation automatique. Sert à garder une ligne accessible pendant CE
    // dialogue même si la valeur choisie est identique au moyen par défaut (auquel cas rien ne le
    // distingue plus après sauvegarde/réouverture — cf. hasSignificantPaymentIntent qui, lui,
    // détecte déjà une valeur PERSISTÉE différente du défaut, avec ou sans ce marqueur).
    paymentBlockIndexes(form, prefix).map((index) => paymentMethodInput(form, prefix, index)).forEach((input) => {
      if (!input || input.dataset.autoMethodReady) return;
      input.dataset.autoMethodReady = "true";
      input.addEventListener("change", () => {
        input.dataset.userMethodEdited = "true";
      });
    });
    block?.querySelectorAll("input, select").forEach((control) => {
      if (control.dataset.autoDisplayReady) return;
      control.dataset.autoDisplayReady = "true";
      control.addEventListener("change", () => {
        updateFormPaymentState(control);
        if (control.matches("[data-form-payment-state]")) distributePaymentSplit(form, prefix, control);
        updatePaymentSplitDisplay(form, prefix);
      });
    });
    distributePaymentSplit(form, prefix);
  }

  function updateFormPaymentState(control) {
    if (!control.matches("[data-form-payment-state]")) return;
    const form = control.closest("form");
    const prefix = control.dataset.prefix || "";
    const index = Number(control.dataset.index);
    const hidden = form?.elements[`${prefix}${index}State`];
    if (!hidden) return;
    const nextState = paymentStateValue({ state: control.value }) === "Refusé" ? "Refusé" : "";
    // Réactivation CONTRÔLÉE (formulaire) : sortir de « Refusé » est interdit si le montant de ce
    // paiement dépasse le reste réellement dû. Même règle/message que le live (helper partagé).
    if (paymentStateValue({ state: hidden.value }) === "Refusé" && nextState === "") {
      const block = paymentBlock(form, prefix);
      const amount = asNumber(form.elements[`${prefix}${index}Amount`]?.value);
      if (!reactivateRefusedAllowed(formPaymentRows(form, prefix), index, { amount }, asNumber(block?.dataset.paymentTotal))) {
        control.value = "Refusé";
        hidden.value = "Refusé";
        return;
      }
    }
    hidden.value = nextState;
  }

  function distributePaymentSplit(form, prefix, changedInput = null) {
    const block = paymentBlock(form, prefix);
    const total = asNumber(block?.dataset.paymentTotal);
    const inputs = paymentBlockIndexes(form, prefix).map((index) => paymentAmountInput(form, prefix, index));
    if (!total) {
      // Remise ramenant le total à 0 € : vider les montants automatiques (clearAutoPaymentAmount
      // ignore déjà les montants saisis manuellement) pour ne pas laisser un paiement prérempli
      // figé alors que la commande ne coûte plus rien.
      inputs.forEach(clearAutoPaymentAmount);
      updatePaymentSplitDisplay(form, prefix);
      return;
    }
    if (!inputs[0]) return;
    const userClearedInput = changedInput && changedInput.dataset.manualEmpty === "true" && !asText(changedInput.value);
    if (userClearedInput) inputs.slice(inputs.indexOf(changedInput) + 1).forEach(clearAutoPaymentAmount);
    if (!changedInput) inputs.forEach(clearAutoPaymentAmount);
    if (!inputs.some((input) => asText(input?.value))) {
      if (!changedInput && canAutoFillPaymentAmount(inputs[0])) setAutoPaymentAmount(inputs[0], total);
      updatePaymentSplitDisplay(form, prefix);
      return;
    }
    let sum = 0;
    for (let index = 0; index < inputs.length; index += 1) {
      const input = inputs[index];
      if (!input) continue;
      const value = asNumber(input.value);
      const hasValue = asText(input.value) !== "";
      const refused = paymentStateValue(paymentObjectFromForm(form, prefix, index)) === "Refusé";
      if (hasValue && !refused) sum += value;
      const next = inputs[index + 1];
      const remainder = Math.max(0, total - sum);
      if (next && hasValue) {
        if (remainder > 0 && canAutoFillPaymentAmount(next, changedInput) && (!asText(next.value) || next.dataset.autoAmount === "true")) setAutoPaymentAmount(next, remainder);
        if (remainder <= 0) {
          inputs.slice(index + 1).forEach(clearAutoPaymentAmount);
        }
      }
    }
    if (!changedInput) capPaymentCoverageToTotal(form, prefix, inputs, total);
    updatePaymentSplitDisplay(form, prefix);
  }

  // Lors d'un recalcul lié au total (ex. remise appliquée), on ne laisse jamais un montant
  // PUREMENT AUTOMATIQUE (suggestion jamais saisie/validée manuellement) dépasser le nouveau
  // total affiché : on le rogne, ou on le vide s'il devient nul. Ne rogne et ne vide JAMAIS un
  // montant saisi manuellement, ni une ligne Payée/Annulée/En cours/À encaisser (même non
  // Refusée) : si l'excédent subsiste après épuisement des lignes purement automatiques, on
  // laisse l'incohérence visible plutôt que d'effacer une donnée réelle — les garde-fous de
  // surpaiement existants (paymentOverpayMessage, finalCheckValidationMessage) restent chargés de
  // bloquer une validation incohérente, jamais ce recalcul d'affichage.
  function capPaymentCoverageToTotal(form, prefix, inputs, total) {
    const expected = Math.max(0, asNumber(total));
    let coverage = inputs.reduce((sum, input, index) => {
      if (!input || !asText(input.value)) return sum;
      if (paymentStateValue(paymentObjectFromForm(form, prefix, index)) === "Refusé") return sum;
      return sum + asNumber(input.value);
    }, 0);
    let excess = coverage - expected;
    if (excess <= 0.005) return;
    for (let index = inputs.length - 1; index >= 0 && excess > 0.005; index -= 1) {
      const input = inputs[index];
      if (!input || !asText(input.value)) continue;
      if (paymentStateValue(paymentObjectFromForm(form, prefix, index)) === "Refusé") continue;
      if (input.dataset.autoAmount !== "true" || input.dataset.userAmountEdited === "true") continue;
      const value = asNumber(input.value);
      const reduced = Math.max(0, value - excess);
      excess -= value - reduced;
      if (reduced <= 0) {
        input.value = "";
        input.dataset.autoAmount = "";
      } else {
        input.value = String(Math.round(reduced * 100) / 100);
        input.dataset.autoAmount = "true";
      }
    }
  }

  function paymentCoverageAmount(payments = [], count = paymentCheckCount()) {
    return paymentIndexes(count).reduce((sum, index) => {
      const payment = payments[index] || {};
      return paymentCountsTowardSchedule(payment) ? sum + asNumber(payment.amount) : sum;
    }, 0);
  }

  function finalCheckValidationMessage(payments = [], total = 0, count = paymentCheckCount()) {
    const expected = asNumber(total);
    if (expected <= 0) return "";
    const max = normalizePaymentCheckCount(count);
    const rows = paymentIndexes(max).map((index) => payments[index] || {});
    const covered = paymentCoverageAmount(rows, max);
    if (covered <= 0 || covered >= expected - 0.005) return "";
    const visibleCount = visiblePaymentCount(rows, expected, max);
    if (visibleCount < max) return "";
    return `Non, vous devez payer la totalité de la somme. Il reste ${money(expected - covered)} à couvrir sur le dernier paiement autorisé.`;
  }

  function validateFormPaymentBlocks(form) {
    for (const block of form.querySelectorAll("[data-payment-prefix]")) {
      const prefix = block.dataset.paymentPrefix || "";
      const message = finalCheckValidationMessage(formPaymentRows(form, prefix), asNumber(block.dataset.paymentTotal), paymentBlockCount(form, prefix));
      if (message) return message;
    }
    return "";
  }

  function membershipTariffSummary(row = {}) {
    const values = membershipTariffValues(row);
    return `<div class="dialog-section tariff-summary" data-membership-tariff-summary data-membership-payment-summary>
      <h3>Tarif calculé</h3>
      <div class="tariff-summary-grid">
        <div><span>Tarif discipline</span><strong data-tariff-value="gross">${money(values.grossTotal)}</strong></div>
        <div data-tariff-license-line ${values.license ? "" : "hidden"}><span>Licence</span><strong data-tariff-value="license">${money(values.license)}</strong></div>
        <div><span>Assurance</span><strong data-tariff-value="insurance">${money(values.insurancePrice)}</strong></div>
        <div><span>Remise</span><strong data-tariff-value="discount">${money(values.discount)}</strong></div>
        <div><span>Total attendu</span><strong data-tariff-value="total">${money(values.total)}</strong></div>
      </div>
    </div>`;
  }

  function updateMembershipTariffSummary(form) {
    const summary = form.querySelector("[data-membership-tariff-summary]");
    if (!summary) return;
    const selectedDiscipline = form.elements.discipline?.value;
    const useFrozen = asText(form.elements.frozenDiscipline?.value) === asText(selectedDiscipline)
      && asText(form.elements.frozenDisciplinePrice?.value) !== "";
    const values = membershipTariffValues({
      discipline: selectedDiscipline,
      insuranceChoice: form.elements.insuranceChoice?.value,
      discount: form.elements.discount?.value,
      ...(useFrozen ? {
        disciplinePrice: form.elements.frozenDisciplinePrice.value,
        disciplineLicense: form.elements.frozenDisciplineLicense?.value,
      } : {}),
    });
    summary.querySelector('[data-tariff-value="gross"]').textContent = money(values.grossTotal);
    const licenseEl = summary.querySelector('[data-tariff-value="license"]');
    if (licenseEl) {
      licenseEl.textContent = money(values.license);
      const line = licenseEl.closest("[data-tariff-license-line]");
      if (line) line.hidden = !values.license;
      else licenseEl.hidden = !values.license;
    }
    summary.querySelector('[data-tariff-value="insurance"]').textContent = money(values.insurancePrice);
    summary.querySelector('[data-tariff-value="discount"]').textContent = money(values.discount);
    summary.querySelector('[data-tariff-value="total"]').textContent = money(values.total);
    const disciplinePrice = form.querySelector("[data-membership-discipline-price]");
    if (disciplinePrice) disciplinePrice.value = money(values.grossTotal);
    const insurancePrice = form.querySelector("[data-membership-insurance-price]");
    if (insurancePrice) insurancePrice.value = money(values.insurancePrice);
    setupAutoPaymentSplit(form, "payment", values.total);
    setDefaultPaymentTaxRate(form, "payment", membershipDefaultTaxRate({
      discipline: form.elements.discipline?.value,
      insuranceChoice: form.elements.insuranceChoice?.value,
      discount: form.elements.discount?.value,
    }));
  }

  function readPayments(form, prefix, formElement = null) {
    const indexes = formElement ? paymentBlockIndexes(formElement, prefix) : paymentIndexes();
    return indexes.map((index) => {
      const payment = {
        check: form.get(`${prefix}${index}Check`) || defaultPaymentMethod(index),
        checkNumber: asText(form.get(`${prefix}${index}CheckNumber`)),
        amount: asNumber(form.get(`${prefix}${index}Amount`)),
        taxRate: Math.max(0, asNumber(form.get(`${prefix}${index}TaxRate`))),
        date: form.get(`${prefix}${index}Date`) || "",
        // "Annulé" doit survivre à la lecture du formulaire au même titre que "Payé"/"Refusé" :
        // sans cette entrée, une ligne annulée dans le formulaire puis enregistrée perdait son état
        // canonique (retombait à vide, indiscernable d'une ligne jamais touchée).
        state: ["Payé", "Refusé", "Annulé"].includes(paymentStateValue({ state: form.get(`${prefix}${index}State`) }))
          ? paymentStateValue({ state: form.get(`${prefix}${index}State`) })
          : "",
      };
      // Garde côté SAUVEGARDE : une ligne validée verrouillée (data-payment-locked) restaure ses
      // valeurs canoniques. On n'enregistre jamais une modification incohérente d'un paiement validé,
      // même si un champ a été altéré de force. L'annulation retire le verrou -> la ligne redevient libre.
      const row = formElement && paymentBlock(formElement, prefix)?.querySelector(`[data-payment-row="${index}"]`);
      if (row && row.dataset.paymentLocked === "1") {
        payment.check = asText(row.dataset.lockedCheck) || payment.check;
        payment.checkNumber = asText(row.dataset.lockedChecknumber);
        payment.amount = asNumber(row.dataset.lockedAmount);
        payment.taxRate = Math.max(0, asNumber(row.dataset.lockedTax));
        payment.date = asText(row.dataset.lockedDate);
        payment.state = asText(row.dataset.lockedState) || "Payé";
      }
      return normalizeImmediatePayment(payment);
    });
  }

  function showDialog(title, body, onSave, onOpen = () => {}, footerLeft = "", onCancel = () => {}, submitLabel = "Enregistrer") {
    // Déduplication : une fiche déjà ouverte (ou réduite) est réutilisée, pas recréée.
    const windowKey = pendingWindowKey; pendingWindowKey = null;
    if (windowKey && keyedWindows.has(windowKey)) {
      const existing = keyedWindows.get(windowKey);
      const existingDialog = existing.dialogEl();
      // Une entrée peut rester en mémoire alors que sa fenêtre vient d'être fermée par du code
      // (ex. « Fiche contact / facture » qui ferme puis rouvre aussitôt la même fiche) : l'événement
      // "close" qui nettoie keyedWindows n'a pas encore eu lieu. Sans cette vérification, on
      // « réactive » une fenêtre déjà fermée (aucun effet visible) au lieu d'en reconstruire une —
      // d'où un bouton qui semblait tout fermer sans rien rouvrir. On ne réutilise que si la fenêtre
      // est réellement affichée ou correctement réduite ; sinon on purge l'entrée périmée et on
      // reconstruit normalement la fiche ci-dessous.
      if (existingDialog?.open || existing.isMinimized?.()) {
        existing.activate();
        return existingDialog;
      }
      keyedWindows.delete(windowKey);
    }
    const targetDialog = dialogForNewWindow();
    const host = { dialog: targetDialog };
    targetDialog.innerHTML = `<form>
      <div class="dialog-header"><h2>${esc(title)}</h2><div class="dialog-header-actions"><button class="icon" type="button" data-dialog-minimize title="Réduire la fenêtre" aria-label="Réduire la fenêtre">—</button><button class="icon" type="button" data-dialog-close title="Fermer" aria-label="Fermer">×</button></div></div>
      <div class="dialog-body"><div class="form-grid">${body}</div></div>
      <datalist id="paymentStateList"><option value="Refusé"></option></datalist>
      <div class="dialog-footer">
        ${footerLeft ? `<div class="dialog-footer-left">${footerLeft}</div>` : `<span></span>`}
        <div class="dialog-footer-actions"><button type="button" data-dialog-close>Annuler</button><button class="primary" type="submit">${esc(submitLabel)}</button></div>
      </div>
    </form>`;
    const applyDialogClasses = (dlg) => {
      dlg.classList.toggle("has-identity-photo", Boolean(dlg.querySelector("[data-identity-photo-widget]")));
      dlg.classList.toggle("club-editor-dialog", Boolean(dlg.querySelector(".club-form-section")));
    };
    applyDialogClasses(targetDialog);
    const form = targetDialog.querySelector("form");
    // Propriété du formulaire (Lot 4A) : on mémorise l'utilisateur qui l'a ouvert. À la soumission,
    // si l'utilisateur authentifié a changé, la mutation est refusée (jamais attribuée à un autre
    // profil). Sert aussi à repérer/fermer les formulaires de mutation lors d'un changement d'user.
    form.dataset.openedBy = activeUserId();
    let saved = false;
    let minimized = false;
    // Fermeture (× / Annuler) : agit sur le dialogue hôte courant (peut changer après réduction/réouverture).
    form.querySelectorAll("[data-dialog-close]").forEach((button) => button.addEventListener("click", () => host.dialog.close()));
    const disposeWindow = () => { if (windowKey) keyedWindows.delete(windowKey); };
    const closeHandler = () => {
      if (!saved && !minimized) onCancel(form);
      if (!minimized) disposeWindow();
    };
    const armCloseHandler = (dlg) => dlg.addEventListener("close", closeHandler, { once: true });
    armCloseHandler(targetDialog);

    // --- Réduction (bouton —) : déplace le <form> vivant en réserve et ferme sans annuler ;
    //     la pastille en bas le rouvre exactement dans l'état saisi. Purement UX. ---
    const minWindow = { id: `min-${++minimizedSeq}`, emoji: "🪟", label: asText(title) || "Fenêtre" };
    const minimizeWindow = () => {
      if (minimized) return;
      minimized = true;
      minWindow.emoji = minimizedEmojiFor(title);
      minWindow.label = minimizedLabelFor(title, form);
      ensureMinimizedStash().appendChild(form);
      host.dialog.close();
      registerMinimizedWindow(minWindow);
    };
    const restoreWindow = () => {
      unregisterMinimizedWindow(minWindow);
      minimized = false;
      host.dialog = dialogForNewWindow();
      host.dialog.innerHTML = "";
      host.dialog.appendChild(form);
      applyDialogClasses(host.dialog);
      armCloseHandler(host.dialog);
      showFloatingDialog(form, "", host.dialog);
    };
    const closeForGoodWindow = () => {
      unregisterMinimizedWindow(minWindow);
      disposeWindow();
      if (form.parentElement) form.parentElement.removeChild(form);
      if (!saved) onCancel(form);
    };
    minWindow.restore = restoreWindow;
    minWindow.closeForGood = closeForGoodWindow;
    form.querySelector("[data-dialog-minimize]")?.addEventListener("click", minimizeWindow);
    // Enregistre la fenêtre par clé (édition d'un objet) pour la déduplication.
    if (windowKey) {
      keyedWindows.set(windowKey, {
        dialogEl: () => host.dialog,
        activate: () => { if (minimized) restoreWindow(); else focusDialogControl(form); },
        isMinimized: () => minimized,
      });
    }
    form.addEventListener("submit", async (event) => {
      event.preventDefault();
      // Garde d'authentification (Lot 4A) : session valide requise, et le formulaire doit être
      // soumis par le même profil qui l'a ouvert. Sinon aucune mutation n'est enregistrée.
      if (!requireAuthenticatedSession()) return;
      if (authRequired() && form.dataset.openedBy && form.dataset.openedBy !== activeUserId()) {
        alert("Ce formulaire a été ouvert sous un autre profil. Veuillez le rouvrir avec l'utilisateur actuellement authentifié.");
        return;
      }
      form.dataset.submitAction = event.submitter?.dataset.submitAction || "";
      const paymentMessage = validateFormPaymentBlocks(event.currentTarget);
      if (paymentMessage) {
        alert(paymentMessage);
        // Une action secondaire (Fiche contact / facture) avait demandé une navigation après save :
        // la sauvegarde n'a pas lieu -> on annule aussi la navigation et on laisse corriger.
        delete form.dataset.followUpAction; delete form.dataset.followUpData; delete form.dataset.followUpModule;
        return;
      }
      recordHistory();
      const result = await onSave(new FormData(event.currentTarget), event.currentTarget);
      // Validation échouée (champ requis manquant, etc.) : on reste dans la popup et on annule toute
      // action secondaire en attente -> aucune navigation, aucun contact ouvert.
      if (result === false || result?.cancel === true) {
        delete form.dataset.followUpAction; delete form.dataset.followUpData; delete form.dataset.followUpModule;
        return;
      }
      saved = true;
      const message = typeof result === "string" ? result : result?.message;
      const notice = typeof result === "object" ? result?.notice : "";
      const defaultMessage = `${title.startsWith("Modifier") ? "Modification" : "Création"} : ${title}`;
      persist(message || defaultMessage);
      host.dialog.close();
      render();
      if (host.dialog !== dialog) refreshOpenContactDialog();
      if (typeof refreshOpenCourseEnrollmentDialogs === "function") refreshOpenCourseEnrollmentDialogs();
      refreshOpenInvoiceEditor();
      refreshOpenDossierDialog();
      if (typeof refreshOpenVigilanceResolver === "function") refreshOpenVigilanceResolver();
      if (typeof result === "object" && result?.reopenInvoiceId) {
        const emittedInvoice = state.invoices.find((invoice) => invoice.id === result.reopenInvoiceId);
        if (emittedInvoice) setTimeout(() => openInvoiceEditor(emittedInvoice), 0);
      }
      if (typeof result === "object" && result?.orderInvoiceFollowUpId) {
        setTimeout(() => showOrderInvoiceFollowUp(result.orderInvoiceFollowUpId), 0);
      }
      if (typeof result === "object" && result?.printRegistrationInvoice) {
        setTimeout(() => printRegistrationInvoice(result.printRegistrationInvoice), 0);
      }
      // Action secondaire « Fiche contact / facture » : on a sauvegardé le formulaire AVANT de
      // naviguer, donc la fiche/facture cible reflète les données à jour (ex. paiement validé).
      const followUpAction = form.dataset.followUpAction || "";
      const followUpData = form.dataset.followUpData || "";
      const followUpModule = form.dataset.followUpModule || "";
      delete form.dataset.followUpAction; delete form.dataset.followUpData; delete form.dataset.followUpModule;
      if (followUpAction === "open-linked-contact" && followUpData) setTimeout(() => openContactDialogFromLink(followUpData), 0);
      else if (followUpAction === "open-contact-invoice" && followUpData) setTimeout(() => openContactInvoiceFromLink(followUpData), 0);
      else if (followUpAction === "open-contact-module" && followUpData) setTimeout(() => openContactModuleFromLink(followUpData, followUpModule), 0);
      if (notice) showInfoDialog("Changement de statut", `<p>${esc(notice)}</p>`);
    });
    onOpen(form);
    setupAddressAutocomplete(form);
    applyClickableTooltips(targetDialog);
    enhanceNumberSteppers(targetDialog);
    showFloatingDialog(form, "", targetDialog);
    return targetDialog;
  }

  function showInfoDialog(title, body, opts) {
    const targetDialog = dialogForNewWindow();
    // opts.iconHtml (facultatif) : SVG/HTML contrôlé affiché avant le titre. Rétrocompatible :
    // sans opts, le titre reste un simple texte échappé (comportement historique inchangé).
    const o = opts || {};
    const titleHtml = o.iconHtml
      ? `<span class="${esc(o.iconClass || "dialog-title-icon")}" aria-hidden="true">${o.iconHtml}</span>${esc(title)}`
      : esc(title);
    targetDialog.innerHTML = `<div>
      <div class="dialog-header"><h2>${titleHtml}</h2><button class="icon" type="button" data-dialog-close title="Fermer" aria-label="Fermer">×</button></div>
      <div class="dialog-body">${body}</div>
      <div class="dialog-footer"><button type="button" data-dialog-close>Fermer</button></div>
    </div>`;
    targetDialog.classList.remove("has-identity-photo");
    targetDialog.querySelectorAll("[data-dialog-close]").forEach((button) => button.addEventListener("click", () => targetDialog.close()));
    applyClickableTooltips(targetDialog);
    enhanceNumberSteppers(targetDialog);
    showFloatingDialog(targetDialog, "[data-dialog-close], button:not([disabled])", targetDialog);
    return targetDialog;
  }

  function showContactDocumentDialog(name, dataUrl) {
    const isImage = /^data:image\//i.test(dataUrl);
    const viewer = isImage
      ? `<img class="contact-document-image" src="${esc(dataUrl)}" alt="${esc(name)}" />`
      : `<iframe class="contact-document-frame" src="${esc(dataUrl)}" title="${esc(name)}"></iframe>`;
    showInfoDialog(name, `<div class="contact-document-viewer">
      ${viewer}
      <p class="muted">Si le document ne s'affiche pas dans le cadre, utilise le bouton Ouvrir / télécharger.</p>
      <div class="inline-actions">
        <a class="button-like" href="${esc(dataUrl)}" target="_blank" rel="noopener">Ouvrir / télécharger</a>
      </div>
    </div>`);
  }

  function openArticleImageDialog(source) {
    const article = articleById(source.dataset.articleId)
      || (ui.stockArticleDraft && ui.stockArticleDraft.id === source.dataset.articleId ? ui.stockArticleDraft : null);
    const images = articleImages(article);
    const captions = articleImageCaptions(article, images.length);
    if (!images.length) return;
    const startIndex = Math.min(Math.max(0, Number(source.dataset.imageIndex) || 0), images.length - 1);
    showInfoDialog(article.name || "Article", `<div class="article-image-viewer" data-article-gallery data-gallery-index="${startIndex}">
      ${images.length > 1 ? `<button class="icon article-gallery-arrow prev" type="button" data-action="article-gallery-prev" title="Image précédente">‹</button>` : ""}
      <div class="article-image-stage">
        ${images.map((image, index) => `<figure class="${index === startIndex ? "active" : ""}" data-gallery-item>
          <img src="${esc(image)}" alt="${esc(captions[index] || article.name || "Article")}" />
          <figcaption>${captions[index] ? esc(captions[index]) : "Sans légende"}</figcaption>
        </figure>`).join("")}
      </div>
      ${images.length > 1 ? `<button class="icon article-gallery-arrow next" type="button" data-action="article-gallery-next" title="Image suivante">›</button>` : ""}
      <div class="article-gallery-counter" data-gallery-counter>${startIndex + 1} / ${images.length}</div>
      ${images.length > 1 ? `<div class="article-gallery-thumbs" aria-label="Miniatures">
        ${images.map((image, index) => `<button class="article-library-thumb ${index === startIndex ? "active" : ""}" type="button" data-action="article-gallery-select" data-image-index="${index}" data-gallery-thumb title="Afficher cette image">
          <img src="${esc(image)}" alt="${esc(captions[index] || article.name || "Article")}" />
        </button>`).join("")}
      </div>` : ""}
    </div>`);
  }

  function setImageGalleryIndex(viewer, next) {
    const items = [...(viewer?.querySelectorAll("[data-gallery-item]") || [])];
    if (!viewer || !items.length) return;
    const index = (next + items.length) % items.length;
    viewer.dataset.galleryIndex = String(index);
    viewer.querySelectorAll("[data-gallery-thumb]").forEach((thumb) => {
      thumb.classList.toggle("active", Number(thumb.dataset.imageIndex) === index);
    });
    items.forEach((item, itemIndex) => item.classList.toggle("active", itemIndex === index));
    const counter = viewer.querySelector("[data-gallery-counter]");
    if (counter) counter.textContent = `${index + 1} / ${items.length}`;
  }

  function shiftArticleGallery(button, direction) {
    const viewer = button.closest("[data-article-gallery], [data-article-image-library]");
    const items = [...(viewer?.querySelectorAll("[data-gallery-item]") || [])];
    if (!viewer || items.length < 2) return;
    const current = Math.min(Math.max(0, Number(viewer.dataset.galleryIndex) || 0), items.length - 1);
    setImageGalleryIndex(viewer, current + direction);
  }

  function selectArticleGalleryImage(button) {
    const viewer = button.closest("[data-article-gallery], [data-article-image-library]");
    setImageGalleryIndex(viewer, Number(button.dataset.imageIndex) || 0);
  }

  function contactForMembership(membership = {}) {
    return state.contacts.members.find((contact) => contact.id && contact.id === membership.contactId)
      || state.contacts.members.find((contact) => personKey(contact) === personKey(membership))
      || null;
  }

  function contactForOrder(order = {}) {
    return state.contacts.members.find((contact) => contact.id && contact.id === order.contactId)
      || (!order.prospectContactId ? state.contacts.members.find((contact) => personKey(contact) === personKey(order)) : null)
      || null;
  }

  function prospectForOrder(order = {}) {
    return state.contacts.prospects.find((contact) => contact.id && contact.id === order.prospectContactId)
      || state.contacts.prospects.find((contact) => personKey(contact) === personKey(order))
      || null;
  }

  function contactLinkForRow(row = {}) {
    if (row.contactId) return `member:${row.contactId}`;
    if (row.prospectContactId) return `prospect:${row.prospectContactId}`;
    const member = contactForOrder(row);
    if (member) return `member:${member.id}`;
    const prospect = prospectForOrder(row);
    if (prospect) return `prospect:${prospect.id}`;
    return "";
  }

  function contactLinkAction(row = {}, label = "Fiche contact / facture") {
    const contactLink = contactLinkForRow(row);
    if (!contactLink) return "";
    return `<button type="button" data-action="open-linked-contact" data-contact-link="${esc(contactLink)}">${esc(label)}</button>`;
  }

  function shopOrderInvoiceSourcePrefix(orderId = "") {
    return `boutique:${asText(orderId)}:`;
  }

  function invoiceForShopOrder(orderId = "") {
    const prefix = shopOrderInvoiceSourcePrefix(orderId);
    if (!asText(orderId)) return null;
    return (state.invoices || []).find((invoice) => (invoice.lines || []).some((line) => asText(line.sourceKey).startsWith(prefix))) || null;
  }

  // Intégrité financière d'une commande boutique : verrous de suppression/modification, calculés
  // uniquement à partir de données déjà persistées (facture liée + paiements de la commande),
  // aucun nouveau champ, aucun statut de commande. Helper pur (pas de DOM, pas de HTML) réutilisé
  // par le rendu des boutons (orderCard) ET par les handlers edit-order/delete-order, pour ne
  // jamais dupliquer la règle. paymentStatus() est le SEUL classificateur de paiement réutilisé
  // (déjà utilisé partout ailleurs dans l'app) : "OK" (payé), "A encaisser", "En cours" sont des
  // engagements actifs ; "Refusé" et "" (vide, y compris un paiement annulé sur un mode immédiat)
  // ne bloquent jamais. Une facture "cancelled" (statut existant mais jamais atteignable depuis
  // l'UI actuelle) n'est traitée ni comme brouillon ni comme émise.
  function shopOrderIntegrityState(order = {}) {
    const invoice = invoiceForShopOrder(order.id);
    const hasDraftInvoice = Boolean(invoice) && invoice.status === "draft";
    const hasIssuedInvoice = Boolean(invoice) && invoice.status !== "draft" && invoice.status !== "cancelled";
    // Un paiement Annulé (état canonique persistant, cf. paymentIsCancelled) n'est JAMAIS un
    // engagement actif : paymentStatus() le classe désormais "Annulé", distinct de "OK"/"A
    // encaisser"/"En cours" -> exclu naturellement de activePayments, jamais une raison de blocage.
    const activePayments = (order.payments || []).filter((payment) => {
      const status = paymentStatus(payment);
      return status === "OK" || status === "A encaisser" || status === "En cours";
    });
    const hasPaidPayment = activePayments.some((payment) => paymentStatus(payment) === "OK");
    const hasPendingPayment = activePayments.some((payment) => {
      const status = paymentStatus(payment);
      return status === "A encaisser" || status === "En cours";
    });
    // Informatif uniquement : n'ajoute jamais de raison de blocage, ne fait jamais partie d'activePayments.
    const hasCancelledPayment = (order.payments || []).some((payment) => paymentIsCancelled(payment));
    const deleteReasons = [];
    if (hasDraftInvoice) deleteReasons.push("draftInvoice");
    if (hasIssuedInvoice) deleteReasons.push("issuedInvoice");
    if (hasPaidPayment) deleteReasons.push("paidPayment");
    if (hasPendingPayment) deleteReasons.push("pendingPayment");
    const editReasons = [];
    if (hasIssuedInvoice) editReasons.push("issuedInvoice");
    if (hasPaidPayment) editReasons.push("paidPayment");
    if (hasPendingPayment) editReasons.push("pendingPayment");
    return {
      invoice,
      hasDraftInvoice,
      hasIssuedInvoice,
      activePayments,
      hasPaidPayment,
      hasPendingPayment,
      hasCancelledPayment,
      deleteBlocked: deleteReasons.length > 0,
      editBlocked: editReasons.length > 0,
      deleteReasons,
      editReasons,
    };
  }

  // Message lisible et unique (jamais une liste technique de statuts) pour un blocage donné.
  // reasons vient de shopOrderIntegrityState().deleteReasons/editReasons.
  function shopOrderIntegrityMessage(reasons = []) {
    const hasInvoiceReason = reasons.includes("draftInvoice") || reasons.includes("issuedInvoice");
    const hasPaymentReason = reasons.includes("paidPayment") || reasons.includes("pendingPayment");
    if (hasInvoiceReason && hasPaymentReason) {
      return "Cette commande possède une facture et un paiement actif. Elle ne peut plus être modifiée ni supprimée.";
    }
    if (reasons.includes("issuedInvoice")) {
      return "Cette commande possède une facture émise. Elle ne peut plus être modifiée ni supprimée.";
    }
    if (reasons.includes("paidPayment")) {
      return "Cette commande contient un paiement validé. Elle ne peut plus être modifiée ni supprimée.";
    }
    if (reasons.includes("pendingPayment")) {
      return "Cette commande contient un paiement en cours ou à encaisser. Terminez ou annulez ce paiement avant de modifier ou supprimer la commande.";
    }
    if (reasons.includes("draftInvoice")) {
      return "Cette commande possède une facture brouillon. Supprimez d'abord ce brouillon depuis les factures avant de supprimer la commande.";
    }
    return "";
  }

  function contactAndKindForOrder(order = {}) {
    const link = parseContactLink(contactLinkForRow(order));
    const kind = link.kind === "prospect" ? "prospects" : "members";
    const contact = state.contacts[kind]?.find((row) => row.id === link.contactId) || null;
    return { contact, kind };
  }

  function ensureDraftInvoiceForShopOrder(orderId = "") {
    const order = state.shopOrders.find((row) => row.id === orderId);
    if (!order) {
      alert("Commande introuvable.");
      return null;
    }
    const linked = contactAndKindForOrder(order);
    if (!linked.contact) {
      alert("Associe d'abord cette commande à un client avant de créer ou imprimer sa facture.");
      return null;
    }
    const existing = invoiceForShopOrder(order.id);
    if (existing && existing.status !== "draft") return existing;
    const billables = billableItemsForContact(linked.contact, linked.kind);
    // La remise commande a la clé "boutique-discount:<id>" (hors préfixe article "boutique:<id>:").
    // Sans cette inclusion, elle était filtrée -> facture sans remise -> total et reste dû faux.
    const orderPrefix = shopOrderInvoiceSourcePrefix(order.id);
    const orderDiscountKey = `boutique-discount:${order.id}`;
    const orderBillables = billables.filter((item) => {
      const key = asText(item.sourceKey);
      return key.startsWith(orderPrefix) || key === orderDiscountKey;
    });
    if (!orderBillables.length) {
      alert("Aucune ligne boutique facturable n'a été trouvée pour cette commande.");
      return null;
    }
    const invoice = existing || draftInvoiceForContact(linked.contact, linked.kind) || normalizeInvoice({
      contactId: linked.contact.id,
      contactKind: linked.kind,
      status: "draft",
    });
    const existingKeys = new Set((invoice.lines || []).map((line) => line.sourceKey).filter(Boolean));
    const nextLines = [
      ...(invoice.lines || []),
      ...orderBillables.filter((item) => !existingKeys.has(item.sourceKey)).map(invoiceLineFromBillable),
    ];
    const nextPayments = selectedInvoicePayments(nextLines, billables);
    const next = normalizeInvoice({
      ...invoice,
      contactId: linked.contact.id,
      contactKind: linked.kind,
      status: "draft",
      lines: nextLines,
      paymentsSnapshot: nextPayments,
      totals: invoiceTotalsFromLines(nextLines, nextPayments),
      updatedAt: new Date().toISOString(),
    });
    return next;
  }

  // Facture (non annulée) incluant déjà cette inscription stage (ligne event et/ou hébergement).
  function invoiceForRegistration(stageId = "", registrationId = "") {
    if (!asText(stageId) || !asText(registrationId)) return null;
    const prefix = `stage:${asText(stageId)}:${asText(registrationId)}:`;
    return (state.invoices || []).find((invoice) => invoice.status !== "cancelled"
      && (invoice.lines || []).some((line) => asText(line.sourceKey).startsWith(prefix))) || null;
  }

  // Crée/récupère la facture (brouillon) d'une inscription stage : lignes event + hébergement de
  // CETTE inscription. Calqué sur ensureDraftInvoiceForShopOrder (mêmes helpers). Anti-doublon : si une
  // facture émise inclut déjà l'inscription, on la retourne telle quelle (pas de nouvelle facture).
  function ensureDraftInvoiceForRegistration(stageId = "", registrationId = "") {
    const row = (state.stageRegistrations[stageId] || []).find((item) => item.id === registrationId);
    if (!row) { alert("Inscription introuvable."); return null; }
    const link = parseContactLink(contactLinkForRow(row));
    const kind = link.kind === "prospect" ? "prospects" : "members";
    const contact = state.contacts[kind]?.find((item) => item.id === link.contactId);
    if (!contact) { alert("Associe d'abord cette inscription à un contact avant de créer ou imprimer sa facture."); return null; }
    const existing = invoiceForRegistration(stageId, registrationId);
    if (existing && existing.status !== "draft") return existing; // déjà facturée -> pas de doublon
    const billables = billableItemsForContact(contact, kind);
    const prefix = `stage:${asText(stageId)}:${asText(registrationId)}:`;
    const registrationBillables = billables.filter((item) => asText(item.sourceKey).startsWith(prefix));
    if (!registrationBillables.length) { alert("Aucune ligne facturable n'a été trouvée pour cette inscription."); return null; }
    const invoice = existing || draftInvoiceForContact(contact, kind) || normalizeInvoice({ contactId: contact.id, contactKind: kind, status: "draft" });
    const existingKeys = new Set((invoice.lines || []).map((line) => line.sourceKey).filter(Boolean));
    const nextLines = [
      ...(invoice.lines || []),
      ...registrationBillables.filter((item) => !existingKeys.has(item.sourceKey)).map(invoiceLineFromBillable),
    ];
    const nextPayments = selectedInvoicePayments(nextLines, billables);
    return normalizeInvoice({
      ...invoice,
      contactId: contact.id,
      contactKind: kind,
      status: "draft",
      lines: nextLines,
      paymentsSnapshot: nextPayments,
      totals: invoiceTotalsFromLines(nextLines, nextPayments),
      updatedAt: new Date().toISOString(),
    });
  }

  // Enchaînement « Imprimer la facture » depuis l'inscription : crée/récupère la facture puis l'émet
  // (ou réutilise l'existante) et l'imprime. Réutilise validateDraftInvoiceForOutput + printInvoice.
  async function printRegistrationInvoice(ref = {}) {
    const invoice = ensureDraftInvoiceForRegistration(asText(ref.stageId), asText(ref.registrationId));
    if (!invoice) return;
    const printable = await validateDraftInvoiceForOutput(invoice);
    if (printable) printInvoice(printable);
  }

  // Réparation unique (idempotente) des factures créées AVANT le correctif boutique : une commande
  // boutique avec remise dont la facture liée ne contient pas la ligne « Remise commande » -> total et
  // reste dû faux. On n'agit que sur la signature CERTAINE (le paiement reflète le net, pas de
  // sur-paiement) ; les cas ambigus (sur-paiement -> remise peut-être non appliquée) sont laissés tels
  // quels. Aucune création de facture, aucun changement de numéro/client/paiement : on ajoute seulement
  // la ligne de remise manquante, on recalcule les totaux via les fonctions existantes, et on journalise.
  function repairShopOrderDiscountInvoices() {
    if (!state || !Array.isArray(state.invoices) || !Array.isArray(state.shopOrders)) return 0;
    const orderById = new Map(state.shopOrders.map((order) => [order.id, order]));
    let repaired = 0;
    state.invoices.forEach((invoice) => {
      if (!invoice || invoice.status === "cancelled") return;
      const orderIds = new Set((invoice.lines || []).map((line) => {
        const match = asText(line.sourceKey).match(/^boutique:([^:]+):/);
        return match ? match[1] : null;
      }).filter(Boolean));
      orderIds.forEach((orderId) => {
        const order = orderById.get(orderId);
        const discount = order ? asNumber(order.discount) : 0;
        if (!order || discount <= 0) return;
        const discountKey = `boutique-discount:${orderId}`;
        const currentLines = invoice.lines || [];
        if (currentLines.some((line) => asText(line.sourceKey) === discountKey)) return; // déjà cohérent
        const grossTotal = currentLines.reduce((sum, line) => sum + asNumber(line.total ?? (asNumber(line.quantity || 1) * asNumber(line.unitPrice))), 0);
        const netTotal = grossTotal - discount;
        const paidRaw = (invoice.paymentsSnapshot || []).reduce((sum, payment) => sum + asNumber(payment.amount), 0);
        if (paidRaw > netTotal + 0.005) return; // ambigu : le client a payé plus que le net -> on ne touche pas
        invoice.lines = [...currentLines, normalizeInvoiceLine({
          sourceType: "frais",
          sourceId: orderId,
          sourceKey: discountKey,
          label: "Remise commande",
          description: "Déduction",
          quantity: 1,
          unitPrice: -discount,
          vatRate: effectiveDefaultVatRate(),
        })];
        invoice.totals = invoiceTotalsFromLines(invoice.lines, invoice.paymentsSnapshot || []);
        logActivity(`Correction facture ${invoice.number || "(brouillon)"} : ajout de la remise commande manquante (${money(-discount)}) suite au correctif boutique.`);
        repaired++;
      });
    });
    if (repaired > 0) {
      try { saveCurrentClubPayload({ reloadActive: false }); } catch { /* persistance silencieuse */ }
    }
    return repaired;
  }

  function showOrderInvoiceFollowUp(orderId = "") {
    const order = state.shopOrders.find((row) => row.id === orderId);
    if (!order) return;
    const calc = calcOrder(order);
    const client = [order.lastName, order.firstName].filter(Boolean).join(" ") || "Client sans nom";
    const invoice = invoiceForShopOrder(order.id);
    showInfoDialog("Commande enregistrée", `<div class="dialog-section">
      <h3>${esc(client)}</h3>
      <div class="tariff-summary-grid compact">
        <div><span>Total</span><strong>${money(calc.total)}</strong></div>
        <div><span>Réglé</span><strong>${money(calc.paid)}</strong></div>
        <div><span>Reste dû</span><strong>${money(calc.restDue)}</strong></div>
      </div>
      <p class="muted">${invoice ? "Une facture existe déjà pour cette commande." : "Un brouillon de facture peut être créé automatiquement avec les articles de cette commande."}</p>
      <div class="inline-actions">
        <button type="button" data-action="open-order-invoice" data-id="${esc(order.id)}">${invoice ? "Ouvrir la facture" : "Créer / éditer la facture"}</button>
        <button type="button" data-action="print-order-invoice" data-id="${esc(order.id)}">Imprimer la facture</button>
        <button type="button" data-action="export-order-invoice-pdf" data-id="${esc(order.id)}">PDF facture</button>
      </div>
    </div>`);
  }

  function openContactDialogFromLink(contactLink) {
    const link = parseContactLink(contactLink);
    if (dialog.open) dialog.close();
    if (link.kind === "member") {
      const contact = state.contacts.members.find((row) => row.id === link.contactId);
      if (contact) return openContactDialog("members", contact);
    }
    if (link.kind === "prospect") {
      const contact = state.contacts.prospects.find((row) => row.id === link.contactId);
      if (contact) return openContactDialog("prospects", contact);
    }
    alert("Fiche contact introuvable.");
  }

  // Ouvre un module (disciplines / boutique / stages) d'un contact à partir de son lien : utilisé par
  // le follow-up de showDialog après sauvegarde d'un nouveau contact. Réutilise openContactModule en lui
  // passant une source factice (il ne lit que dataset.contactLink et dataset.module).
  function openContactModuleFromLink(contactLink, module) {
    openContactModule({ dataset: { contactLink, module } });
  }

  function parseContactLink(value) {
    const [kind, contactId] = asText(value).split(":");
    if ((kind === "member" || kind === "prospect") && contactId) return { kind, contactId };
    return { kind: "", contactId: "" };
  }

  function contactByLink(value) {
    const link = parseContactLink(value);
    if (link.kind === "member") return state.contacts.members.find((contact) => contact.id === link.contactId) || null;
    if (link.kind === "prospect") return state.contacts.prospects.find((contact) => contact.id === link.contactId) || null;
    return null;
  }

  function contactSearchText(contact = {}) {
    return [contact.lastName, contact.firstName].filter(Boolean).join(" ").trim();
  }

  function contactRecordMatches(contact = {}, row = {}) {
    if (!contact || !row) return false;
    if (contact.id && row.contactId === contact.id) return true;
    if (contact.id && row.prospectContactId === contact.id) return true;
    return personKey(contact) === personKey(row);
  }

  function firstStageIdForContact(contact = {}) {
    for (const stage of state.tariffs.stages) {
      const rows = state.stageRegistrations[stage.id] || [];
      if (rows.some((row) => contactRecordMatches(contact, row))) return stage.id;
    }
    return ui.stageId;
  }

  function contactModuleEntries(contact = {}, module = "") {
    if (module === "disciplines") {
      return state.memberships
        .filter((row) => contactRecordMatches(contact, row))
        .map((row) => ({ row, calc: calcMembership(row) }));
    }
    // Lot 2 Modules désactivables — fonction de LECTURE : plus de garde isModuleEnabled ici.
    // Un module désactivé (forcément sans donnée active depuis le lot 1) doit garder son
    // historique visible sur la fiche contact, avec des totaux exacts. Les points de
    // CRÉATION et la facturation (billableItemsForContact) gardent leurs propres gardes.
    if (module === "boutique") {
      return state.shopOrders
        .filter((row) => contactRecordMatches(contact, row))
        .map((row) => ({ row, calc: calcOrder(row) }));
    }
    if (module === "stages") {
      return state.tariffs.stages.flatMap((stage) => (state.stageRegistrations[stage.id] || [])
        .filter((row) => contactRecordMatches(contact, row))
        .map((row) => ({ row, stageId: stage.id, calc: calcRegistration(row) })));
    }
    return [];
  }

  function contactInvoiceKind(kind) {
    return kind === "prospects" || kind === "prospect" ? "prospects" : "members";
  }

  function invoiceContact(kind, contactId) {
    return state.contacts[contactInvoiceKind(kind)]?.find((contact) => contact.id === contactId) || null;
  }

  function invoiceStatusLabel(invoice = {}) {
    const status = invoice.status || "draft";
    if (status === "draft") return "Brouillon";
    if (status === "issued") return "Émise";
    if (status === "paid") return "Payée";
    if (status === "partial") return "Partiellement payée";
    if (status === "cancelled") return "Annulée";
    return status;
  }

  function computedInvoiceStatus(invoice = {}) {
    if (invoice.status === "draft" || invoice.status === "cancelled") return invoice.status;
    const totals = invoiceTotalsFromLines(invoice.lines || [], invoice.paymentsSnapshot || []);
    if (asNumber(totals.total) > 0 && asNumber(totals.restDue) <= 0.005) return "paid";
    if (asNumber(totals.paid) > 0) return "partial";
    return "issued";
  }

  // Facture « figée » = émise (ou au-delà : partiellement/totalement payée), par opposition au
  // brouillon (modifiable) et à l'annulée. Une facture figée est un snapshot : son montant n'est
  // PAS recalculé si l'inscription/le tarif change ensuite (comportement volontaire de facturation).
  function invoiceIsFrozen(invoice = {}) {
    const status = computedInvoiceStatus(invoice);
    return status !== "draft" && status !== "cancelled";
  }

  // Lot 3b — Retard = ALERTE dérivée, jamais un statut principal. Une facture est « en retard »
  // si elle a un reste dû ET qu'au moins une échéance de paiement planifiée est dépassée
  // (réutilise paymentIsLate). Une facture payée / annulée / brouillon n'est jamais en retard.
  function invoiceIsLate(invoice = {}) {
    const status = computedInvoiceStatus(invoice);
    if (status === "draft" || status === "cancelled" || status === "paid") return false;
    const totals = invoiceTotalsFromLines(invoice.lines || [], invoice.paymentsSnapshot || []);
    if (asNumber(totals.restDue) <= 0.005) return false;
    return (invoice.paymentsSnapshot || []).some((payment) => paymentIsLate(payment));
  }

  // Lot 3a — Source unique de vérité des actions autorisées selon l'état de la facture.
  // Toutes les zones (éditeur, listes, boutons paiement/impression) doivent s'y référer
  // plutôt que de re-décider chacune de leur côté.
  function invoiceAllowedActions(invoice = {}) {
    const status = computedInvoiceStatus(invoice);
    const isDraft = status === "draft";
    const isCancelled = status === "cancelled";
    const totals = invoiceTotalsFromLines(invoice.lines || [], invoice.paymentsSnapshot || []);
    const hasDue = asNumber(totals.restDue) > 0.005;
    return {
      editLines: isDraft,                              // ajouter / modifier / supprimer des lignes
      emit: isDraft,                                   // émettre / valider
      addPayment: !isDraft && !isCancelled && hasDue,  // règlement seulement si reste dû
      settled: !isDraft && !isCancelled && !hasDue,    // soldée -> mention « Facture soldée »
      print: !isDraft,                                 // imprimer
      pdf: !isDraft,                                   // PDF
      open: true,                                      // toujours ouvrable / consultable
    };
  }

  function invoiceStatusPill(invoice = {}) {
    const status = computedInvoiceStatus(invoice);
    const label = invoiceStatusLabel({ ...invoice, status });
    const frozenTitle = invoiceIsFrozen(invoice) ? ` title="Facture émise : montant figé à l'émission"` : "";
    const lateBadge = invoiceIsLate(invoice) ? `<span class="invoice-status late" title="Au moins une échéance de paiement est dépassée">En retard</span>` : "";
    return `<span class="invoice-status ${esc(status)}"${frozenTitle}>${esc(label)}</span>${lateBadge}`;
  }

  function billableItem(source) {
    const quantity = Math.max(0, asNumber(source.quantity || 1));
    const unitPrice = asNumber(source.unitPrice);
    return {
      id: asText(source.id || id("billable")),
      sourceType: asText(source.sourceType),
      sourceId: asText(source.sourceId),
      sourceKey: asText(source.sourceKey),
      label: asText(source.label),
      description: asText(source.description),
      quantity,
      unitPrice,
      vatRate: isClubVatExempt() ? 0 : Math.max(0, asNumber(source.vatRate ?? effectiveDefaultVatRate())),
      total: source.total === undefined ? quantity * unitPrice : asNumber(source.total),
      payments: normalizePayments(source.payments || []),
      paymentGroupKey: asText(source.paymentGroupKey || source.sourceKey),
    };
  }

  function invoiceLineFromBillable(item) {
    return normalizeInvoiceLine({
      sourceType: item.sourceType,
      sourceId: item.sourceId,
      sourceKey: item.sourceKey,
      label: item.label,
      description: item.description,
      quantity: item.quantity,
      unitPrice: item.unitPrice,
      vatRate: item.vatRate,
      total: item.total,
    });
  }

  function invoiceSourceTypeLabel(type) {
    return {
      inscription: "Inscription",
      discipline: "Discipline",
      cotisation: "Cotisation",
      licence: "Licence",
      assurance: "Assurance",
      stage: "Stage",
      boutique: "Boutique",
      frais: "Frais",
      custom: "Libre",
    }[type] || type || "Ligne";
  }

  function billedSourceKeys(excludeInvoiceId = "") {
    const keys = new Set();
    (state.invoices || []).forEach((invoice) => {
      if (invoice.id === excludeInvoiceId || invoice.status === "draft" || invoice.status === "cancelled") return;
      (invoice.lines || []).forEach((line) => {
        if (line.sourceKey && line.sourceType !== "custom") keys.add(line.sourceKey);
      });
    });
    return keys;
  }

  function billableItemsForContact(contact = {}, kind = "members") {
    const rows = [];
    const contactKind = contactInvoiceKind(kind);
    const tax = effectiveDefaultVatRate();
    const memberships = state.memberships.filter((row) => contactRecordMatches(contact, row));
    memberships.forEach((row) => {
      const values = membershipTariffValues(row);
      const discipline = row.discipline || "discipline";
      const license = Math.max(0, asNumber(values.license));
      const cotisation = Math.max(0, asNumber(values.grossTotal));
      const paymentGroupKey = `membership:${row.id}`;
      if (cotisation > 0) {
        rows.push(billableItem({
          sourceType: "cotisation",
          sourceId: row.id,
          sourceKey: `cotisation:${row.id}`,
          label: `Cotisation ${discipline}`,
          description: personLabel(row),
          unitPrice: cotisation,
          vatRate: membershipDefaultTaxRate(row),
          payments: row.payments,
          paymentGroupKey,
        }));
      }
      if (license > 0) {
        rows.push(billableItem({
          sourceType: "licence",
          sourceId: row.id,
          sourceKey: `licence:${row.id}`,
          label: `Licence fédérale ${discipline}`,
          description: personLabel(row),
          unitPrice: license,
          vatRate: membershipDefaultTaxRate(row),
          payments: row.payments,
          paymentGroupKey,
        }));
      }
      if (asNumber(values.insurancePrice) > 0) {
        rows.push(billableItem({
          sourceType: "assurance",
          sourceId: row.id,
          sourceKey: `assurance:${row.id}`,
          label: `Assurance ${row.insuranceLabel || row.insuranceChoice || discipline}`,
          description: discipline,
          unitPrice: asNumber(values.insurancePrice),
          vatRate: membershipDefaultTaxRate(row),
          payments: row.payments,
          paymentGroupKey,
        }));
      }
      if (asNumber(values.discount) > 0) {
        rows.push(billableItem({
          sourceType: "frais",
          sourceId: row.id,
          sourceKey: `discount:${row.id}`,
          label: `Remise ${discipline}`,
          description: "Déduction",
          unitPrice: -asNumber(values.discount),
          vatRate: tax,
          payments: row.payments,
          paymentGroupKey,
        }));
      }
    });
    // Lot 2D — point bloquant : le contenu FACTURABLE d'un contact (calcul des factures) inclut TOUJOURS
    // ses inscriptions existantes. Cette lecture historique ne dépend ni de settings.display.showStages
    // ni de hasFeature : une créance de stage déjà enregistrée reste facturable et soldable via les
    // chemins financiers génériques (facture de contact, avoir, paiement). La CRÉATION de NOUVELLES
    // données Stages, elle, reste gardée par hasFeature (ensureFeatureEnabledForMutation) aux mutations.
    {
      state.tariffs.stages.forEach((stage) => {
        (state.stageRegistrations[stage.id] || []).filter((row) => contactRecordMatches(contact, row)).forEach((row) => {
          const event = calcStageSegment(row.event || {});
          if (event.subtotal > 0) {
            rows.push(billableItem({
              sourceType: "stage",
              sourceId: row.id,
              sourceKey: `stage:${stage.id}:${row.id}:event`,
              label: stage.name || "Stage",
              description: "Inscription stage",
              unitPrice: event.subtotal,
              vatRate: stageDefaultTaxRate(stage),
              payments: row.event?.payments,
              paymentGroupKey: `stage:${stage.id}:${row.id}:event`,
            }));
          }
          const lodging = calcStageSegment(row.lodging || {});
          if (lodging.subtotal > 0) {
            rows.push(billableItem({
              sourceType: "frais",
              sourceId: row.id,
              sourceKey: `stage:${stage.id}:${row.id}:lodging`,
              label: row.lodging?.name || stage.lodgingName || "Hébergement",
              description: stage.name || "Stage",
              unitPrice: lodging.subtotal,
              vatRate: lodgingDefaultTaxRate(stage),
              payments: row.lodging?.payments,
              paymentGroupKey: `stage:${stage.id}:${row.id}:lodging`,
            }));
          }
        });
      });
    }
    // Lot 2B — point bloquant 1 : le contenu FACTURABLE d'un contact (calcul des factures) inclut
    // toujours ses commandes existantes. Cette lecture historique ne dépend pas de
    // settings.display.showBoutique ; la CRÉATION de nouvelles données Boutique, elle, reste gardée
    // par hasFeature (ensureFeatureEnabledForMutation) aux points de mutation.
    {
      state.shopOrders.filter((row) => contactRecordMatches(contact, row)).forEach((order) => {
        orderItemDetails(order).forEach((item, index) => {
          rows.push(billableItem({
            sourceType: "boutique",
            sourceId: order.id,
            sourceKey: `boutique:${order.id}:${item.article.id || item.articleId || index}`,
            label: item.article.name || "Article boutique",
            description: item.sizesText ? `Taille(s) ${item.sizesText}` : "Boutique",
            quantity: item.quantity || 1,
            unitPrice: item.unitPrice,
            vatRate: tariffTaxRate(item.article || {}),
            payments: order.payments,
            paymentGroupKey: `order:${order.id}`,
          }));
        });
        if (asNumber(order.discount) > 0) {
          rows.push(billableItem({
            sourceType: "frais",
            sourceId: order.id,
            sourceKey: `boutique-discount:${order.id}`,
            label: "Remise commande",
            description: "Déduction",
            unitPrice: -asNumber(order.discount),
            vatRate: tax,
            payments: order.payments,
            paymentGroupKey: `order:${order.id}`,
          }));
        }
      });
    }
    return rows;
  }

  function selectedInvoicePayments(lines = [], billables = []) {
    const billableByKey = new Map(billables.map((item) => [item.sourceKey, item]));
    const usedGroups = new Set();
    const payments = [];
    lines.forEach((line) => {
      const item = billableByKey.get(line.sourceKey);
      if (!item || usedGroups.has(item.paymentGroupKey)) return;
      usedGroups.add(item.paymentGroupKey);
      payments.push(...normalizePayments(item.payments || []));
    });
    return payments.filter((payment) => asNumber(payment.amount) || asText(payment.date) || asText(payment.state) || asText(payment.check) || asText(payment.checkNumber));
  }

  function invoiceNumberPrefix() {
    const club = activeClub();
    return asText(club?.documents?.prefix || activeClub()?.shortName || "MGC").toUpperCase().replace(/[^A-Z0-9]/g, "").slice(0, 8) || "MGC";
  }

  function nextInvoiceNumber() {
    const prefix = invoiceNumberPrefix();
    const year = new Date().getFullYear();
    const needle = `${prefix}-${year}-`;
    const max = (state.invoices || []).reduce((value, invoice) => {
      if (!asText(invoice.number).startsWith(needle)) return value;
      const number = Number(asText(invoice.number).slice(needle.length));
      return Number.isFinite(number) ? Math.max(value, number) : value;
    }, 0);
    return `${needle}${String(max + 1).padStart(4, "0")}`;
  }

  function clubInvoiceSnapshot() {
    const club = activeClub();
    return club ? clone(club) : {};
  }

  function contactInvoiceSnapshot(contact = {}, kind = "members") {
    const snapshot = {
      id: contact.id || "",
      kind: contactInvoiceKind(kind),
      lastName: contact.lastName || "",
      firstName: contact.firstName || "",
      email: contact.email || "",
      phone: contact.mobile || contact.phone || "",
      address: contact.address || "",
      postalCode: contact.postalCode || "",
      city: contact.city || "",
    };
    // Lot 6c — Mineur avec responsable légal : on FIGE le destinataire de facturation (additif).
    // Les anciennes factures sans billedTo -> fallback d'affichage = le contact lui-même.
    if (contactInvoiceKind(kind) === "members" && memberCategory(contact) === "Enfant" && asText(contact.legalGuardianName)) {
      snapshot.billedTo = {
        name: asText(contact.legalGuardianName),
        email: asText(contact.legalGuardianEmail),
        phone: asText(contact.legalGuardianPhone),
      };
    }
    return snapshot;
  }

  function draftInvoiceForContact(contact = {}, kind = "members") {
    return (state.invoices || []).find((invoice) => invoice.status === "draft" && invoice.contactId === contact.id && invoice.contactKind === contactInvoiceKind(kind)) || null;
  }

  function upsertInvoice(invoice) {
    stampRecordClubId(invoice);
    const index = state.invoices.findIndex((item) => item.id === invoice.id);
    if (index >= 0) state.invoices[index] = normalizeInvoice(invoice);
    else state.invoices.push(normalizeInvoice(invoice));
  }

  function confirmInvoiceIssue() {
    return requestDialogConfirmation(
      "Émettre la facture",
      "Voulez-vous vraiment émettre cette facture ?\n\nAprès émission, elle recevra un numéro officiel, sera verrouillée et ne pourra plus être modifiée librement.",
      "Émettre la facture",
    );
  }

  async function issueDraftInvoice(invoice = {}, options = {}) {
    if (!invoice?.id || invoice.status !== "draft") return invoice;
    if (!(invoice.lines || []).length) {
      alert("Ajoute au moins une ligne à la facture avant de la valider.");
      return null;
    }
    if (!options.skipIssueConfirmation && !(await confirmInvoiceIssue())) return null;
    const now = new Date().toISOString();
    const next = normalizeInvoice({
      ...invoice,
      clubId: invoice.clubId || activeClubId(),
      number: invoice.number || nextInvoiceNumber(),
      status: "issued",
      issuedAt: invoice.issuedAt || now,
      updatedAt: now,
      clubSnapshot: invoice.clubSnapshot && Object.keys(invoice.clubSnapshot).length ? invoice.clubSnapshot : clubInvoiceSnapshot(),
      contactSnapshot: invoice.contactSnapshot && Object.keys(invoice.contactSnapshot).length ? invoice.contactSnapshot : contactInvoiceSnapshot(invoiceContact(invoice.contactKind, invoice.contactId), invoice.contactKind),
      totals: invoiceTotalsFromLines(invoice.lines || [], invoice.paymentsSnapshot || []),
    });
    upsertInvoice(next);
    audit.invoiceIssued(next, invoiceContact(next.contactKind, next.contactId));
    return next;
  }

  function contactInvoices(contact = {}, kind = "members") {
    const contactKind = contactInvoiceKind(kind);
    return (state.invoices || []).filter((invoice) => invoice.contactId === contact.id && invoice.contactKind === contactKind);
  }

  function invoiceIsUnpaid(invoice = {}) {
    const totals = invoiceTotalsFromLines(invoice.lines || [], invoice.paymentsSnapshot || []);
    return invoice.status !== "draft" && invoice.status !== "cancelled" && asNumber(totals.restDue) > 0.005;
  }

  function contactModuleSummary(contact = {}, module = "") {
    const rows = contactModuleEntries(contact, module);
    const restDue = rows.reduce((sum, item) => sum + Math.max(0, asNumber(item.calc.restDue)), 0);
    return {
      count: rows.length,
      restDue,
      tone: contactModuleTone(rows, restDue),
    };
  }

  function moduleEntryPayments(entry = {}) {
    return [
      ...(entry.row?.payments || []),
      ...(entry.row?.event?.payments || []),
      ...(entry.row?.lodging?.payments || []),
      ...(entry.row?.paymentsSnapshot || []),
    ];
  }

  function contactModuleTone(rows = [], restDue = 0) {
    if (!rows.length) return "empty";
    if (asNumber(restDue) <= 0) return "paid";
    const payments = rows.flatMap(moduleEntryPayments);
    if (payments.some(paymentIsLate)) return "due";
    if (payments.some(paymentIsPendingOrPlanned)) return "pending";
    return "due";
  }

  function firstContactModuleEntry(contact = {}, module = "") {
    const rows = contactModuleEntries(contact, module);
    return rows.find((item) => asNumber(item.calc.restDue) > 0) || rows[0] || null;
  }

  function contactModuleButton(contactLink, contact, module, label) {
    const summary = contactModuleSummary(contact, module);
    const tone = `is-${summary.tone || "empty"}`;
    const title = summary.count
      ? `${label} : ${summary.restDue > 0 ? `reste dû ${money(summary.restDue)}` : "tout est réglé"}`
      : `${label} : aucune ligne`;
    return `<button type="button" class="${tone}" title="${esc(title)}" data-action="open-contact-module" data-module="${esc(module)}" data-contact-link="${esc(contactLink)}">${esc(label)}</button>`;
  }

  // Lot correctif — cohérence modules désactivés / bas de fiche contact : chaque bouton suit
  // désormais le MÊME prédicat que la navigation (isViewVisible), au lieu d'un mélange où seuls
  // Boutique/Stages étaient gardés (via isModuleEnabled) et Facture/E-mail/Disciplines jamais.
  // isViewVisible() combine déjà visibilité menu (mode simple/avancé/personnalisé) ET drapeau
  // fonctionnel (Stages/Boutique) : aucune nouvelle règle de désactivation créée, on réutilise
  // seulement le prédicat existant. Aucune donnée supprimée : un contact garde son historique
  // (inscriptions, commandes, stages passés) même si le module correspondant est ensuite masqué ;
  // seule l'action de création/raccourci disparaît du bas de fiche.
  function contactModuleLinks(kind, row = {}) {
    const contactLinkKind = kind === "members" ? "member" : "prospect";
    // Création : le contact n'a pas encore d'id. On affiche quand même les actions ; data-contact-new
    // déclenche « valider + enregistrer le contact, puis ouvrir l'action » via le follow-up de showDialog
    // (jamais de navigation avec un contact non sauvegardé). « Envoyer un mail » reste désactivé tant que
    // le contact n'est pas enregistré (solution la plus simple et la moins risquée).
    if (!row.id) {
      const newModuleBtn = (module, label) => `<button type="button" class="is-empty" data-action="open-contact-module" data-module="${module}" data-contact-new="1" title="${esc(label)} — le contact sera enregistré d'abord">${esc(label)}</button>`;
      return `<div class="contact-module-links" aria-label="Accès direct du contact" data-tour="contact-modules">
        ${isViewVisible("newsletter") ? `<button type="button" class="is-empty" disabled title="Enregistre d'abord le contact pour pouvoir lui envoyer un e-mail">Envoyer un mail</button>` : ""}
        ${isViewVisible("invoices") ? `<button type="button" class="is-paid" data-action="open-contact-invoice" data-contact-new="1" data-tour="invoice-create" title="Créer une facture — le contact sera enregistré d'abord">Créer / éditer une facture</button>` : ""}
        ${isViewVisible("boutique") ? newModuleBtn("boutique", "Boutique") : ""}
        ${kind === "members" && isViewVisible("disciplines") ? newModuleBtn("disciplines", "Disciplines") : ""}
        ${isViewVisible("stages") ? newModuleBtn("stages", "Stages") : ""}
      </div>`;
    }
    const contactLink = `${contactLinkKind}:${row.id}`;
    const memberLinks = kind === "members" && isViewVisible("disciplines") ? `
      ${contactModuleButton(contactLink, row, "disciplines", "Disciplines")}
    ` : "";
    const stageLink = isViewVisible("stages") ? contactModuleButton(contactLink, row, "stages", "Stages") : "";
    return `<div class="contact-module-links" aria-label="Accès direct du contact" data-tour="contact-modules">
      ${isViewVisible("newsletter") ? `<button type="button" class="${asText(row.email) ? "is-paid" : "is-empty"}" title="${asText(row.email) ? "Préparer un e-mail au contact" : "Adresse e-mail manquante"}" data-action="send-contact-email" data-contact-link="${esc(contactLink)}">Envoyer un mail</button>` : ""}
      ${isViewVisible("invoices") ? `<button type="button" class="is-paid" title="Créer ou éditer une facture centralisée pour ce contact" data-action="open-contact-invoice" data-contact-link="${esc(contactLink)}" data-tour="invoice-create">Créer / éditer une facture</button>` : ""}
      ${isViewVisible("boutique") ? contactModuleButton(contactLink, row, "boutique", "Boutique") : ""}
      ${memberLinks}
      ${stageLink}
    </div>`;
  }

  // Une fiche contact peut être le dialogue PRIMAIRE (ouverte directement depuis Contacts) ou un
  // dialogue EMPILÉ (ouverte depuis "Inscrits à la séance"/planning, via dialogForNewWindow qui crée
  // un ".stacked-dialog" par-dessus). Ne rafraîchir que `dialog` (primaire) laissait une fiche
  // empilée périmée après ajout/retrait de discipline : la donnée était bien enregistrée
  // immédiatement, mais son affichage ne se mettait à jour qu'en fermant/rouvrant la fiche (d'où
  // l'impression qu'il fallait cliquer sur "Enregistrer" pour valider). On rafraîchit maintenant
  // CHAQUE dialogue ouvert (primaire + tous les stacked) qui porte le marqueur fiche contact.
  function refreshOpenContactDialog() {
    const candidates = [dialog, ...document.querySelectorAll(".stacked-dialog")].filter((dlg) => dlg && dlg.open);
    candidates.forEach((dlg) => {
      const marker = dlg.querySelector("[data-contact-dialog-kind][data-contact-dialog-id]");
      if (!marker) return;
      const kind = marker.dataset.contactDialogKind;
      const contact = state.contacts[kind]?.find((row) => row.id === marker.dataset.contactDialogId);
      if (!contact) return;
      const recap = dlg.querySelector(".contact-recap");
      const nextRecap = contactActivitySummary(kind, contact);
      if (recap && nextRecap) {
        recap.outerHTML = nextRecap;
      } else if (!recap && nextRecap) {
        const actions = dlg.querySelector(".contact-dialog-actions");
        actions?.insertAdjacentHTML("beforebegin", nextRecap);
      }
      const footer = dlg.querySelector(".dialog-footer-left");
      if (footer) footer.innerHTML = contactModuleLinks(kind, contact);
      applyClickableTooltips(dlg);
    });
  }

  function refreshOpenInvoiceEditor() {
    const editor = [...document.querySelectorAll("[data-invoice-editor-id]")].pop();
    if (!editor) return;
    const invoice = normalizeInvoice(state.invoices.find((inv) => inv.id === editor.dataset.invoiceEditorId) || {});
    if (!invoice.id) return;
    const host = editor.closest("dialog") || editor.parentElement;
    // Lot Responsable légal — l'en-tête (nom/adresse, alerte "Responsable légal non renseigné",
    // bouton de correction) ne se rafraîchissait pas ici : si le contact est corrigé pendant que
    // la facture reste ouverte (ou minimisée), l'alerte pouvait rester affichée à tort jusqu'à
    // fermeture/réouverture complète. Même résolution de contact que openInvoiceEditor().
    const headWrap = host.querySelector("[data-invoice-editor-head]");
    if (headWrap) headWrap.innerHTML = invoiceBillingHeadHtml(invoice, invoiceDisplayContact(invoice));
    const summaryWrap = host.querySelector("[data-invoice-editor-summary]");
    if (summaryWrap) summaryWrap.innerHTML = invoiceEditorSummary(invoice, invoice.lines, invoice.paymentsSnapshot);
    const payWrap = host.querySelector("[data-invoice-editor-payments]");
    if (payWrap) payWrap.innerHTML = `<h3>Paiements et échéances</h3>${invoicePaymentsHtml(invoice.paymentsSnapshot)}${invoice.status !== "draft" ? invoicePaymentActionHtml(invoice) : ""}`;
    // Lot 5d-1 : rafraîchir le bloc « Avoirs liés » en place (avoir créé visible immédiatement).
    const cnWrap = host.querySelector("[data-invoice-credit-notes]");
    if (cnWrap) cnWrap.outerHTML = invoiceLinkedCreditNotesHtml(invoice);
    applyClickableTooltips(host);
  }

  // Lot 6a — Diagnostic mineur / responsable légal sur la fiche contact (AFFICHAGE SEUL).
  // Réutilise memberCategory (âge si date de naissance, sinon catégorie « Enfant »). Ne touche
  // ni aux factures, ni à contactInvoiceSnapshot, ni aux calculs, ni aux données.
  function contactMinorGuardianHtml(contact = {}, kind = "members") {
    if (kind !== "members") return "";                 // responsable légal = champs adhérent
    if (memberCategory(contact) !== "Enfant") return ""; // adulte / âge inconnu non-enfant -> rien
    const name = asText(contact.legalGuardianName);
    const coords = [asText(contact.legalGuardianPhone), asText(contact.legalGuardianEmail)].filter(Boolean).map(esc).join(" · ");
    const auth = contact.parentalAuthorization ? ` <span class="muted">· Autorisation parentale renseignée</span>` : "";
    const body = name
      ? `<div><strong>Responsable légal :</strong> ${esc(name)}${coords ? ` <span class="muted">(${coords})</span>` : ""}${auth}</div>`
      : `<div class="muted"><strong>⚠️ Responsable légal non renseigné</strong></div>`;
    return `<section class="contact-recap-section">
      <h4><span class="invoice-status">Mineur</span></h4>
      ${body}
    </section>`;
  }

  function contactActivitySummary(kind, contact = {}) {
    if (!contact.id && !asText(contact.lastName) && !asText(contact.firstName)) return "";
    const memberships = contactModuleEntries(contact, "disciplines");
    const orders = contactModuleEntries(contact, "boutique");
    const registrations = contactModuleEntries(contact, "stages");
    const all = [...memberships, ...orders, ...registrations];
    const totals = all.reduce((acc, item) => {
      acc.total += asNumber(item.calc.total);
      acc.paid += asNumber(item.calc.paid);
      acc.due += Math.max(0, asNumber(item.calc.restDue));
      return acc;
    }, { total: 0, paid: 0, due: 0 });
    const invoiceRows = contactInvoices(contact, kind);
    const invoiceTotals = invoiceRows.reduce((acc, invoice) => {
      const totalsValue = invoiceTotalsFromLines(invoice.lines || [], invoice.paymentsSnapshot || []);
      acc.total += asNumber(totalsValue.total);
      acc.paid += asNumber(totalsValue.paid);
      acc.due += Math.max(0, asNumber(totalsValue.restDue));
      return acc;
    }, { total: 0, paid: 0, due: 0 });
    const empty = !all.length ? `<div class="contact-recap-empty">Aucune activité enregistrée pour ce contact.</div>` : "";
    return `<div class="dialog-section contact-recap" data-tour="contact-recap">
      <div class="contact-recap-head">
        <div>
          <h3>Récapitulatif du contact</h3>
          <p>Lecture seule : activités actives et paiements liés à cette personne.</p>
        </div>
        <div class="contact-recap-total ${totals.due > 0 ? "has-due" : ""}">
          <span>Reste dû</span>
          <strong>${money(totals.due)}</strong>
        </div>
      </div>
      <div class="contact-recap-kpis">
        <div><span>Total attendu</span><strong>${money(totals.total)}</strong></div>
        <div><span>Réglé</span><strong>${money(totals.paid)}</strong></div>
        <div><span>Activités</span><strong>${intValue(all.length)}</strong></div>
      </div>
      ${empty}
      ${contactMinorGuardianHtml(contact, kind)}
      ${kind === "members" && isViewVisible("disciplines")
        // Disciplines sort ici du mécanisme générique contactRecapSection (qui masque toute la
        // section, bouton d'ajout compris, dès que la liste est vide) : un adhérent sans discipline
        // doit quand même voir "+ Ajouter une discipline" et comprendre comment en ajouter une,
        // au lieu que la section disparaisse silencieusement (c'était la cause probable du "je ne
        // trouve pas où ajouter une discipline" remonté par Thierry).
        ? `<section class="contact-recap-section">
            <div class="dialog-mini-title"><h4>Disciplines</h4>${contact.id ? `<button type="button" data-action="add-contact-membership" data-contact-link="${esc(`member:${contact.id}`)}" title="Ajouter une nouvelle inscription discipline/groupe pour ce contact">+ Ajouter une discipline</button>` : ""}</div>
            ${memberships.length
              ? `<p class="muted">Un adhérent peut avoir plusieurs disciplines, tant que les horaires ne se chevauchent pas.</p><div class="contact-recap-list">${memberships.map(contactRecapMembership).join("")}</div>`
              : `<p class="contact-recap-empty">Aucune discipline enregistrée pour le moment.</p>`}
          </section>`
        : contactRecapSection("Disciplines", memberships, contactRecapMembership)}
      ${contactRecapSection("Boutique", orders, contactRecapOrder, (isModuleEnabled("boutique") && hasFeature("shop")) ? "" : "Module désactivé — historique conservé. Réactivez le module pour ajouter de nouvelles données.")}
      ${contactRecapSection("Stages", registrations, contactRecapRegistration, (isModuleEnabled("stages") && hasFeature("stages")) ? "" : "Module désactivé — historique conservé. Réactivez le module pour ajouter de nouvelles données.")}
      ${invoiceRows.length ? `<section class="contact-recap-section">
        <h4>Factures</h4>
        <div class="contact-recap-kpis">
          <div><span>Facturé</span><strong>${money(invoiceTotals.total)}</strong></div>
          <div><span>Payé</span><strong>${money(invoiceTotals.paid)}</strong></div>
          <div><span>Reste à payer</span><strong class="${invoiceTotals.due > 0 ? "due" : ""}">${money(invoiceTotals.due)}</strong></div>
        </div>
        <div class="contact-recap-list">${invoiceRows.map(contactRecapInvoice).join("")}</div>
      </section>` : ""}
      ${contactAvailableCreditNotesHtml(contact)}
    </div>`;
  }

  function contactRecapSection(title, entries, renderer, note = "", headerExtra = "") {
    if (!entries.length) return "";
    return `<section class="contact-recap-section">
      ${headerExtra ? `<div class="dialog-mini-title"><h4>${esc(title)}</h4>${headerExtra}</div>` : `<h4>${esc(title)}</h4>`}
      ${note ? `<p class="muted">${esc(note)}</p>` : ""}
      <div class="contact-recap-list">${entries.map(renderer).join("")}</div>
    </section>`;
  }

  function contactRecapStatus(calc = {}) {
    if (asNumber(calc.restDue) <= 0 && asNumber(calc.total) > 0) return statusPill("Payé");
    return statusPill(asNumber(calc.paid) > 0 ? "Partiel" : "Reste dû");
  }

  function contactRecapAmounts(calc = {}) {
    return `<div class="contact-recap-amounts">
      <span>Total <strong>${money(calc.total)}</strong></span>
      <span>Réglé <strong>${money(calc.paid)}</strong></span>
      <span class="${asNumber(calc.restDue) > 0 ? "due" : ""}">Reste <strong>${money(calc.restDue)}</strong></span>
    </div>`;
  }

  function contactRecapMembership(entry) {
    const row = entry.row;
    // Lot V1 Niveaux — "Niveau" reste une note libre sans automatisme (cf. audit
    // Niveaux/Groupes/Disciplines) : simple affichage si renseigné, rien sinon, propre à
    // cette inscription (pas une donnée globale du contact, une autre inscription du même
    // contact peut avoir un niveau différent ou vide).
    const subtitle = [
      asText(row.level) ? `Niveau : ${asText(row.level)}` : "",
      row.insuranceChoice ? `Assurance ${membershipInsurancePrice(row) ? money(membershipInsurancePrice(row)) : ""}` : "",
      row.medicalCertificate ? "Certificat OK" : "Certificat non renseigné",
    ].filter(Boolean).join(" · ");
    // Un contact peut avoir plusieurs inscriptions (memberships) : le groupe est affiché à côté
    // de la discipline pour que la fiche distingue clairement chaque inscription (ex. "Judo —
    // Judo enfants" vs "Self-défense — Self-défense ados"), sans quoi deux inscriptions à la
    // même discipline mais des groupes différents seraient indiscernables.
    const group = getGroupById(row.groupId);
    const titleText = [row.discipline || "Discipline non renseignée", group?.name || ""].filter(Boolean).join(" — ");
    // Bouton "Retirer" imbriqué dans la ligne cliquable (edit-membership) : le delegate de clic
    // résout via closest("[data-action]") en partant de l'élément cliqué, donc ce bouton intercepte
    // le clic avant qu'il n'atteigne l'article parent -> pas de double action, pas besoin de
    // stopPropagation. Réutilise tel quel l'action delete-membership déjà existante (confirmation,
    // undo, contact jamais supprimé) : aucune nouvelle logique de suppression créée.
    return `<article class="contact-recap-row clickable-card" data-action="edit-membership" data-id="${esc(row.id)}" title="Ouvrir cette inscription">
      <div class="contact-recap-main">
        <strong>${esc(titleText)}</strong>
        <span>${esc(subtitle || "Inscription discipline")}</span>
        <button type="button" class="contact-recap-remove-btn" data-action="delete-membership" data-id="${esc(row.id)}" title="Retirer cette discipline de la fiche">Retirer</button>
      </div>
      ${contactRecapStatus(entry.calc)}
      ${contactRecapAmounts(entry.calc)}
    </article>`;
  }

  function contactRecapOrder(entry) {
    const details = orderItemDetails(entry.row);
    const itemText = details.length
      ? details.map((item) => `${item.article.name || "Article"}${item.sizesText ? ` (${item.sizesText})` : ""} x${intValue(item.quantity)}`).join(" · ")
      : "Aucun article détaillé";
    return `<article class="contact-recap-row">
      <div class="contact-recap-main">
        <strong>Commande boutique</strong>
        <span>${esc(itemText)}</span>
      </div>
      ${statusPill(shopOrderStatus(entry.row, entry.calc))}
      ${contactRecapAmounts(entry.calc)}
    </article>`;
  }

  function contactRecapRegistration(entry) {
    const stage = stageById(entry.stageId);
    const event = calcStageSegment(entry.row.event || {});
    const lodging = calcStageSegment(entry.row.lodging || {});
    const parts = [
      event.subtotal ? `Stage ${money(event.subtotal)}` : "",
      lodging.subtotal ? `Hébergement ${money(lodging.subtotal)}` : "",
    ].filter(Boolean).join(" · ");
    return `<article class="contact-recap-row">
      <div class="contact-recap-main">
        <strong>${esc(stage.name || "Stage")}</strong>
        <span>${esc(parts || "Inscription stage")}</span>
      </div>
      ${contactRecapStatus(entry.calc)}
      ${contactRecapAmounts(entry.calc)}
    </article>`;
  }

  function contactRecapInvoice(invoice) {
    const totals = invoiceTotalsFromLines(invoice.lines || [], invoice.paymentsSnapshot || []);
    return `<article class="contact-recap-row clickable-card" data-action="open-invoice" data-id="${esc(invoice.id)}">
      <div class="contact-recap-main">
        <strong>${esc(invoice.number || "Brouillon de facture")}</strong>
        <span>${esc(dateDisplay(invoice.issuedAt || invoice.createdAt) || "")}</span>
      </div>
      ${invoiceStatusPill(invoice)}
      ${contactRecapAmounts(totals)}
    </article>`;
  }

  function invoiceBelongsToActiveClub(invoice = {}) {
    const clubId = activeClubId();
    return !clubId || !asText(invoice.clubId) || invoice.clubId === clubId;
  }

  function invoiceDisplayContact(invoice = {}) {
    return invoice.contactSnapshot || invoiceContact(invoice.contactKind, invoice.contactId) || {};
  }

  function invoiceDisplayTotals(invoice = {}) {
    return invoice.totals || invoiceTotalsFromLines(invoice.lines || [], invoice.paymentsSnapshot || []);
  }

  function invoiceMatchesFilter(invoice = {}) {
    if (ui.invoiceFilter === "all") return true;
    if (ui.invoiceFilter === "unpaid") return invoiceIsUnpaid(invoice);
    return invoice.status === ui.invoiceFilter || computedInvoiceStatus(invoice) === ui.invoiceFilter;
  }

  function invoiceSearchText(invoice = {}) {
    const contact = invoiceDisplayContact(invoice);
    const totals = invoiceDisplayTotals(invoice);
    const status = computedInvoiceStatus(invoice);
    const lines = invoice.lines || [];
    const payments = invoiceVisiblePayments(invoice.paymentsSnapshot || []);
    const values = [
      invoice.id,
      invoice.number,
      invoice.number || "Brouillon de facture",
      invoiceStatusLabel({ ...invoice, status }),
      status,
      dateDisplay(invoice.issuedAt || invoice.createdAt),
      invoice.issuedAt,
      invoice.createdAt,
      invoice.notes,
      contact.lastName,
      contact.firstName,
      personLabel(contact),
      contact.address,
      contact.address2,
      contact.postalCode,
      contact.city,
      contact.country,
      contact.email,
      contact.phone,
      contact.mobile,
      money(totals.total),
      money(totals.paid),
      money(totals.restDue),
      asNumber(totals.total),
      asNumber(totals.paid),
      asNumber(totals.restDue),
    ];
    lines.forEach((line) => {
      values.push(
        line.sourceType,
        invoiceSourceTypeLabel(line.sourceType),
        line.label,
        line.description,
        line.sourceId,
        line.sourceKey,
        money(line.unitPrice),
        money(line.total),
        asNumber(line.unitPrice),
        asNumber(line.total),
      );
    });
    payments.forEach((payment, index) => {
      values.push(
        invoicePaymentModeLabel(payment, index),
        paymentModeLabel(payment.check),
        payment.check,
        invoicePaymentCheckNumber(payment),
        invoiceDateLabel(payment.date),
        paymentStatus(payment),
        payment.state,
        money(payment.amount),
        asNumber(payment.amount),
      );
    });
    return normalizedPersonText(values.filter((value) => value !== undefined && value !== null).join(" "));
  }

  function invoiceMatchesSearch(invoice = {}, query = ui.invoiceSearch) {
    const needle = normalizedPersonText(query);
    if (!needle) return true;
    return invoiceSearchText(invoice).includes(needle);
  }

  function filteredInvoices() {
    return (state.invoices || [])
      .filter(invoiceBelongsToActiveClub)
      .filter(invoiceMatchesFilter)
      .filter((invoice) => invoiceMatchesSearch(invoice, ui.invoiceSearch))
      .sort((a, b) => asText(b.issuedAt || b.createdAt).localeCompare(asText(a.issuedAt || a.createdAt)));
  }

  function invoiceListTotals(invoices = []) {
    return invoices.reduce((acc, invoice) => {
      const invoiceTotals = invoiceDisplayTotals(invoice);
      acc.total += asNumber(invoiceTotals.total);
      acc.paid += asNumber(invoiceTotals.paid);
      acc.due += Math.max(0, asNumber(invoiceTotals.restDue));
      return acc;
    }, { total: 0, paid: 0, due: 0 });
  }

  function renderInvoices() {
    const invoices = filteredInvoices();
    const filters = [
      ["all", "Toutes"],
      ["draft", "Brouillons"],
      ["issued", "Émises"],
      ["partial", "Partielles"],
      ["paid", "Payées"],
      ["unpaid", "À régler"],
      ["cancelled", "Annulées"],
    ];
    return `
      ${toolbar("new-invoice", "Nouvelle facture", `<div class="segmented">${filters.map(([key, label]) => `<button data-action="set-invoice-filter" data-filter="${esc(key)}" class="${ui.invoiceFilter === key ? "active" : ""}">${esc(label)}</button>`).join("")}</div>`)}
      <div class="band search-page-form invoice-search-form">
        <input type="search" value="${esc(ui.invoiceSearch || "")}" data-invoice-search placeholder="Rechercher une facture..." />
        <button type="button" data-action="clear-invoice-search" ${ui.invoiceSearch ? "" : "disabled"}>Effacer</button>
      </div>
      <div data-invoice-results>
        ${invoiceResultsHtml(invoices)}
      </div>`;
  }

  function invoiceResultsHtml(invoices = filteredInvoices()) {
    const totals = invoiceListTotals(invoices);
    const queryLabel = ui.invoiceSearch ? ` · recherche "${esc(ui.invoiceSearch)}"` : "";
    return `
      ${kpis([
        { label: "Factures", value: invoices.length },
        { label: "Total", value: money(totals.total) },
        { label: "Réglé", value: money(totals.paid) },
        { label: "Reste dû", value: money(totals.due) },
      ])}
      <div class="band">
        <div class="band-title"><h2>Factures du club actif</h2><strong>${invoices.length} facture${invoices.length > 1 ? "s" : ""}${queryLabel}</strong></div>
        <div class="table-wrap"><table>
          <thead><tr><th>N°</th><th>Contact</th><th>Date</th><th>Statut</th><th class="money">Total</th><th class="money">Réglé</th><th class="money">Reste dû</th></tr></thead>
          <tbody>
            ${invoices.length ? invoices.map(invoiceRowHtml).join("") : ((state.invoices || []).length === 0 ? `<tr><td colspan="7">${emptyStateHtml("invoices")}</td></tr>` : `<tr><td colspan="7" class="empty">Aucune facture pour ce filtre.</td></tr>`)}
          </tbody>
        </table></div>
      </div>`;
  }

  function updateInvoiceResults() {
    const container = app.querySelector("[data-invoice-results]");
    if (container) container.innerHTML = invoiceResultsHtml();
    const clearButton = app.querySelector('[data-action="clear-invoice-search"]');
    if (clearButton) clearButton.disabled = !ui.invoiceSearch;
  }

  function invoiceRowHtml(invoice) {
    const contact = invoiceDisplayContact(invoice);
    const totals = invoiceDisplayTotals(invoice);
    return `<tr class="clickable-row" data-action="open-invoice" data-id="${esc(invoice.id)}">
      <td><strong>${esc(invoice.number || "Brouillon")}</strong></td>
      <td>${esc(personLabel(contact) || "Contact")}</td>
      <td>${dateDisplay(invoice.issuedAt || invoice.createdAt)}</td>
      <td>${invoiceStatusPill(invoice)}</td>
      <td class="money">${money(totals.total)}</td>
      <td class="money">${money(totals.paid)}</td>
      <td class="money ${asNumber(totals.restDue) > 0 ? "due" : ""}">${money(totals.restDue)}</td>
    </tr>`;
  }

  function invoiceEditorSourceRow(item, selectedKeys, alreadyBilledKeys, locked) {
    const selected = selectedKeys.has(item.sourceKey);
    const alreadyBilled = alreadyBilledKeys.has(item.sourceKey);
    const disabled = locked || alreadyBilled;
    return `<label class="invoice-source-row ${alreadyBilled ? "already-billed" : ""}">
      <input type="checkbox" name="billableKeys" value="${esc(item.sourceKey)}" ${selected && !alreadyBilled ? "checked" : ""} ${disabled ? "disabled" : ""} />
      <span class="invoice-source-type">${esc(invoiceSourceTypeLabel(item.sourceType))}</span>
      <span><strong>${esc(item.label)}</strong><small>${esc(item.description || "")}</small></span>
      <span class="money">${money(item.total)}</span>
      ${alreadyBilled ? `<em>déjà facturé</em>` : ""}
    </label>`;
  }

  function invoiceEditorLineRow(line, index, locked) {
    const cats = ["", "Don", "Frais divers", "Prestation", "Location ponctuelle", "Autre recette"];
    return `<div class="invoice-custom-row" data-invoice-custom-row>
      <input name="customLabel_${index}" placeholder="Ligne personnalisée" value="${esc(line.label || "")}" ${locked ? "readonly" : ""} />
      <input name="customQty_${index}" type="number" min="0" step="0.01" value="${esc(line.quantity || 1)}" ${locked ? "readonly" : ""} />
      <input name="customUnit_${index}" type="number" step="0.01" value="${esc(line.unitPrice || "")}" ${locked ? "readonly" : ""} />
      <input name="customVat_${index}" type="number" min="0" step="0.01" value="${esc(line.vatRate ?? effectiveDefaultVatRate())}" ${locked || isClubVatExempt() ? "readonly" : ""} />
      <select name="customCat_${index}" title="Catégorie comptable (recette)" ${locked ? "disabled" : ""}>${cats.map((c) => `<option value="${esc(c)}" ${asText(line.category) === c ? "selected" : ""}>${c ? esc(c) : "Catégorie…"}</option>`).join("")}</select>
      <button type="button" class="icon danger" data-action="remove-invoice-custom-line" ${locked ? "disabled" : ""}>×</button>
    </div>`;
  }

  function invoiceEditorSummary(invoice, lines, payments) {
    const totals = invoiceTotalsFromLines(lines, payments);
    return `<div class="invoice-summary">
      <div><span>Total</span><strong>${money(totals.total)}</strong></div>
      <div><span>Déjà payé</span><strong>${money(totals.paid)}</strong></div>
      <div><span>Reste à payer</span><strong class="${asNumber(totals.restDue) > 0 ? "due" : ""}">${money(totals.restDue)}</strong></div>
    </div>`;
  }

  // Lot 4a — Libellé clair de l'état d'un paiement/échéance (réutilise les helpers existants,
  // aucune logique de stockage modifiée) : Payé / En retard / À encaisser le JJ/MM / Refusé.
  function invoicePaymentStatusLabel(payment = {}) {
    if (paymentIsRefused(payment)) return `<span class="invoice-status cancelled">Refusé</span>`;
    if (paymentStatus(payment) === "OK") return "Payé";
    if (paymentIsLate(payment)) return `<span class="invoice-status late" title="Échéance dépassée">En retard</span>`;
    const due = paymentDueDate(payment);
    if (!isImmediatePayment(payment) && due) return `À encaisser le ${esc(dateDisplay(due))}`;
    return esc(paymentStatus(payment) || "À suivre");
  }

  function invoicePaymentsHtml(payments = []) {
    const rows = invoiceVisiblePayments(payments);
    if (!rows.length) return `<div class="empty compact">Aucun paiement enregistré.</div>`;
    return `<div class="invoice-payment-list">${rows.map((payment, index) => `<div>
      <strong>${esc(invoicePaymentModeLabel(payment, index))}</strong>
      <span>${money(payment.amount)}</span>
      <span>${esc(invoiceDateLabel(payment.date))}</span>
      <span>${invoicePaymentStatusLabel(payment)}</span>
    </div>`).join("")}</div>`;
  }

  function invoicePaymentActionHtml(invoice = {}) {
    const allowed = invoiceAllowedActions(invoice);
    // Facture soldée : pas de bouton ambigu -> mention claire « Facture soldée ».
    if (allowed.settled) {
      return `<div class="inline-actions invoice-payment-actions"><span class="invoice-status paid" title="Aucun reste à payer">Facture soldée</span></div>`;
    }
    if (!allowed.addPayment) return ""; // brouillon / annulée : rien
    const totals = invoiceTotalsFromLines(invoice.lines || [], invoice.paymentsSnapshot || []);
    return `<div class="inline-actions invoice-payment-actions">
      <button type="button" class="primary" data-action="add-invoice-payment" data-id="${esc(invoice.id)}">Ajouter un règlement</button>
      <span>Reste à payer : <strong>${money(totals.restDue)}</strong></span>
    </div>`;
  }

  function invoicePrintActionsHtml(invoice = {}) {
    if (!invoice.id || !invoiceAllowedActions(invoice).print) return "";
    // Réimpression toujours possible (émise / payée / partielle / annulée). Libellé adapté si déjà imprimée.
    const label = asText(invoice.printedAt) ? "Réimprimer la facture" : "Imprimer la facture";
    return `<button type="button" data-action="print-invoice" data-id="${esc(invoice.id)}">${label}</button>
      <button type="button" data-action="export-invoice-pdf" data-id="${esc(invoice.id)}">PDF facture</button>`;
  }

  function invoiceVisiblePayments(payments = []) {
    return normalizePayments(payments).filter((payment) => asNumber(payment.amount) > 0.005);
  }

  // Lot 5a — Avoirs liés à une facture (affichage seul). Lit state.creditNotes sans rien modifier :
  // pas de changement de calcul, pas d'effet sur le reste dû, pas de mutation des avoirs.
  function creditNotesForInvoice(invoiceId) {
    if (!asText(invoiceId)) return [];
    return (state.creditNotes || [])
      .filter((cn) => cn && asText(cn.invoiceId) === asText(invoiceId))
      .slice()
      .sort((a, b) => asText(b.date).localeCompare(asText(a.date)));
  }

  function invoiceCreditNoteStatusPill(creditNote = {}) {
    const labels = { actif: "Actif", "utilisé": "Utilisé", "annulé": "Annulé" };
    const cls = creditNote.status === "annulé" ? "cancelled" : (creditNote.status === "utilisé" ? "partial" : "paid");
    return `<span class="invoice-status ${cls}">${esc(labels[creditNote.status] || creditNote.status)}</span>`;
  }

  function invoiceLinkedCreditNotesHtml(invoice = {}) {
    // Bloc affiché pour toute facture NON brouillon : permet aussi de créer le 1er avoir (Lot 5d-1).
    // Conteneur [data-invoice-credit-notes] -> rafraîchi en place par refreshOpenInvoiceEditor.
    if (!invoice.id || computedInvoiceStatus(invoice) === "draft") return "";
    const cancelled = computedInvoiceStatus(invoice) === "cancelled";
    const notes = creditNotesForInvoice(invoice.id);
    // Lot 7b — Facture annulée : pas de création d'avoir. On n'affiche le bloc (lecture seule)
    // que s'il existe déjà des avoirs liés.
    if (cancelled && !notes.length) return "";
    const typeLabels = { "réduction": "Avoir / crédit", "crédit": "Crédit à valoir", "annulation": "Annulation" };
    // Lot UX avoirs — reste dû de la facture, pour proposer directement le règlement par avoir.
    // Réutilise use-credit-note-payment (mêmes conditions que le bloc du dialogue de paiement) :
    // aucune logique de calcul dupliquée, juste un raccourci d'affichage.
    const restDue = asNumber(invoiceTotalsFromLines(invoice.lines || [], invoice.paymentsSnapshot || []).restDue);
    const rows = notes.map((cn) => {
      const amt = asNumber(cn.amount);
      // Lot B3b — un avoir supérieur au reste dû n'est plus bloqué : il est utilisable jusqu'à
      // concurrence du reste dû, le solde restant activement disponible (voir use-credit-note-payment).
      const eligible = !cancelled && cn.status === "actif" && asText(cn.contactId) === asText(invoice.contactId) && restDue > 0.005;
      const usedAmount = eligible ? Math.min(amt, restDue) : 0;
      const usable = eligible && usedAmount > 0.005;
      const remainder = usable ? amt - usedAmount : 0;
      const actionBtn = remainder > 0.005
        ? `Utiliser ${money(usedAmount)} et garder ${money(remainder)} d'avoir`
        : "Utiliser au paiement";
      const action = usable
        ? `<button type="button" class="secondary small" data-action="use-credit-note-payment" data-credit-note-id="${esc(cn.id)}" data-invoice-id="${esc(invoice.id)}">${esc(actionBtn)}</button>`
        : "";
      return `<div class="contact-invoice-row" data-action="edit-credit-note" data-id="${esc(cn.id)}" title="Ouvrir l'avoir" style="cursor:pointer">
      <span class="contact-invoice-num"><strong>${money(cn.amount)}</strong><small>${esc(dateDisplay(cn.date))}</small></span>
      <span>${esc(cn.reason || typeLabels[cn.type] || "Avoir")}</span>
      <span class="muted">${esc(typeLabels[cn.type] || cn.type)}</span>
      ${invoiceCreditNoteStatusPill(cn)}
      ${action}
    </div>`;
    }).join("");
    const createBtn = cancelled ? "" : `<button type="button" data-action="add-credit-note" data-invoice-id="${esc(invoice.id)}" data-contact-id="${esc(invoice.contactId)}">Créer un avoir</button>`;
    return `<div class="dialog-section invoice-editor" data-invoice-credit-notes>
      <div class="band-title compact"><h3>Avoirs liés à cette facture</h3>${createBtn}</div>
      <p class="muted">Un avoir peut être utilisé comme règlement pour réduire le reste à payer de cette facture.</p>
      <div class="contact-invoice-list">${notes.length ? rows : `<div class="empty compact">Aucun avoir lié à cette facture.</div>`}</div>
    </div>`;
  }

  // Lot 5b — Avoirs DISPONIBLES (statut « actif ») d'un contact (affichage seul, fiche contact).
  // Ignore les avoirs sans contactId (orphelins) : aucun rattachement automatique dans ce lot.
  function creditNotesAvailableForContact(contactId) {
    if (!asText(contactId)) return [];
    return (state.creditNotes || [])
      .filter((cn) => cn && asText(cn.contactId) === asText(contactId) && cn.status === "actif")
      .slice()
      .sort((a, b) => asText(b.date).localeCompare(asText(a.date)));
  }

  function contactAvailableCreditNotesHtml(contact = {}) {
    const notes = creditNotesAvailableForContact(contact.id);
    if (!notes.length) return ""; // pas de bloc vide
    const typeLabels = { "réduction": "Avoir / crédit", "crédit": "Crédit à valoir", "annulation": "Annulation" };
    const total = notes.reduce((sum, cn) => sum + asNumber(cn.amount), 0);
    const rows = notes.map((cn) => {
      const inv = asText(cn.invoiceId) ? (state.invoices || []).find((i) => i.id === cn.invoiceId) : null;
      const invLabel = inv ? `Facture ${inv.number || "—"}` : "";
      return `<div class="contact-invoice-row" data-action="edit-credit-note" data-id="${esc(cn.id)}" title="Ouvrir l'avoir" style="cursor:pointer">
      <span class="contact-invoice-num"><strong>${money(cn.amount)}</strong><small>${esc(dateDisplay(cn.date))}</small></span>
      <span>${esc(cn.reason || typeLabels[cn.type] || "Avoir")}${invLabel ? ` <small class="muted">· ${esc(invLabel)}</small>` : ""}</span>
      <span class="muted">${esc(typeLabels[cn.type] || cn.type)}</span>
    </div>`;
    }).join("");
    return `<section class="contact-recap-section">
      <h4>Avoirs disponibles</h4>
      <div class="contact-recap-kpis"><div><span>Total disponible</span><strong>${money(total)}</strong></div></div>
      <div class="contact-invoice-list">${rows}</div>
    </section>`;
  }

  function invoiceLineVatLabel(line = {}, club = activeClub()) {
    const isReduction = asNumber(line.total) < -0.005 || asNumber(line.unitPrice) < -0.005 || asText(line.sourceKey).startsWith("discount:") || /^remise\b/i.test(asText(line.label));
    if (isReduction || isClubVatExempt(club)) return "—";
    return `${intValue(line.vatRate)}%`;
  }

  function invoicePaymentModeLabel(payment = {}, index = 0) {
    const method = asText(payment.check || defaultPaymentMethod(index));
    if (method === "avoir") return "Avoir";
    if (/^\d+$/.test(method) && !asText(payment.checkNumber)) return "Chèque";
    return paymentModeLabel(method);
  }

  function invoicePaymentCheckNumber(payment = {}) {
    const checkNumber = asText(payment.checkNumber);
    if (checkNumber) return checkNumber;
    const method = asText(payment.check);
    if (/^\d+$/.test(method)) return method;
    return "";
  }

  function invoiceDateLabel(value) {
    return dateDisplay(value) || "Date non renseignée";
  }

  function invoiceClubDetailsHtml(club = {}) {
    const contact = club.contact || {};
    const admin = club.admin || {};
    const address = [
      contact.address,
      contact.address2,
      [contact.postalCode, contact.city].filter(Boolean).join(" "),
      contact.country,
    ].filter(Boolean);
    const rows = [
      ...address,
      contact.phone ? `Tél. ${contact.phone}` : "",
      contact.email ? `Email ${contact.email}` : "",
      contact.website ? `Site ${contact.website}` : "",
      admin.siret ? `SIRET ${admin.siret}` : "",
      admin.siren ? `SIREN ${admin.siren}` : "",
      admin.rna ? `RNA ${admin.rna}` : "",
      admin.vatNumber ? `TVA intracommunautaire ${admin.vatNumber}` : "",
      clubVatMention(club),
    ].filter(Boolean);
    return rows.map((row) => esc(row)).join("<br>") || "Informations non renseignées";
  }

  function invoiceDocumentPayload(invoice = {}, options = {}) {
    invoice = normalizeInvoice(invoice);
    const totals = invoiceTotalsFromLines(invoice.lines || [], invoice.paymentsSnapshot || []);
    const club = invoice.clubSnapshot || activeClub() || {};
    const contact = invoice.contactSnapshot || invoiceContact(invoice.contactKind, invoice.contactId) || {};
    const draft = invoice.status === "draft";
    const computedStatus = computedInvoiceStatus(invoice);
    // Mentions d'impression (rendu uniquement) : duplicata si déjà imprimée, payée si solde = 0,
    // annulée si statut annulé. On ne modifie aucune donnée métier ici.
    const cancelled = computedStatus === "cancelled";
    const fullyPaid = !draft && !cancelled && asNumber(totals.total) > 0.005 && asNumber(totals.restDue) <= 0.005;
    const duplicata = Boolean(options.duplicata) && !draft;
    const paidDate = fullyPaid
      ? invoiceVisiblePayments(invoice.paymentsSnapshot || []).map((p) => asText(p.date)).filter(Boolean).sort().pop()
      : "";
    const paidDateLabel = paidDate ? invoiceDateLabel(paidDate) : "";
    const primaryColor = "#1f2937";
    const secondaryColor = "#64748b";
    const accentColor = "#2563eb";
    // Priorité : logo personnalisé du club (snapshot ou actuel) -> logo personnalisé global -> logo
    // par défaut de l'app (data URL, comme dans la barre latérale). Fallback initiales seulement si
    // aucun logo exploitable. Les data URL fonctionnent à l'aperçu, à l'impression et au PDF.
    const logo = isLogoDataUrl(club.logoDataUrl) ? club.logoDataUrl
      : isLogoDataUrl(settings.logoDataUrl) ? settings.logoDataUrl
      : defaultLogoDataUrl();
    const contactRows = [
      contact.address,
      [contact.postalCode, contact.city].filter(Boolean).join(" "),
      contact.country,
      contact.email ? `Email ${contact.email}` : "",
      contact.phone ? `Tél. ${contact.phone}` : "",
    ].filter(Boolean);
    // Lot 6e — Destinataire de facturation (réutilise le helper du Lot 6d, aucune donnée modifiée).
    // Cas responsable : on affiche l'adresse du contact (fallback) SANS l'e-mail/tél de l'enfant.
    const billing = invoiceBillingDisplay(invoice, contact);
    const billingAddressRows = [
      contact.address,
      [contact.postalCode, contact.city].filter(Boolean).join(" "),
      contact.country,
    ].filter(Boolean);
    const footerRows = [
      club.documents?.legalMentions,
      club.documents?.paymentTerms,
      club.documents?.defaultMessage,
      club.documents?.footer,
      clubVatMention(club),
    ].map(asText).filter(Boolean);
    const rows = (invoice.lines || []).map((line, index) => {
      const typeLabel = invoiceSourceTypeLabel(line.sourceType);
      const isReduction = asNumber(line.total) < -0.005 || asNumber(line.unitPrice) < -0.005 || /^remise\b/i.test(asText(line.label));
      return `<tr class="${index % 2 ? "alt" : ""} ${isReduction ? "reduction" : ""}">
      <td><span class="type-pill">${esc(typeLabel)}</span></td>
      <td><strong>${esc(line.label || "Ligne")}</strong>${line.description ? `<br><span>${esc(line.description)}</span>` : ""}</td>
      <td class="num">${esc(intValue(line.quantity))}</td>
      <td class="num">${money(line.unitPrice)}</td>
      <td class="num">${esc(invoiceLineVatLabel(line, club))}</td>
      <td class="num">${money(line.total)}</td>
    </tr>`;
    }).join("");
    const paymentRows = invoiceVisiblePayments(invoice.paymentsSnapshot || [])
      .map((payment) => `<tr>
        <td>${esc(invoicePaymentModeLabel(payment))}</td>
        <td>${esc(invoicePaymentCheckNumber(payment))}</td>
        <td>${esc(invoiceDateLabel(payment.date))}</td>
        <td>${esc(paymentStatus(payment) || payment.state || "à suivre")}</td>
        <td class="num">${money(payment.amount)}</td>
      </tr>`).join("");
    const title = draft ? "Aperçu brouillon" : `Facture ${invoice.number || "sans numéro"}`;
    return {
      title,
      html: `<!doctype html><html lang="fr"><head><meta charset="utf-8" />
        <title>${esc(title)}</title>
        <style>
          @page{size:A4;margin:14mm}
          *{box-sizing:border-box}
          body{font-family:Arial,"Helvetica Neue",sans-serif;color:#172033;margin:0;background:#fff;font-size:11.5px;line-height:1.45}
          .invoice-page{position:relative;max-width:190mm;margin:0 auto;min-height:267mm;padding:4mm 0 0}
          .invoice-page::before{content:"";position:absolute;left:0;top:0;width:58mm;height:3px;background:${esc(primaryColor)}}
          .document-header{display:grid;grid-template-columns:1.35fr .8fr;gap:18mm;align-items:start;margin-bottom:14mm;padding-top:8mm}
          .brand{display:grid;grid-template-columns:auto 1fr;gap:12px;align-items:start}
          .brand-logo{width:58px;height:58px;object-fit:contain}
          .brand-fallback{width:58px;height:58px;border:1px solid #d7dce5;border-radius:12px;display:grid;place-items:center;font-weight:800;color:${esc(primaryColor)};font-size:17px;background:#f8fafc}
          .club-name{font-size:19px;font-weight:800;color:${esc(primaryColor)};margin:0 0 5px;letter-spacing:.2px}
          .details{color:#475569}
          .details div{margin:1px 0}
          .invoice-meta{text-align:right;border:1px solid #d9dee8;border-top:3px solid ${esc(accentColor)};border-radius:12px;padding:14px 16px;background:#fbfcfe}
          .invoice-meta .label{font-size:10px;text-transform:uppercase;letter-spacing:.12em;color:#64748b;font-weight:800}
          h1{font-size:31px;margin:3px 0 8px;color:#111827;letter-spacing:.01em}
          .invoice-number{font-size:16px;font-weight:800;color:${esc(primaryColor)};margin-bottom:8px}
          .meta-row{display:flex;justify-content:space-between;gap:12px;border-top:1px solid #e5e9f0;padding-top:7px;margin-top:7px;color:#475569}
          .status-badge{display:inline-block;border-radius:999px;padding:4px 10px;font-size:10.5px;font-weight:800;text-transform:uppercase;letter-spacing:.04em;border:1px solid #cbd5e1;background:#f8fafc;color:#334155}
          .status-badge.paid{background:#ecfdf5;border-color:#a7f3d0;color:#047857}
          .status-badge.partial{background:#fff7ed;border-color:#fed7aa;color:#b45309}
          .status-badge.late{background:#fef2f2;border-color:#fecaca;color:#b91c1c}
          .status-badge.draft{background:#f1f5f9;border-color:#cbd5e1;color:#475569}
          .status-badge.cancelled{background:#e5e7eb;border-color:#9ca3af;color:#374151}
          .draft-banner{position:relative;border:2px dashed #991b1b;color:#991b1b;font-weight:900;text-align:center;padding:10px;margin:-5mm 0 9mm;text-transform:uppercase;letter-spacing:.18em;background:#fff7f7}
          .draft-watermark{position:fixed;inset:0;display:grid;place-items:center;pointer-events:none;z-index:0}
          .draft-watermark span{transform:rotate(-28deg);font-size:66px;font-weight:900;letter-spacing:.18em;color:rgba(153,27,27,.08)}
          .doc-watermark{position:fixed;inset:0;display:grid;place-items:center;pointer-events:none;z-index:0}
          .doc-watermark span{transform:rotate(-28deg);font-size:60px;font-weight:900;letter-spacing:.16em;color:rgba(37,99,235,.07)}
          .doc-banner{position:relative;z-index:1;border-radius:8px;text-align:center;font-weight:900;padding:9px 12px;margin:-3mm 0 8mm;text-transform:uppercase;letter-spacing:.12em;font-size:11px}
          .doc-banner.duplicata{border:2px dashed #1d4ed8;color:#1d4ed8;background:#eff6ff}
          .doc-banner.paid{border:2px solid #a7f3d0;color:#047857;background:#ecfdf5}
          .doc-banner.cancelled{border:2px solid #9ca3af;color:#374151;background:#e5e7eb}
          .section-grid{display:grid;grid-template-columns:1fr 1fr;gap:12mm;margin-bottom:10mm;position:relative;z-index:1}
          .card{border:1px solid #d9dee8;border-radius:12px;padding:13px 15px;background:#fff}
          .card h2{font-size:10px;text-transform:uppercase;letter-spacing:.13em;color:${esc(secondaryColor)};margin:0 0 9px;font-weight:900}
          .card strong{font-size:14px;color:#111827}
          table{width:100%;border-collapse:separate;border-spacing:0;margin:0 0 10mm;position:relative;z-index:1}
          th{background:#f3f6fa;color:#334155;font-size:10px;text-transform:uppercase;letter-spacing:.06em;border-top:1px solid #d8dee9;border-bottom:1px solid #d8dee9;padding:9px 8px;text-align:left}
          th:first-child{border-left:1px solid #d8dee9;border-top-left-radius:10px} th:last-child{border-right:1px solid #d8dee9;border-top-right-radius:10px}
          td{border-bottom:1px solid #e6ebf2;padding:9px 8px;text-align:left;vertical-align:top;background:#fff}
          tr.alt td{background:#fbfcfe}
          tr.reduction td{color:#7f1d1d;background:#fffafa}
          tbody tr:last-child td:first-child{border-bottom-left-radius:10px} tbody tr:last-child td:last-child{border-bottom-right-radius:10px}
          .num{text-align:right;white-space:nowrap}
          .type-pill{display:inline-block;border:1px solid #d7deea;border-left:3px solid ${esc(accentColor)};background:#f8fafc;border-radius:999px;padding:3px 8px;font-size:10px;font-weight:800;color:#334155;white-space:nowrap}
          .line-desc span{color:#64748b}
          .totals-wrap{display:grid;grid-template-columns:1fr 78mm;gap:10mm;align-items:start;margin-top:-2mm;margin-bottom:10mm}
          .total-box{border:1px solid #d9dee8;border-radius:12px;overflow:hidden;background:#fff}
          .total-row{display:flex;justify-content:space-between;gap:18px;padding:9px 12px;border-bottom:1px solid #e6ebf2}
          .total-row:last-child{border-bottom:0}
          .total-row strong{font-size:13px}
          .rest-due{background:#fff7ed;color:#9a3412}
          .rest-due.positive{background:#fef2f2;color:#b91c1c;font-weight:900}
          .rest-due.paid{background:#ecfdf5;color:#047857;font-weight:900}
          .payments-title{font-size:14px;color:${esc(primaryColor)};margin:0 0 8px}
          .empty-payment{border:1px dashed #cbd5e1;border-radius:10px;padding:12px;color:#64748b;background:#fbfcfe;margin-bottom:10mm}
          footer{position:relative;z-index:1;margin-top:12mm;color:#64748b;border-top:1px solid #d9dee8;padding-top:8px;font-size:10.5px}
          footer div{margin:2px 0}
          @media print{
            body{print-color-adjust:exact;-webkit-print-color-adjust:exact}
            .invoice-page{max-width:none;min-height:auto}
            table,.card,.total-box{break-inside:avoid}
          }
        </style></head><body>
          ${draft ? `<div class="draft-watermark"><span>BROUILLON</span></div>` : ""}
          ${duplicata && !draft ? `<div class="doc-watermark"><span>DUPLICATA</span></div>` : ""}
          <main class="invoice-page">
            <header class="document-header">
              <section class="brand">
                ${logo ? `<img class="brand-logo" src="${esc(logo)}" alt="${esc(club.name || settings.clubName || "Club")}" />` : `<div class="brand-fallback">${esc(initialsForText(club.name || settings.clubName || "Club"))}</div>`}
                <div>
                  <p class="club-name">${esc(club.name || settings.clubName || "Club")}</p>
                  <div class="details">${invoiceClubDetailsHtml(club).split("<br>").map((row) => `<div>${row}</div>`).join("")}</div>
                </div>
              </section>
              <aside class="invoice-meta">
                <div class="label">${draft ? "Document de travail" : "Document officiel"}</div>
                <h1>${draft ? "Brouillon" : "Facture"}</h1>
                <div class="invoice-number">${esc(invoice.number || "Numéro non attribué")}</div>
                <span class="status-badge ${esc(computedStatus)}">${esc(invoiceStatusLabel({ status: computedStatus }))}</span>
                <div class="meta-row"><span>Date</span><strong>${esc(dateDisplay(invoice.issuedAt || invoice.createdAt) || dateDisplay(new Date()))}</strong></div>
              </aside>
            </header>
            ${draft ? `<div class="draft-banner">BROUILLON - document non officiel</div>` : ""}
            ${duplicata ? `<div class="doc-banner duplicata">Duplicata de facture — réimpression</div>` : ""}
            ${cancelled ? `<div class="doc-banner cancelled">Facture annulée</div>` : ""}
            ${fullyPaid ? `<div class="doc-banner paid">Facture payée — Solde restant : ${money(0)}${paidDateLabel ? ` · Payée le ${esc(paidDateLabel)}` : ""}</div>` : ""}
            <section class="section-grid">
              <div class="card">
                <h2>Facturé à</h2>
                ${billing.billedTo
                  ? `<strong>${esc(billing.billedTo.name)}</strong>
                <div class="details">
                  <div>Pour : ${esc(billing.beneficiary || personLabel(contact))}</div>
                  ${asText(billing.billedTo.phone) ? `<div>Tél. ${esc(billing.billedTo.phone)}</div>` : ""}
                  ${asText(billing.billedTo.email) ? `<div>Email ${esc(billing.billedTo.email)}</div>` : ""}
                  ${billingAddressRows.length ? billingAddressRows.map((row) => `<div>${esc(row)}</div>`).join("") : `<div>Adresse non renseignée</div>`}
                </div>`
                  : `<strong>${esc(personLabel(contact) || "Contact")}</strong>
                <div class="details">${contactRows.length ? contactRows.map((row) => `<div>${esc(row)}</div>`).join("") : `<div>Informations non renseignées</div>`}</div>
                ${billing.guardianMissing ? `<div style="color:${secondaryColor};font-size:12px;margin-top:4px">Responsable légal non renseigné</div>` : ""}`}
              </div>
              <div class="card">
                <h2>Résumé</h2>
                <div class="details">
                  <div>Référence : <strong>${esc(invoice.number || "Brouillon")}</strong></div>
                  <div>Statut : <strong>${esc(invoiceStatusLabel({ status: computedStatus }))}</strong></div>
                  <div>Émission : <strong>${esc(dateDisplay(invoice.issuedAt) || (draft ? "Non émise" : "Date non renseignée"))}</strong></div>
                </div>
              </div>
            </section>
            <table><thead><tr><th>Type</th><th>Désignation</th><th class="num">Qté</th><th class="num">Prix U</th><th class="num">TVA</th><th class="num">Total</th></tr></thead><tbody>${rows || `<tr><td colspan="6">Aucune ligne.</td></tr>`}</tbody></table>
            <section class="totals-wrap">
              <div>${invoice.notes ? `<div class="card"><h2>Notes</h2><div class="details">${esc(invoice.notes).replaceAll("\n", "<br>")}</div></div>` : ""}</div>
              <div class="total-box">
                <div class="total-row"><span>Total</span><strong>${money(totals.total)}</strong></div>
                <div class="total-row"><span>Déjà payé</span><strong>${money(totals.paid)}</strong></div>
                <div class="total-row rest-due ${asNumber(totals.restDue) > 0.005 ? "positive" : "paid"}"><span>${asNumber(totals.restDue) > 0.005 ? "Reste à payer" : "Facture payée"}</span><strong>${money(totals.restDue)}</strong></div>
              </div>
            </section>
            <h2 class="payments-title">Paiements et échéances</h2>
            ${paymentRows
              ? `<table><thead><tr><th>Mode</th><th>N° chèque</th><th>Date</th><th>État</th><th class="num">Montant</th></tr></thead><tbody>${paymentRows}</tbody></table>`
              : `<div class="empty-payment">Aucun paiement enregistré.</div>`}
            ${footerRows.length ? `<footer>${footerRows.map((row) => `<div>${esc(row)}</div>`).join("")}</footer>` : ""}
          </main>
        </body></html>`,
    };
  }

  // Une facture déjà imprimée (printedAt posé, non brouillon) -> les sorties suivantes sont des duplicata.
  function invoiceAlreadyPrinted(invoice = {}) {
    const stored = (state.invoices || []).find((item) => item.id === invoice.id) || invoice;
    return Boolean(asText(stored.printedAt)) && stored.status !== "draft";
  }

  // Marque la facture comme imprimée (métadonnée printedAt), une seule fois, sans toucher au contenu
  // (lignes, montants, snapshots, paiements). Persistance silencieuse (pas de re-render).
  function markInvoicePrinted(invoiceId) {
    const inv = (state.invoices || []).find((item) => item.id === invoiceId);
    if (!inv || inv.status === "draft" || asText(inv.printedAt)) return;
    inv.printedAt = new Date().toISOString();
    try { saveCurrentClubPayload({ reloadActive: false }); } catch { /* persistance silencieuse */ }
  }

  // Dispatcher léger previewId -> callback, abonné UNE SEULE FOIS au canal de résultat réel
  // (jamais l'ouverture de l'aperçu) exposé par le preload privilégié. Une facture n'est marquée
  // imprimée que lorsque son previewId reçoit success:true (webContents.print() réellement réussi,
  // callback Electron). "closed" nettoie l'entrée quand l'aperçu se ferme, avec ou sans impression.
  let previewPrintResultHandlers = null;
  function previewPrintResultHandlerMap() {
    if (previewPrintResultHandlers) return previewPrintResultHandlers;
    previewPrintResultHandlers = new Map();
    window.monGestaClubShell?.onPreviewPrintResult?.((data = {}) => {
      const handler = previewPrintResultHandlers.get(data.previewId);
      if (handler && data.success) handler(data);
      if (data.closed) previewPrintResultHandlers.delete(data.previewId);
    });
    return previewPrintResultHandlers;
  }

  // Aperçu d'impression NATIF (correctif régression globale) : le durcissement des fenêtres
  // Electron (setWindowOpenHandler refusant toute création de fenêtre par défaut) bloquait
  // silencieusement window.open("", "_blank"). Le main process ouvre désormais une fenêtre
  // d'aperçu sécurisée (socle partagé avec showPagePrintPreview) : le document s'affiche d'abord,
  // la boîte d'impression native ne s'ouvre qu'après un clic explicite sur « Imprimer » DANS
  // l'aperçu — jamais automatiquement. Distinct de exportInvoicePdf (qui produit un vrai .pdf).
  //
  // markInvoicePrinted() n'est PLUS appelé à l'ouverture de l'aperçu (l'ouverture seule ne prouve
  // rien) : on attend le résultat RÉEL de webContents.print() via previewPrintResultHandlerMap,
  // reçu de façon asynchrone et découplée de cette fonction (l'utilisateur peut fermer l'aperçu
  // sans imprimer, annuler la boîte native, ou imprimer bien après le retour de cette fonction).
  async function printInvoice(invoice = {}) {
    if (!invoice?.id) return;
    const payload = invoiceDocumentPayload(invoice, { duplicata: invoiceAlreadyPrinted(invoice) });
    if (!window.monGestaClubShell?.printHtml) {
      // Hors Electron (démo web) : aucune impression native possible. Repli sur le socle d'aperçu web
      // partagé (showPagePrintPreview, mode "print") — jamais un téléchargement HTML : un document
      // affiché avec un vrai bouton Imprimer, cohérent avec les avoirs/présences/page générique.
      //
      // markInvoicePrinted() n'est PAS appelé ici : un navigateur n'a aucun équivalent fiable au
      // callback success de webContents.print() (ni window.onafterprint, qui se déclenche aussi
      // après une annulation ou une simple fermeture de la boîte d'impression). Ouvrir l'aperçu ne
      // prouve rien : mieux vaut une information incomplète mais honnête qu'un faux statut « imprimée ».
      // Le statut imprimé/DUPLICATA reste une fonctionnalité fiable réservée à l'application Electron.
      showPagePrintPreview(payload, { mode: "print" });
      ui.saveMessage = "Aperçu de la facture ouvert dans une nouvelle fenêtre.";
      render();
      return;
    }
    ui.saveMessage = "Ouverture de l'aperçu...";
    render();
    try {
      const result = await window.monGestaClubShell.printHtml(payload);
      if (result?.ok && result?.previewId) {
        previewPrintResultHandlerMap().set(result.previewId, () => { markInvoicePrinted(invoice.id); render(); });
        ui.saveMessage = "Aperçu de la facture ouvert";
      } else {
        ui.saveMessage = "Aperçu impossible à ouvrir pour le moment";
      }
    } catch (error) {
      console.error(error);
      ui.saveMessage = "Aperçu impossible à ouvrir pour le moment";
    }
    render();
  }

  // Correctif "PDF honnête" : hors Electron, ce bouton retombait sur printInvoice(), qui
  // téléchargeait un fichier .html — un bouton nommé PDF ne doit jamais produire un fichier portant
  // la mauvaise extension. Aucune bibliothèque de génération PDF n'existe dans le projet (vérifié) :
  // seule la boîte d'impression du navigateur peut produire un vrai PDF ("Enregistrer au format
  // PDF"), donc le repli web ouvre le même aperçu partagé que printInvoice, en mode "pdf" (libellé
  // et aide dédiés) — jamais un téléchargement, jamais un faux fichier renommé.
  async function exportInvoicePdf(invoice = {}) {
    if (!invoice?.id) return;
    const payload = invoiceDocumentPayload(invoice, { duplicata: invoiceAlreadyPrinted(invoice) });
    if (window.monGestaClubShell?.exportPdf) {
      ui.saveMessage = "Création du PDF facture...";
      render();
      try {
        const result = await window.monGestaClubShell.exportPdf(payload);
        // Marquée UNIQUEMENT sur result.ok === true : succès explicite couvrant printToPDF, la boîte
        // d'enregistrement non annulée ET l'écriture réelle du fichier (voir exportCurrentWindowPdf,
        // main process — result structuré dans tous les cas, jamais une simple absence d'erreur).
        // Annulation ou échec : aucune marque, aucun DUPLICATA prématuré.
        if (result?.ok === true) {
          markInvoicePrinted(invoice.id);
          ui.saveMessage = "PDF facture créé";
        } else if (result?.canceled) {
          ui.saveMessage = "Export PDF annulé";
        } else {
          ui.saveMessage = result?.message || "Export PDF impossible pour le moment";
        }
        render();
      } catch (error) {
        console.error(error);
        ui.saveMessage = "Export PDF impossible pour le moment";
        render();
        alert("Impossible de créer le PDF de la facture.");
      }
      return;
    }
    // Hors Electron : jamais de marquage (voir printInvoice ci-dessus pour la justification complète —
    // aucun signal fiable de succès n'existe côté navigateur).
    showPagePrintPreview(payload, { mode: "pdf" });
    ui.saveMessage = "Aperçu ouvert : choisissez « Enregistrer en PDF » dans la nouvelle fenêtre.";
    render();
  }

  async function validateDraftInvoiceForOutput(invoice = {}, sourceButton = null) {
    invoice = normalizeInvoice(invoice);
    if (!invoice?.id) return null;
    if (invoice.status !== "draft") return invoice;
    const form = sourceButton?.closest?.("form");
    let result = null;
    if (form?.querySelector("[data-invoice-editor]")) {
      const previousAction = form.dataset.submitAction || "";
      form.dataset.submitAction = "issue";
      recordHistory();
      result = await saveInvoiceFromForm(invoice, new FormData(form), form);
      form.dataset.submitAction = previousAction;
      if (result === false || result?.cancel === true) return null;
      const emitted = state.invoices.find((item) => item.id === result?.reopenInvoiceId) || state.invoices.find((item) => item.id === invoice.id);
      persist(result?.message || `Facture ${emitted?.number || ""} émise`);
      const targetDialog = dialogForContainer(form);
      if (targetDialog?.open) targetDialog.close();
      render();
      if (emitted) setTimeout(() => openInvoiceEditor(emitted), 0);
      return emitted || null;
    }
    recordHistory();
    const emitted = await issueDraftInvoice(invoice);
    if (!emitted) return null;
    persist(`Facture ${emitted.number || ""} émise`);
    render();
    return emitted;
  }

  function openContactInvoiceFromLink(contactLink) {
    const link = parseContactLink(contactLink);
    const kind = link.kind === "prospect" ? "prospects" : "members";
    const contact = state.contacts[kind]?.find((row) => row.id === link.contactId);
    if (!contact) return;
    openInvoiceEditor(draftInvoiceForContact(contact, kind) || { contactId: contact.id, contactKind: kind, status: "draft" });
  }

  // Point d'entrée « Nouvelle facture » (page Factures / Accueil) : une facture est toujours
  // adressée à une personne. On choisit d'abord le contact, puis on ouvre l'éditeur existant
  // (openContactInvoiceFromLink → openInvoiceEditor). Dialogue de navigation léger : aucune
  // donnée écrite, aucun moteur dupliqué.
  function openNewInvoiceContactChooser() {
    if (!((state.contacts.members || []).length || (state.contacts.prospects || []).length)) {
      alert("Ajoutez d'abord un contact : une facture est toujours adressée à une personne.");
      return;
    }
    dialog.innerHTML = `<form>
      <div class="dialog-header"><h2>Nouvelle facture</h2><button class="icon" type="button" data-dialog-close title="Fermer" aria-label="Fermer">×</button></div>
      <div class="dialog-body"><div class="form-grid">
        <p class="muted wide">Choisissez la personne à facturer. MonGestaClub réunira ensuite tout ce qui peut lui être facturé (inscriptions, commandes, stages…), et vous pourrez ajouter des lignes libres.</p>
        ${customerSelectField({}, "Personne à facturer", "— Choisir un contact —")}
      </div></div>
      <div class="dialog-footer">
        <span></span>
        <div class="dialog-footer-actions"><button type="button" data-dialog-close>Annuler</button><button class="primary" type="submit">Continuer</button></div>
      </div>
    </form>`;
    dialog.querySelectorAll("[data-dialog-close]").forEach((button) => button.addEventListener("click", () => dialog.close()));
    dialog.querySelector("form").addEventListener("submit", (event) => {
      event.preventDefault();
      const link = asText(event.currentTarget.elements.contactLink.value);
      if (!link) { alert("Choisissez un contact à facturer."); return; }
      dialog.close();
      openContactInvoiceFromLink(link);
    });
    showFloatingDialog(dialog, "select[name='contactLink']");
  }

  // Section « Factures du contact » : accès direct aux factures déjà liées au contact (voir /
  // réimprimer une émise/payée/annulée, continuer un brouillon). Réutilise l'action open-invoice
  // existante (ouverture officielle + réimpression/duplicata déjà en place). Aucune facture créée
  // ni modifiée ici : c'est seulement un raccourci de navigation.
  // Menu déroulant « Choisir une facture » (remplace l'ancienne liste). Affiché uniquement si le
  // contact a plusieurs factures. La facture affichée est pré-sélectionnée ; changer d'option ouvre
  // la facture choisie au même emplacement (swap propre, protection brouillon conservée). Les actions
  // Imprimer / PDF restent dans le footer de la facture affichée (pas de boutons par option).
  function contactInvoicesSectionHtml(contact = {}, kind = "members", currentInvoiceId = "") {
    const all = contactInvoices(contact, kind)
      .slice()
      .sort((a, b) => asText(b.issuedAt || b.createdAt).localeCompare(asText(a.issuedAt || a.createdAt)));
    if (all.length < 2) return ""; // rien à choisir si le contact n'a qu'une (ou zéro) facture
    const current = all.find((inv) => inv.id === currentInvoiceId);
    const optionLabel = (inv) => {
      const total = money(invoiceDisplayTotals(inv).total);
      if (inv.status === "draft") return `Brouillon — ${total}`;
      const status = invoiceStatusLabel({ ...inv, status: computedInvoiceStatus(inv) }) + (invoiceIsLate(inv) ? " · En retard" : "");
      return `${inv.number || "Facture"} — ${status} — ${total}`;
    };
    const placeholder = current ? "" : `<option value="" disabled selected>— Choisir une facture —</option>`;
    const options = all.map((inv) => `<option value="${esc(inv.id)}" ${inv.id === currentInvoiceId ? "selected" : ""}>${esc(optionLabel(inv))}</option>`).join("");
    return `<div class="dialog-section invoice-editor">
      <label>Choisir une facture<select data-invoice-switch>${placeholder}${options}</select></label>
    </div>`;
  }

  // Lot 1 — Tableau LECTURE SEULE des lignes figées d'une facture non-brouillon.
  // Réutilise le motif d'en-têtes de l'impression (Type / Désignation / Qté / Prix U / TVA / Total)
  // et les classes de table déjà stylées (.table-wrap > table). Aucune édition, aucun input.
  function invoiceFrozenLinesHtml(invoice = {}) {
    const club = activeClub();
    const lines = invoice.lines || [];
    if (!lines.length) return `<div class="empty compact">Aucune ligne sur cette facture.</div>`;
    const rows = lines.map((line) => `<tr>
      <td>${esc(invoiceSourceTypeLabel(line.sourceType))}</td>
      <td><strong>${esc(line.label || "Ligne")}</strong>${line.description ? `<br><span class="muted">${esc(line.description)}</span>` : ""}</td>
      <td style="text-align:right">${esc(intValue(line.quantity))}</td>
      <td style="text-align:right">${money(line.unitPrice)}</td>
      <td style="text-align:right">${esc(invoiceLineVatLabel(line, club))}</td>
      <td style="text-align:right">${money(line.total)}</td>
    </tr>`).join("");
    return `<div class="table-wrap"><table>
      <thead><tr><th>Type</th><th>Désignation</th><th style="text-align:right">Qté</th><th style="text-align:right">Prix U</th><th style="text-align:right">TVA</th><th style="text-align:right">Total</th></tr></thead>
      <tbody>${rows}</tbody>
    </table></div>`;
  }

  // Lot 6d — Destinataire de facturation affiché dans l'écran facture (AFFICHAGE SEUL).
  // Facture figée : lit contactSnapshot.billedTo (capturé à l'émission). Brouillon (snapshot
  // absent) : calcule depuis le contact vivant (mineur + responsable légal). Adulte / ancienne
  // facture sans billedTo : le contact lui-même (fallback, comportement inchangé).
  function invoiceBillingDisplay(invoice = {}, contact = {}) {
    const snap = invoice.contactSnapshot;
    if (snap && snap.billedTo && asText(snap.billedTo.name)) {
      return { billedTo: snap.billedTo, beneficiary: personLabel(contact), guardianMissing: false };
    }
    if (!snap && contactInvoiceKind(invoice.contactKind) === "members" && memberCategory(contact) === "Enfant") {
      const name = asText(contact.legalGuardianName);
      if (name) return { billedTo: { name, email: asText(contact.legalGuardianEmail), phone: asText(contact.legalGuardianPhone) }, beneficiary: personLabel(contact), guardianMissing: false };
      return { billedTo: null, beneficiary: "", guardianMissing: true };
    }
    return { billedTo: null, beneficiary: "", guardianMissing: false };
  }

  function invoiceBillingHeadHtml(invoice = {}, contact = {}) {
    const b = invoiceBillingDisplay(invoice, contact);
    const address = esc([contact.address, contact.postalCode, contact.city].filter(Boolean).join(" ") || "Adresse non renseignée");
    if (b.billedTo) {
      const coords = [asText(b.billedTo.phone), asText(b.billedTo.email)].filter(Boolean).map(esc).join(" · ");
      return `<h3>Facturé à : ${esc(b.billedTo.name)}</h3>
            <p><span class="muted">Pour :</span> ${esc(b.beneficiary)}</p>
            ${coords ? `<p class="muted">${coords}</p>` : ""}
            <p>${address}</p>`;
    }
    if (b.guardianMissing) {
      // Lot Responsable légal — parité avec le dialogue Discipline/Dossier, qui a déjà ce bouton
      // (membershipGuardianSummaryHtml). Réutilise tel quel contactLinkAction()/open-linked-contact :
      // le formulaire facture porteur (s'il y en a un, cf. .dialog-footer) est sauvegardé puis fermé
      // AVANT l'ouverture de la fiche contact — aucun nouveau mécanisme, aucun empilement.
      // guardianMissing n'est vrai que pour un mineur (memberCategory === "Enfant"), donc contactId
      // (jamais prospectContactId) est le bon champ pour contactLinkForRow().
      return `<h3>${esc(personLabel(contact))}</h3>
            <p>${address}</p>
            <p class="muted"><strong>⚠️ Responsable légal non renseigné</strong></p>
            <p>${contactLinkAction({ contactId: contact.id }, "Ouvrir la fiche contact")}</p>`;
    }
    return `<h3>${esc(personLabel(contact))}</h3><p>${address}</p>`;
  }

  // Ouvre une facture avec swap propre. Depuis une facture VERROUILLÉE (lecture seule, rien à
  // perdre) on ferme la courante avant d'ouvrir la cible -> une seule facture à l'écran. Depuis un
  // BROUILLON, on NE ferme PAS (aucune perte d'édition non sauvegardée). Réutilisé par l'action
  // « open-invoice » et par le menu déroulant « Choisir une facture ».
  function openInvoiceWithSwap(target, originEl) {
    if (!target) return;
    const hostDialog = originEl && originEl.closest ? originEl.closest("dialog") : null;
    const hostEditorId = hostDialog?.querySelector("[data-invoice-editor-id]")?.dataset.invoiceEditorId || "";
    const hostInvoice = hostEditorId ? state.invoices.find((inv) => inv.id === hostEditorId) : null;
    if (hostDialog && hostDialog.open && hostInvoice && hostInvoice.status !== "draft" && hostEditorId !== target.id) {
      hostDialog.close();
      setTimeout(() => openInvoiceEditor(target), 0);
      return;
    }
    openInvoiceEditor(target);
  }

  function openInvoiceEditor(invoice = {}) {
    invoice = normalizeInvoice(invoice);
    const contact = invoice.contactSnapshot || invoiceContact(invoice.contactKind, invoice.contactId);
    if (!contact) {
      alert("Contact introuvable pour cette facture.");
      return;
    }
    const allowed = invoiceAllowedActions(invoice);
    const locked = !allowed.editLines;
    const billables = billableItemsForContact(contact, invoice.contactKind);
    const alreadyBilled = billedSourceKeys(invoice.id);
    const selectedKeys = new Set((invoice.lines || []).map((line) => line.sourceKey).filter(Boolean));
    const proposedLines = (invoice.lines || []).filter((line) => line.sourceType !== "custom");
    const selectedBillables = billables.filter((item) => selectedKeys.has(item.sourceKey));
    const customLines = (invoice.lines || []).filter((line) => line.sourceType === "custom");
    if (!customLines.length && !locked) customLines.push(normalizeInvoiceLine({ sourceType: "custom", label: "", quantity: 1, unitPrice: 0, vatRate: effectiveDefaultVatRate() }));
    const previewLines = locked ? invoice.lines : [...selectedBillables.map(invoiceLineFromBillable), ...customLines.filter((line) => line.label || asNumber(line.unitPrice))];
    const previewPayments = locked ? invoice.paymentsSnapshot : selectedInvoicePayments(previewLines, billables);
    const title = locked ? `Facture ${invoice.number || ""}` : "Créer / éditer une facture";
    const body = `<div class="dialog-section invoice-editor" data-invoice-editor data-tour="invoice-dialog" data-invoice-editor-id="${esc(invoice.id)}">
        <div class="invoice-editor-head" data-tour="invoice-contact">
          <div data-invoice-editor-head>${invoiceBillingHeadHtml(invoice, contact)}</div>
          <div data-tour="invoice-status">${invoiceStatusPill(invoice)}${invoice.number ? `<strong>${esc(invoice.number)}</strong>` : ""}${locked ? `<span class="invoice-status" title="Facture actuellement affichée">Facture affichée</span>` : ""}</div>
        </div>
        <div data-invoice-editor-summary data-tour="invoice-total">${invoiceEditorSummary(invoice, previewLines, previewPayments)}</div>
        ${invoiceIsFrozen(invoice) ? `<p class="invoice-frozen-note" title="Le montant d'une facture émise n'est pas recalculé si l'inscription ou le tarif change ensuite.">🔒 Montant figé à l'émission.</p>` : ""}
      </div>
      ${contactInvoicesSectionHtml(contact, invoice.contactKind, invoice.id)}
      ${locked
        ? `<div class="dialog-section invoice-editor">
        <h3>Lignes de la facture</h3>
        ${invoiceFrozenLinesHtml(invoice)}
      </div>`
        : `<div class="dialog-section invoice-editor">
        <h3>Lignes proposées</h3>
        <p class="muted">Choisis les éléments du contact à ajouter à cette facture. Les lignes déjà présentes dans une facture émise sont signalées.</p>
        <div class="invoice-source-list" data-tour="invoice-lines">
          ${billables.length ? billables.map((item) => invoiceEditorSourceRow(item, selectedKeys, alreadyBilled, locked)).join("") : `<div class="empty compact">Aucun élément facturable trouvé pour ce contact.</div>`}
          ${proposedLines.filter((line) => !billables.some((item) => item.sourceKey === line.sourceKey)).map((line) => `<div class="invoice-source-row already-billed"><span class="invoice-source-type">${esc(invoiceSourceTypeLabel(line.sourceType))}</span><span><strong>${esc(line.label)}</strong><small>Source ancienne ou supprimée</small></span><span class="money">${money(line.total)}</span></div>`).join("")}
        </div>
      </div>
      <div class="dialog-section invoice-editor">
        <div class="band-title compact"><h3>Lignes personnalisées</h3><button type="button" data-action="add-invoice-custom-line" data-tour="invoice-add-line">Ajouter une ligne</button></div>
        <div class="invoice-custom-head"><span>Libellé</span><span>Qté</span><span>Prix U</span><span>TVA %</span><span>Catégorie</span><span></span></div>
        <div data-invoice-custom-lines data-tour="invoice-custom-lines">${customLines.map((line, index) => invoiceEditorLineRow(line, index, locked)).join("")}</div>
      </div>`}
      <div class="dialog-section invoice-editor" data-invoice-editor-payments data-tour="invoice-payments">
        <h3>Paiements et échéances</h3>
        ${invoicePaymentsHtml(previewPayments)}
        ${locked ? invoicePaymentActionHtml(invoice) : ""}
      </div>
      ${invoiceLinkedCreditNotesHtml(invoice)}
      ${locked
        ? (asText(invoice.notes) ? `<div class="dialog-section invoice-editor"><h3>Notes</h3><p>${esc(invoice.notes).replaceAll("\n", "<br>")}</p></div>` : "")
        : textareaField("notes", "Notes facture", invoice.notes || "")}
      <input type="hidden" name="invoiceId" value="${esc(invoice.id)}" />
      <input type="hidden" name="contactId" value="${esc(invoice.contactId)}" />
      <input type="hidden" name="contactKind" value="${esc(invoice.contactKind)}" />`;
    const footer = [
      invoicePrintActionsHtml(invoice),
      allowed.emit ? `<button class="primary" type="submit" data-submit-action="issue" data-tour="invoice-issue">Émettre / valider la facture</button>` : "",
    ].filter(Boolean).join("");
    setNextWindowKey(invoice.id ? `invoice:${invoice.id}` : null);
    const invoiceDialog = showDialog(title, body, (data, form) => saveInvoiceFromForm(invoice, data, form), (form) => {
      form.addEventListener("change", (event) => {
        if (event.target.matches("input[name='billableKeys']")) updateInvoiceEditorPreview(form, invoice, billables);
        if (event.target.matches("[data-invoice-switch]")) {
          const id = event.target.value;
          if (id && id !== invoice.id) openInvoiceWithSwap(state.invoices.find((inv) => inv.id === id), event.target);
        }
      });
      form.addEventListener("input", (event) => {
        if (event.target.closest("[data-invoice-custom-row]")) updateInvoiceEditorPreview(form, invoice, billables);
      });
    }, footer);
    // Facture verrouillée = vue lecture seule : on retire le bouton submit par défaut
    // (« Enregistrer ») de showDialog et on renomme « Annuler » en « Fermer » pour ne laisser
    // que des actions cohérentes (Imprimer / PDF / Fermer). Aucune édition possible.
    if (locked && invoiceDialog) {
      const submit = invoiceDialog.querySelector(".dialog-footer-actions button.primary[type='submit']");
      if (submit) submit.remove();
      const closeBtn = invoiceDialog.querySelector(".dialog-footer-actions button[data-dialog-close]");
      if (closeBtn) closeBtn.textContent = "Fermer";
    }
  }

  function selectedInvoiceLinesFromForm(form, invoice, billables) {
    const billableByKey = new Map(billables.map((item) => [item.sourceKey, item]));
    const lines = [...form.querySelectorAll("input[name='billableKeys']:checked")]
      .map((input) => billableByKey.get(input.value))
      .filter(Boolean)
      .map(invoiceLineFromBillable);
    form.querySelectorAll("[data-invoice-custom-row]").forEach((row, index) => {
      const label = form.elements[`customLabel_${index}`]?.value || "";
      const quantity = asNumber(form.elements[`customQty_${index}`]?.value || 1);
      const unitPrice = asNumber(form.elements[`customUnit_${index}`]?.value);
      if (!asText(label) && !unitPrice) return;
      lines.push(normalizeInvoiceLine({
        sourceType: "custom",
        sourceKey: `custom:${invoice.id}:${index}:${asText(label)}`,
        category: form.elements[`customCat_${index}`]?.value || "",
        label,
        quantity,
        unitPrice,
        vatRate: asNumber(form.elements[`customVat_${index}`]?.value ?? effectiveDefaultVatRate()),
      }));
    });
    return lines;
  }

  async function saveInvoiceFromForm(sourceInvoice, data, form) {
    if (sourceInvoice.status !== "draft") return false;
    const contact = invoiceContact(data.get("contactKind"), data.get("contactId"));
    if (!contact) {
      alert("Contact introuvable.");
      return false;
    }
    const billables = billableItemsForContact(contact, data.get("contactKind"));
    const lines = selectedInvoiceLinesFromForm(form, sourceInvoice, billables);
    if (!lines.length) {
      alert("Ajoute au moins une ligne à la facture.");
      return false;
    }
    const issue = form.dataset.submitAction === "issue";
    if (issue && !(await confirmInvoiceIssue())) return { cancel: true };
    // Note : sourceInvoice.id est TOUJOURS renseigné ici (openInvoiceEditor passe la facture par
    // normalizeInvoice(), qui attribue un id même à un brouillon jamais persisté). Le seul signal
    // fiable de « facture réellement nouvelle » est son absence de state.invoices à cet instant.
    const wasNew = !state.invoices.some((item) => item.id === sourceInvoice.id);
    const paymentsSnapshot = selectedInvoicePayments(lines, billables);
    const totals = invoiceTotalsFromLines(lines, paymentsSnapshot);
    const now = new Date().toISOString();
    const next = normalizeInvoice({
      ...sourceInvoice,
      id: sourceInvoice.id || id("invoice"),
      clubId: activeClubId(),
      contactId: contact.id,
      contactKind: contactInvoiceKind(data.get("contactKind")),
      number: issue ? (sourceInvoice.number || nextInvoiceNumber()) : sourceInvoice.number,
      status: issue ? "issued" : "draft",
      createdAt: sourceInvoice.createdAt || now,
      issuedAt: issue ? (sourceInvoice.issuedAt || now) : "",
      updatedAt: now,
      clubSnapshot: issue ? clubInvoiceSnapshot() : sourceInvoice.clubSnapshot,
      contactSnapshot: issue ? contactInvoiceSnapshot(contact, data.get("contactKind")) : sourceInvoice.contactSnapshot,
      lines,
      paymentsSnapshot: issue ? paymentsSnapshot : paymentsSnapshot,
      totals,
      notes: data.get("notes") || "",
    });
    upsertInvoice(next);
    // Un seul événement par sauvegarde : émission prioritaire sur création (facture créée ET
    // émise en une seule opération -> invoice.issued uniquement, jamais les deux).
    if (issue) {
      audit.invoiceIssued(next, contact);
    } else if (wasNew) {
      audit.invoiceCreated(next, contact);
    } else {
      const changes = invoiceAuditChanges(sourceInvoice, next);
      if (changes.length) audit.invoiceUpdated(next, contact, changes);
    }
    return issue
      ? { message: `Facture ${next.number} émise pour ${personLabel(contact)}`, reopenInvoiceId: next.id }
      : `Brouillon de facture enregistré pour ${personLabel(contact)}`;
  }

  function openInvoicePaymentDialog(invoice = {}) {
    invoice = normalizeInvoice(invoice);
    if (invoice.status === "draft" || invoice.status === "cancelled") return;
    const totals = invoiceTotalsFromLines(invoice.lines || [], invoice.paymentsSnapshot || []);
    const nextIndex = (invoice.paymentsSnapshot || []).length + 1;
    const defaultMethod = acceptedPaymentModes().includes("cash") ? "cash" : defaultPaymentMethod(nextIndex - 1);
    const payableLines = (invoice.lines || []).filter((line) => Math.abs(asNumber(line.total)) > 0.005);
    // Reste dû PAR LIGNE : on répartit le déjà-payé sur les lignes (séquentiel, lignes positives).
    // Ainsi la somme des restes par ligne = reste dû global -> les cases cochées correspondent
    // exactement au montant réglé (plus d'écart « lignes 240 € mais on paie 165 € »).
    let toAllocate = Math.max(0, asNumber(totals.paid));
    const lineDues = payableLines.map((line) => {
      const gross = asNumber(line.total);
      let due = gross;
      if (gross > 0) {
        const alloc = Math.min(toAllocate, gross);
        toAllocate -= alloc;
        due = Math.round((gross - alloc) * 100) / 100;
      }
      return { line, gross, due, settled: gross > 0 && due <= 0.005 };
    });
    const lineSelector = payableLines.length >= 2 ? `<div class="dialog-section invoice-payment-lines">
      <h4>Régler des lignes précises</h4>
      <p class="muted">Reste à régler par ligne (le déjà-payé est déjà déduit). Coche les lignes à régler : la somme se met à jour.</p>
      ${lineDues.map((it) => {
        const label = esc([invoiceSourceTypeLabel(it.line.sourceType), it.line.label].filter(Boolean).join(" · "));
        const paidPart = asNumber(it.gross) - asNumber(it.due); // déjà réglé sur cette ligne
        if (it.settled) {
          return `<label class="invoice-pay-line settled">
            <input type="checkbox" disabled />
            <span class="invoice-pay-line-info"><span class="invoice-pay-line-label">${label}</span><small class="invoice-pay-line-detail">Total ${money(it.gross)} · entièrement réglé</small></span>
            <span class="invoice-pay-line-due"><strong>réglé</strong></span>
          </label>`;
        }
        const fixed = it.gross < 0; // ligne négative (remise) : toujours comptée, non décochable
        const detail = fixed
          ? `Remise appliquée`
          : (paidPart > 0.005 ? `Total ${money(it.gross)} · déjà réglé ${money(paidPart)}` : `Total ${money(it.gross)}`);
        return `<label class="invoice-pay-line">
          <input type="checkbox" data-invoice-pay-line value="${esc(it.due)}" ${fixed ? "checked disabled" : "checked"} />
          <span class="invoice-pay-line-info"><span class="invoice-pay-line-label">${label}</span><small class="invoice-pay-line-detail">${detail}</small></span>
          <span class="invoice-pay-line-due"><small>reste à régler</small><strong>${money(it.due)}</strong></span>
        </label>`;
      }).join("")}
    </div>` : "";
    const availableAvoirs = creditNotesAvailableForContact(invoice.contactId);
    const avoirSection = availableAvoirs.length ? `<div class="dialog-section invoice-credit-note-section">
      <h4>Utiliser un avoir</h4>
      <p class="muted">Un avoir réduit le reste à payer, sans créer d'encaissement bancaire.</p>
      ${availableAvoirs.map((cn) => {
        const amt = asNumber(cn.amount);
        const restDue = asNumber(totals.restDue);
        // Lot B3b — même règle que le bloc facture : utilisable dès que le reste dû est positif,
        // même au-delà du montant de l'avoir (le reliquat reste disponible pour le contact).
        const usedAmount = restDue > 0.005 ? Math.min(amt, restDue) : 0;
        const usable = usedAmount > 0.005;
        const remainder = usable ? amt - usedAmount : 0;
        const typeLabel = ({ "réduction": "Avoir / crédit", "crédit": "Crédit à valoir", "annulation": "Annulation" })[cn.type] || "Avoir";
        const info = `${esc(cn.reason || typeLabel)} · ${money(amt)}`;
        if (usable) {
          const actionBtn = remainder > 0.005
            ? `Utiliser ${money(usedAmount)} et garder ${money(remainder)} d'avoir`
            : "Utiliser cet avoir";
          return `<div class="credit-note-use-row">
            <span class="credit-note-use-info">${info}</span>
            <button type="button" class="secondary small" data-action="use-credit-note-payment" data-credit-note-id="${esc(cn.id)}" data-invoice-id="${esc(invoice.id)}">${esc(actionBtn)}</button>
          </div>`;
        }
        return `<div class="credit-note-use-row credit-note-use-row--disabled">
          <span class="credit-note-use-info">${info}</span>
          <span class="muted small">Facture déjà soldée</span>
        </div>`;
      }).join("")}
    </div>` : "";
    const body = `<div class="dialog-section">
      <h3>${esc(invoice.number || "Facture")}</h3>
      <div class="invoice-summary">
        <div><span>Total</span><strong>${money(totals.total)}</strong></div>
        <div><span>Déjà payé</span><strong>${money(totals.paid)}</strong></div>
        <div><span>Reste à payer</span><strong class="${totals.restDue > 0 ? "due" : ""}">${money(totals.restDue)}</strong></div>
      </div>
    </div>
    ${avoirSection}
    ${lineSelector}
    <div class="dialog-section invoice-payment-form">
      <div class="invoice-payment-form-head"><h4>Nouveau règlement</h4></div>
      <label>Montant à enregistrer<input name="amount" type="number" step="0.01" min="0" max="${esc(Math.max(0, totals.restDue).toFixed(2))}" value="${esc(Math.max(0, totals.restDue).toFixed(2))}" required /></label>
      <label>Mode de règlement<select name="check">${paymentMethodOptions(nextIndex - 1, defaultMethod)}</select></label>
      <label class="payment-check-number-field" data-invoice-check-number-field hidden>N° chèque<input name="checkNumber" /></label>
      <label>Date du règlement<input name="date" type="date" value="${esc(dateInputValue(new Date()))}" required /></label>
      <label class="invoice-cheque-later" data-invoice-cheque-later hidden><input type="checkbox" name="chequeLater" /> <span>Chèque à encaisser plus tard (sinon encaissé maintenant)</span></label>
    </div>`;
    showDialog("Ajouter un règlement", body, (data) => {
      // Le règlement ne dépasse jamais le reste dû (garde de sécurité, en plus du max de l'input).
      const amount = Math.min(asNumber(data.get("amount")), Math.max(0, asNumber(totals.restDue)));
      if (amount <= 0) {
        alert("Indique un montant de règlement supérieur à zéro.");
        return false;
      }
      const target = state.invoices.find((item) => item.id === invoice.id);
      if (!target) return false;
      // Statut calculé (plus de menu technique) : un règlement est « Payé » par défaut ; seul un
      // chèque coché « à encaisser plus tard » reste non encaissé (state vide) -> ne réduit pas le reste dû.
      const mode = data.get("check") || defaultMethod;
      const isCheck = paymentMethodKind({ check: mode }) === "check";
      const payment = normalizePayment({
        check: mode,
        checkNumber: isCheck ? data.get("checkNumber") || "" : "",
        amount,
        date: data.get("date") || "",
        state: (isCheck && data.get("chequeLater")) ? "" : "Payé",
        taxRate: effectiveDefaultVatRate(),
      });
      target.paymentsSnapshot = normalizePayments([...(target.paymentsSnapshot || []), payment]);
      target.totals = invoiceTotalsFromLines(target.lines || [], target.paymentsSnapshot);
      target.status = computedInvoiceStatus(target);
      target.updatedAt = new Date().toISOString();
      upsertInvoice(target);
      audit.invoicePaymentAttached(target, invoiceContact(target.contactKind, target.contactId), payment);
      return `Règlement ajouté sur la facture ${target.number || ""}`;
    }, (form) => {
      const select = form.elements.check;
      const checkNumberField = form.querySelector("[data-invoice-check-number-field]");
      const chequeLaterField = form.querySelector("[data-invoice-cheque-later]");
      const refresh = () => {
        const isCheck = paymentMethodKind({ check: select?.value }) === "check";
        if (checkNumberField) checkNumberField.hidden = !isCheck;
        if (chequeLaterField) chequeLaterField.hidden = !isCheck;
        if (!isCheck) {
          if (form.elements.checkNumber) form.elements.checkNumber.value = "";
          if (form.elements.chequeLater) form.elements.chequeLater.checked = false;
        }
      };
      select?.addEventListener("change", refresh);
      refresh();
      const lineBoxes = [...form.querySelectorAll("[data-invoice-pay-line]")];
      if (lineBoxes.length && form.elements.amount) {
        const recalcFromLines = () => {
          const sum = lineBoxes.filter((box) => box.checked).reduce((acc, box) => acc + asNumber(box.value), 0);
          const capped = Math.min(Math.max(0, sum), Math.max(0, totals.restDue));
          form.elements.amount.value = capped.toFixed(2);
        };
        lineBoxes.forEach((box) => box.addEventListener("change", recalcFromLines));
        recalcFromLines();
      }
      // Libellé du bouton principal propre à cette popup : « Valider le règlement » (plus clair que
      // « Enregistrer »). Les autres dialogues gardent le défaut « Enregistrer ».
    }, "", undefined, "Valider le règlement");
  }

  function updateInvoiceEditorPreview(form, invoice, billables) {
    const lines = selectedInvoiceLinesFromForm(form, invoice, billables);
    const payments = selectedInvoicePayments(lines, billables);
    const summary = form.querySelector(".invoice-summary");
    if (summary) summary.outerHTML = invoiceEditorSummary(invoice, lines, payments);
    const paymentList = form.querySelector(".invoice-payment-list, .invoice-editor .empty.compact");
    const paymentSection = [...form.querySelectorAll(".dialog-section.invoice-editor")].find((section) => section.querySelector("h3")?.textContent.includes("Paiements"));
    if (paymentSection) {
      paymentSection.innerHTML = `<h3>Paiements et échéances</h3>${invoicePaymentsHtml(payments)}`;
    }
  }

  function addInvoiceCustomLine(button) {
    const form = button.closest("form");
    const list = form?.querySelector("[data-invoice-custom-lines]");
    if (!list) return;
    const index = list.querySelectorAll("[data-invoice-custom-row]").length;
    list.insertAdjacentHTML("beforeend", invoiceEditorLineRow(normalizeInvoiceLine({ sourceType: "custom", quantity: 1, vatRate: effectiveDefaultVatRate() }), index, false));
    enhanceNumberSteppers(list);
  }

  function removeInvoiceCustomLine(button) {
    const row = button.closest("[data-invoice-custom-row]");
    const form = button.closest("form");
    row?.remove();
    form?.querySelectorAll("[data-invoice-custom-row]").forEach((item, index) => {
      item.querySelectorAll("input").forEach((input) => {
        input.name = input.name.replace(/_\d+$/, `_${index}`);
      });
    });
  }

  function openContactModule(source) {
    const contact = contactByLink(source.dataset.contactLink);
    if (!contact) return;
    const module = source.dataset.module;
    if (module === "disciplines") {
      const entry = firstContactModuleEntry(contact, module);
      // Inscription existante -> on l'ouvre ; sinon nouvelle inscription seedée avec le contact
      // (cohérent avec boutique/stages qui ouvrent déjà une nouvelle entrée quand il n'y en a pas).
      if (entry) openMembershipDialog(entry.row);
      else openMembershipDialog(registrationSeedFromContact(contact, source.dataset.contactLink));
      return;
    }
    if (module === "boutique") {
      const entry = firstContactModuleEntry(contact, module);
      const link = parseContactLink(source.dataset.contactLink);
      if (entry) openOrderDialog(entry.row);
      else openOrderDialog({
        contactId: link.kind === "member" ? link.contactId : "",
        prospectContactId: link.kind === "prospect" ? link.contactId : "",
        lastName: contact.lastName || "",
        firstName: contact.firstName || "",
        email: contact.email || "",
        phone: contact.mobile || contact.phone || "",
        address: contact.address || "",
        postalCode: contact.postalCode || "",
        city: contact.city || "",
      });
      return;
    }
    if (module === "stages") {
      const entry = firstContactModuleEntry(contact, module);
      const stageId = entry?.stageId || firstStageIdForContact(contact);
      if (entry) openRegistrationDialog(stageId, entry.row);
      else openRegistrationStageChoiceDialog({ contactLink: source.dataset.contactLink });
    }
  }

  function registrationSeedFromContact(contact = {}, contactLink = "") {
    const link = parseContactLink(contactLink);
    return {
      contactId: link.kind === "member" ? link.contactId : "",
      prospectContactId: link.kind === "prospect" ? link.contactId : "",
      lastName: contact.lastName || "",
      firstName: contact.firstName || "",
      phone: contact.mobile || contact.phone || "",
      email: contact.email || "",
      address: contact.address || "",
      postalCode: contact.postalCode || "",
      city: contact.city || "",
      identityPhotoDataUrl: contact.identityPhotoDataUrl || "",
    };
  }

  function customerSelectField(row = {}, label = "Client enregistré", freeLabel = "Vente libre / créer un non-membre") {
    const selected = contactLinkForRow(row);
    const memberOptions = state.contacts.members
      .slice()
      .sort((a, b) => personKey(a).localeCompare(personKey(b)))
      .map((contact) => contactOption("member", contact, selected));
    const prospectOptions = state.contacts.prospects
      .slice()
      .sort((a, b) => personKey(a).localeCompare(personKey(b)))
      .map((contact) => contactOption("prospect", contact, selected));
    return `<label class="wide shop-member-select">${esc(label)}<select name="contactLink" data-contact-link>
      <option value="">${esc(freeLabel)}</option>
      ${memberOptions.length ? `<optgroup label="Adhérents">${memberOptions.join("")}</optgroup>` : ""}
      ${prospectOptions.length ? `<optgroup label="Non adhérents">${prospectOptions.join("")}</optgroup>` : ""}
    </select></label>`;
  }

  function contactOption(kind, contact, selected) {
    const label = [contact.lastName, contact.firstName].filter(Boolean).join(" ");
    const value = `${kind}:${contact.id}`;
    return `<option value="${esc(value)}" ${value === selected ? "selected" : ""}>${esc(label || "Contact sans nom")}</option>`;
  }

  function stageParticipantSelectField(row = {}, stage = {}) {
    const selected = contactLinkForRow(row);
    const selectedLink = parseContactLink(selected);
    const allowMembers = stageAllowsContactKind(stage, "member") || selectedLink.kind === "member";
    const allowProspects = stageAllowsContactKind(stage, "prospect") || selectedLink.kind === "prospect";
    const memberOptions = allowMembers
      ? state.contacts.members
        .slice()
        .sort((a, b) => personKey(a).localeCompare(personKey(b)))
        .map((contact) => contactOption("member", contact, selected))
      : [];
    const prospectOptions = allowProspects
      ? state.contacts.prospects
        .slice()
        .sort((a, b) => personKey(a).localeCompare(personKey(b)))
        .map((contact) => contactOption("prospect", contact, selected))
      : [];
    return `<label class="wide shop-member-select">Participant enregistré<select name="contactLink" data-contact-link>
      <option value="">Nouveau participant / créer un non-membre</option>
      ${memberOptions.length ? `<optgroup label="Adhérents">${memberOptions.join("")}</optgroup>` : ""}
      ${prospectOptions.length ? `<optgroup label="Non adhérents">${prospectOptions.join("")}</optgroup>` : ""}
    </select></label>`;
  }

  function contactBody(row = {}) {
    const tel = row.mobile || row.phone || "";
    const address = [row.address, row.postalCode, row.city].filter(Boolean).join(" ");
    const category = memberCategory(row) || row.category || "";
    const customPhoto = identityPhoto(row);
    const displayPhoto = identityPhotoDisplaySrc(row);
    // Widget "Coordonnées" réutilisé (alertes vigilance, popover dans facture/inscription…) :
    // le lien e-mail était un <a href="mailto:...") brut ("Envoyer un mail"), ouvrant la
    // messagerie externe directement au lieu du dialogue MonGestaClub. contactLinkForRow()
    // (déjà utilisé juste en dessous pour "Ouvrir la fiche contact / facture") résout le
    // membre/prospect réel derrière cette ligne fusionnée (adhésion/commande/inscription) :
    // réutilisé ici pour retrouver le contact complet et ouvrir le même dialogue e-mail que
    // partout ailleurs. Repli sur le mailto direct seulement si la résolution échoue (cas
    // très rare : ligne sans contact lié), pour ne jamais rendre l'adresse totalement inerte.
    const contactLink = contactLinkForRow(row);
    const emailAction = row.email
      ? (contactLink
        ? `<button type="button" class="contact-action-link" data-action="send-contact-email" data-contact-link="${esc(contactLink)}" title="Ouvrir la messagerie MonGestaClub"><span>${esc(row.email)}</span><strong>Envoyer un mail</strong></button>`
        : `<a class="contact-action-link" href="${esc(contactEmailHref(row))}" title="Ouvrir la messagerie"><span>${esc(row.email)}</span><strong>Envoyer un mail</strong></a>`)
      : `<span class="muted">Non renseigné</span>`;
    return `<div class="contact-card">
      <div class="contact-card-head">
        <button class="contact-card-photo ${customPhoto ? "" : "default-avatar"}" type="button" data-action="open-identity-photo" data-photo-src="${esc(customPhoto)}" data-avatar-src="${esc(displayPhoto)}" title="${customPhoto ? "Ouvrir la photo" : "Ouvrir la silhouette"}"><img src="${esc(displayPhoto)}" alt="${customPhoto ? "Photo" : "Silhouette"} de ${esc(personLabel(row) || "contact")}" /></button>
        <div>${personCell(row)}</div>
      </div>
      <dl>
        <div><dt>E-mail</dt><dd>${emailAction}</dd></div>
        <div><dt>Téléphone</dt><dd>${tel ? `<a class="contact-action-link" href="tel:${esc(tel)}" title="Appeler ce numéro"><span>${esc(tel)}</span><strong>Appeler</strong></a>` : `<span class="muted">Non renseigné</span>`}</dd></div>
        <div><dt>Adresse</dt><dd>${address ? esc(address) : `<span class="muted">Non renseignée</span>`}</dd></div>
        <div><dt>Date de naissance</dt><dd>${dateDisplay(row.birthDate) || `<span class="muted">Non renseignée</span>`}</dd></div>
        <div><dt>Âge</dt><dd>${memberAgeLabel(row) || `<span class="muted">Non calculé</span>`}</dd></div>
        <div><dt>Catégorie</dt><dd>${category ? esc(category) : `<span class="muted">Non calculée</span>`}</dd></div>
      </dl>
      ${contactLinkForRow(row) ? `<div class="inline-actions">${contactLinkAction(row, "Ouvrir la fiche contact / facture")}</div>` : ""}
    </div>`;
  }

  function openAlertContact(source) {
    let row = null;
    if (source.dataset.type === "membership") {
      const membership = state.memberships.find((item) => item.id === source.dataset.id);
      row = { ...(membership || {}), ...(contactForMembership(membership) || {}) };
    }
    if (source.dataset.type === "order") row = state.shopOrders.find((item) => item.id === source.dataset.id);
    if (source.dataset.type === "registration") row = state.stageRegistrations[source.dataset.stageId]?.find((item) => item.id === source.dataset.id);
    if (!row) return;
    showInfoDialog("Coordonnées", contactBody(row));
  }

  function openPaymentContact(source) {
    let row = null;
    if (source.dataset.paymentModule === "membership") {
      const membership = state.memberships.find((item) => item.id === source.dataset.id);
      row = { ...(membership || {}), ...(contactForMembership(membership) || {}) };
    }
    if (source.dataset.paymentModule === "order") row = state.shopOrders.find((item) => item.id === source.dataset.id);
    if (source.dataset.paymentModule === "registration") {
      row = state.stageRegistrations[source.dataset.stageId]?.find((item) => item.id === source.dataset.id);
    }
    if (!row) return;
    showInfoDialog("Coordonnées", contactBody(row));
  }

  function contactFromDialogForm(form) {
    const data = new FormData(form);
    const contactLink = parseContactLink(data.get("contactLink"));
    const linked = contactLink.kind && contactLink.id
      ? state.contacts[contactLink.kind]?.find((contact) => contact.id === contactLink.id) || {}
      : {};
    return {
      ...linked,
      lastName: data.get("lastName") || linked.lastName || "",
      firstName: data.get("firstName") || linked.firstName || "",
      email: data.get("email") || linked.email || "",
      mobile: data.get("mobile") || data.get("phone") || linked.mobile || "",
      phone: data.get("phone") || linked.phone || "",
      address: data.get("address") || linked.address || "",
      postalCode: data.get("postalCode") || linked.postalCode || "",
      city: data.get("city") || linked.city || "",
      birthDate: data.get("birthDate") || linked.birthDate || "",
      category: data.get("category") || linked.category || "",
      identityAvatarChoice: data.get("identityAvatarChoice") || linked.identityAvatarChoice || "auto",
    };
  }

  function openDialogContact(source) {
    const form = source.closest("form");
    if (!form) return;
    form.querySelector(".dialog-contact-popover")?.remove();
    const panel = document.createElement("div");
    panel.className = "dialog-contact-popover";
    panel.innerHTML = `
      <div class="dialog-contact-popover-head">
        <strong>Coordonnées</strong>
        <button class="icon" type="button" data-action="close-dialog-contact" title="Fermer" aria-label="Fermer">×</button>
      </div>
      ${contactBody(contactFromDialogForm(form))}
    `;
    (form.querySelector(".dialog-body") || form).prepend(panel);
  }

  function closeDialogContact(source) {
    source.closest(".dialog-contact-popover")?.remove();
  }

  function setIdentityPhotoInForm(form, dataUrl = "") {
    const widget = form?.querySelector("[data-identity-photo-widget]");
    const input = widget?.querySelector("[data-identity-photo-value]");
    const frame = widget?.querySelector(".identity-photo-frame");
    const preview = widget?.querySelector("[data-identity-photo-preview]");
    if (!widget || !input || !frame || !preview) return;
    const valid = isImageDataUrl(dataUrl);
    const formData = new FormData(form);
    const avatarSrc = identityAvatarSrc(contactFromDialogForm(form));
    input.value = valid ? dataUrl : "";
    frame.classList.toggle("empty", false);
    frame.classList.toggle("default-avatar", !valid);
    frame.dataset.avatarSrc = valid ? "" : avatarSrc;
    if (valid) {
      preview.outerHTML = `<img src="${esc(dataUrl)}" alt="Photo d'identité" data-identity-photo-preview />`;
    } else {
      preview.outerHTML = `<img src="${esc(avatarSrc)}" alt="Silhouette de ${esc([formData.get("firstName"), formData.get("lastName")].filter(Boolean).join(" ") || "contact")}" data-identity-photo-preview />`;
    }
  }

  function openIdentityPhoto(source) {
    const widget = source.closest("[data-identity-photo-widget]");
    const dataUrl = source.dataset.photoSrc || widget?.querySelector("[data-identity-photo-value]")?.value || "";
    const form = widget?.closest("form");
    const editable = Boolean(widget && !widget.hasAttribute("data-identity-photo-readonly"));
    const fallbackRow = form ? contactFromDialogForm(form) : {};
    const avatarSrc = source.dataset.avatarSrc || widget?.querySelector(".identity-photo-frame")?.dataset.avatarSrc || identityAvatarSrc(fallbackRow);
    let pendingPhoto = dataUrl;
    const overlay = document.createElement("div");
    overlay.className = "identity-photo-lightbox";
    overlay.innerHTML = `<div class="identity-photo-lightbox-panel" role="dialog" aria-modal="true" aria-label="Photo d'identité">
      <button class="icon identity-photo-lightbox-close" type="button" data-photo-lightbox-close title="Fermer" aria-label="Fermer">×</button>
      <div class="identity-photo-lightbox-image">
        <img src="${esc(isImageDataUrl(dataUrl) ? dataUrl : avatarSrc)}" alt="${isImageDataUrl(dataUrl) ? "Photo d'identité" : "Silhouette automatique"}" />
      </div>
      ${editable ? `<div class="identity-photo-lightbox-actions">
        <label class="button-like">Modifier<input type="file" accept="image/*" data-lightbox-identity-photo-file hidden /></label>
        <button type="button" class="danger" data-lightbox-remove-photo ${isImageDataUrl(dataUrl) ? "" : "hidden"}>Retirer</button>
        <button type="button" class="primary" data-lightbox-validate-photo disabled>Valider la photo</button>
      </div>` : ""}
    </div>`;
    const close = () => overlay.remove();
    const renderPendingPhoto = () => {
      const imageBox = overlay.querySelector(".identity-photo-lightbox-image");
      if (!imageBox) return;
      imageBox.innerHTML = `<img src="${esc(isImageDataUrl(pendingPhoto) ? pendingPhoto : avatarSrc)}" alt="${isImageDataUrl(pendingPhoto) ? "Photo d'identité" : "Silhouette automatique"}" />`;
      const remove = overlay.querySelector("[data-lightbox-remove-photo]");
      if (remove) remove.hidden = !isImageDataUrl(pendingPhoto);
      const validate = overlay.querySelector("[data-lightbox-validate-photo]");
      if (validate) validate.disabled = pendingPhoto === dataUrl;
    };
    overlay.addEventListener("click", (event) => {
      if (event.target === overlay || event.target.closest("[data-photo-lightbox-close]")) close();
    });
    overlay.querySelector("[data-lightbox-remove-photo]")?.addEventListener("click", () => {
      pendingPhoto = "";
      renderPendingPhoto();
    });
    overlay.querySelector("[data-lightbox-validate-photo]")?.addEventListener("click", () => {
      setIdentityPhotoInForm(form, pendingPhoto);
      close();
    });
    overlay.querySelector("[data-lightbox-identity-photo-file]")?.addEventListener("change", async (event) => {
      const file = event.target.files?.[0];
      if (!file) return;
      if (!file.type.startsWith("image/")) {
        alert("Choisis un fichier image.");
        event.target.value = "";
        return;
      }
      pendingPhoto = await identityPhotoFileToDataUrl(file);
      renderPendingPhoto();
      event.target.value = "";
    });
    (dialog.open ? dialog : document.body).appendChild(overlay);
  }

  function addSizeStockRow(source) {
    const form = source.closest("form");
    const list = form?.querySelector("[data-size-stock-list]");
    if (!list) return;
    const index = list.querySelectorAll("[data-size-stock-row]").length;
    list.insertAdjacentHTML("beforeend", sizeStockRow("", "", index));
    enhanceNumberSteppers(list);
    updateSizeStockDialogTotal(form);
  }

  function removeSizeStockRow(source) {
    const row = source.closest("[data-size-stock-row]");
    const form = source.closest("form");
    const list = form?.querySelector("[data-size-stock-list]");
    if (row && list?.querySelectorAll("[data-size-stock-row]").length > 1) row.remove();
    else if (row) row.querySelectorAll("input").forEach((input) => { input.value = ""; });
    updateSizeStockDialogTotal(form);
  }

  // Lot Contact V2 — responsable légal directement sur la fiche contact (mineur). Mêmes 3 champs
  // texte que ceux déjà utilisés côté membership (openMembershipDialog), même pattern de bascule
  // via un marqueur désactivable (guardianFieldsEditable) pour préserver la valeur existante quand
  // la section est masquée (contact majeur). Aucune synchronisation avec la membership dans ce lot.
  function contactLegalGuardianSectionHtml(row = {}) {
    const isChild = memberCategory(row) === "Enfant";
    // Lot polish Contact V2 — un seul bloc plein largeur (titre + aide + champs), au lieu de deux
    // éléments séparés qui se retrouvaient dispersés dans la grille du formulaire.
    return `<input type="hidden" name="guardianFieldsEditable" value="1" data-guardian-marker ${isChild ? "" : "disabled"} />
      <div class="dialog-section contact-guardian-section" data-contact-guardian ${isChild ? "" : "hidden"}>
        <h3>Responsable légal</h3>
        <p class="muted">Obligatoire pour les mineurs. Utilisé pour la facturation et les documents.</p>
        <div class="form-grid compact">
          ${field("legalGuardianName", "Responsable légal — nom", row.legalGuardianName || "")}
          ${field("legalGuardianPhone", "Responsable légal — téléphone", row.legalGuardianPhone || "")}
          ${field("legalGuardianEmail", "Responsable légal — e-mail", row.legalGuardianEmail || "", "email")}
        </div>
      </div>`;
  }

  // Lot Contact/Dossier V2 — autorisation parentale (mineur uniquement, même règle de masquage que
  // le responsable légal) et droit à l'image (tous contacts, adulte compris — déjà le comportement
  // existant côté membership) centralisés sur le contact. Réutilise le marqueur guardianFieldsEditable
  // déjà présent (même contrainte "hidden si adulte confirmé") plutôt que d'en créer un second.
  function contactAdminInfoSectionHtml(row = {}) {
    const isChild = memberCategory(row) === "Enfant";
    return `<div class="dialog-section contact-admin-section">
      <h3>Informations administratives</h3>
      <p class="muted">Ces informations concernent la personne et s'appliquent à ses inscriptions.</p>
      <div class="form-check-grid">
        <label class="form-check" data-contact-parental ${isChild ? "" : "hidden"}><input type="checkbox" name="parentalAuthorization" ${row.parentalAuthorization ? "checked" : ""} /> Autorisation parentale</label>
        <label class="form-check"><input type="checkbox" name="imageRights" ${row.imageRights ? "checked" : ""} /> Droit à l'image</label>
        <label class="form-check"><input type="checkbox" name="rulesSigned" ${row.rulesSigned ? "checked" : ""} /> Règlement signé</label>
      </div>
    </div>`;
  }

  function openContactDialog(kind, row = {}) {
    const isMember = kind === "members";
    const body = [
      row.id ? `<div hidden data-contact-dialog-kind="${esc(kind)}" data-contact-dialog-id="${esc(row.id)}"></div>` : "",
      identityPhotoSection(row),
      identityAvatarChoiceField(row),
      field("lastName", "Nom *", row.lastName, "text", 'required data-tour="contact-lastname"'),
      field("firstName", "Prénom *", row.firstName, "text", 'required data-tour="contact-firstname"'),
      field("email", "E-mail", row.email, "email", 'data-tour="contact-email"'),
      field("mobile", "Portable", row.mobile, "text", 'data-tour="contact-mobile"'),
      field("phone", "Téléphone fixe", row.phone),
      field("city", "Ville", row.city, "text"),
      field("postalCode", "CP", row.postalCode, "text"),
      field("address", "Adresse", row.address, "text", 'data-tour="contact-address"'),
      field("birthDate", "Date de naissance", dateInputValue(row.birthDate), "date", "data-birth-date"),
      field("category", "Adulte / Enfant", memberCategory(row), "text", "readonly data-birth-category"),
      contactLegalGuardianSectionHtml(row),
      contactAdminInfoSectionHtml(row),
      isMember ? field("birthPlace", "Lieu de naissance", row.birthPlace) : "",
      isMember ? field("nationality", "Nationalité", row.nationality) : "",
      contactDocumentsSection(row),
      contactActivitySummary(kind, row),
      row.id ? `<div class="dialog-section contact-dialog-actions" data-tour="contact-delete">
        <button class="danger" type="button" data-action="delete-contact" data-kind="${esc(kind)}" data-id="${esc(row.id)}">${isMember ? "Supprimer l'adhérent" : "Supprimer le contact"}</button>
      </div>` : "",
    ].join("");
    setNextWindowKey(row.id ? `contact:${row.id}` : null);
    showDialog(row.id ? "Modifier le contact" : "Nouveau contact", body, async (form, formElement) => {
      if (!validateRequiredContactLike(form, ["lastName", "firstName", "contactMethod"], "Renseignez le nom, le prénom et au moins un moyen de contact (téléphone ou e-mail).")) return false;
      const target = state.contacts[kind];
      const birthDate = form.get("birthDate") || "";
      const keptDocumentIds = new Set([...formElement.querySelectorAll('input[name="existingDocuments"]')].map((input) => input.value));
      const documents = [
        ...normalizeContactDocuments(row.documents).filter((doc) => keptDocumentIds.has(doc.id)),
        ...pendingContactDocuments(formElement),
      ];
      const next = {
        ...row,
        id: row.id || id(kind === "members" ? "member" : "prospect"),
        lastName: form.get("lastName"),
        firstName: form.get("firstName"),
        email: form.get("email"),
        mobile: form.get("mobile"),
        phone: form.get("phone"),
        city: form.get("city"),
        postalCode: form.get("postalCode"),
        address: form.get("address"),
        birthDate,
        category: isMember ? memberCategory({ birthDate, category: row.category }) : form.get("category") || row.category || "Non-membre",
        identityAvatarChoice: normalizeIdentityAvatarChoice(form.get("identityAvatarChoice")),
        birthPlace: form.get("birthPlace") || "",
        nationality: form.get("nationality") || "",
        identityPhotoDataUrl: isImageDataUrl(form.get("identityPhotoDataUrl")) ? form.get("identityPhotoDataUrl") : "",
        documents,
        documentsText: form.get("documentsText") || "",
        // Lot Contact V2 — préserve les valeurs existantes quand la section est masquée (majeur),
        // même pattern que le dossier sportif de la membership.
        legalGuardianName: form.get("guardianFieldsEditable") ? asText(form.get("legalGuardianName")) : asText(row.legalGuardianName),
        legalGuardianPhone: form.get("guardianFieldsEditable") ? asText(form.get("legalGuardianPhone")) : asText(row.legalGuardianPhone),
        legalGuardianEmail: form.get("guardianFieldsEditable") ? asText(form.get("legalGuardianEmail")) : asText(row.legalGuardianEmail),
        // Lot Contact/Dossier V2 — autorisation parentale : préserve la valeur existante quand
        // masquée (majeur), même marqueur que le responsable légal. Droit à l'image : jamais masqué.
        parentalAuthorization: form.get("guardianFieldsEditable") ? Boolean(form.get("parentalAuthorization")) : Boolean(row.parentalAuthorization),
        imageRights: Boolean(form.get("imageRights")),
        // Lot Contact/Dossier V2 (règlement) — jamais masqué, comme le droit à l'image.
        rulesSigned: Boolean(form.get("rulesSigned")),
      };
      upsert(target, next);
      // Action secondaire en attente (boutons Disciplines / Stages / Boutique / Facture cliqués depuis
      // un NOUVEAU contact) : on fournit le lien du contact désormais créé pour que showDialog ouvre
      // l'action sur ce contact après la sauvegarde. Réutilise le mécanisme follow-up existant.
      if (formElement.dataset.followUpAction) {
        formElement.dataset.followUpData = `${kind === "members" ? "member" : "prospect"}:${next.id}`;
      }
      return `${row.id ? "Modification" : "Création"} de la fiche contact de ${personLabel(next)}`;
    }, updateBirthCategoryFields, contactModuleLinks(kind, row));
  }

  function contactDocumentsSection(row = {}) {
    const documents = normalizeContactDocuments(row.documents);
    return `<div class="dialog-section contact-documents">
      <h3>Documents</h3>
      <p class="muted">Certificat, licence, autorisation parentale, justificatif ou autre document utile.</p>
      <div class="contact-doc-list" data-contact-doc-list>
        ${documents.length ? documents.map(contactDocumentItemHtml).join("") : `<div class="empty compact" data-empty-documents>Aucun document joint.</div>`}
      </div>
      <label>Ajouter des documents<input type="file" name="contactDocuments" multiple /></label>
      ${textareaField("documentsText", "Notes documents", row.documentsText || "")}
    </div>`;
  }

  function contactDocumentItemHtml(doc, pending = false) {
    const payload = pending ? `<input type="hidden" name="pendingDocuments" value="${esc(JSON.stringify(doc))}" />` : `<input type="hidden" name="existingDocuments" value="${esc(doc.id)}" />`;
    return `<div class="contact-doc-item" data-contact-document>
      ${payload}
      <a href="${esc(doc.dataUrl)}" target="_blank" rel="noopener" title="Ouvrir le document">${esc(doc.name)}<span>${esc(dateDisplay(doc.addedAt))}</span></a>
      <button type="button" data-action="open-contact-document">Lire</button>
      <button type="button" class="danger" data-action="remove-contact-document">Retirer</button>
    </div>`;
  }

  function pendingContactDocuments(formElement) {
    return [...formElement.querySelectorAll('input[name="pendingDocuments"]')]
      .map((input) => {
        try {
          return normalizeContactDocuments([JSON.parse(input.value)])[0] || null;
        } catch (error) {
          return null;
        }
      })
      .filter(Boolean);
  }

  async function previewContactDocumentFiles(input) {
    const list = input.closest(".contact-documents")?.querySelector("[data-contact-doc-list]");
    if (!list) return;
    list.querySelector("[data-empty-documents]")?.remove();
    for (const doc of await filesToContactDocuments(input.files || [])) {
      list.insertAdjacentHTML("beforeend", contactDocumentItemHtml(doc, true));
    }
    input.value = "";
  }

  function removeContactDocument(button) {
    const item = button.closest("[data-contact-document]");
    item?.remove();
    const list = button.closest(".contact-documents")?.querySelector("[data-contact-doc-list]");
    if (list && !list.querySelector("[data-contact-document]")) {
      list.innerHTML = `<div class="empty compact" data-empty-documents>Aucun document joint.</div>`;
    }
  }

  async function filesToContactDocuments(files = []) {
    const rows = [];
    for (const file of [...files]) {
      rows.push({
        id: id("doc"),
        name: file.name || "Document",
        type: file.type || "application/octet-stream",
        dataUrl: await fileToDataUrl(file),
        addedAt: new Date().toISOString(),
      });
    }
    return rows;
  }

  // Lot Contact/Discipline V2 — résumé lecture seule du responsable légal dans le formulaire
  // Discipline/Inscription : `contact` est la source de vérité (déjà lue par la facturation),
  // `row` est l'inscription (pour la seule note "ancienne information", en lecture seule aussi).
  function membershipGuardianSummaryHtml(row = {}, contact = {}) {
    const name = asText(contact.legalGuardianName);
    const coords = [asText(contact.legalGuardianPhone), asText(contact.legalGuardianEmail)].filter(Boolean).map(esc).join(" · ");
    const info = name
      ? `<div><strong>${esc(name)}</strong>${coords ? ` <span class="muted">(${coords})</span>` : ""}</div>`
      : `<p class="muted">Responsable légal non renseigné sur la fiche contact.</p>`;
    // Note douce si cette inscription porte encore une ancienne valeur différente de celle du
    // contact (ou présente alors que le contact est vide) — jamais copiée ni écrasée automatiquement.
    const legacyDiffers = ["legalGuardianName", "legalGuardianPhone", "legalGuardianEmail"].some((key) => {
      const value = asText(row[key]);
      return value && value !== asText(contact[key]);
    });
    const legacyNote = legacyDiffers
      ? `<p class="muted">Ancienne information présente sur cette inscription. À reporter sur la fiche contact.</p>`
      : "";
    const linkBtn = contactLinkAction(row, "Modifier sur la fiche contact");
    return `${info}${legacyNote}
      <p class="muted">Le responsable légal se renseigne sur la fiche contact du mineur. Il est utilisé pour la facturation et les documents.</p>
      ${linkBtn}`;
  }

  // Lot Contact/Dossier V2 — résumé lecture seule autorisation parentale / droit à l'image, même
  // principe que le responsable légal : le contact est la source de vérité, la membership ne
  // propose plus ces cases éditables. Autorisation parentale masquée pour un adulte confirmé (déjà
  // couvert par la note "Adhérent majeur..." affichée à côté) ; droit à l'image toujours affiché.
  function membershipAdminInfoSummaryHtml(row = {}, contact = {}, isConfirmedAdult = false) {
    const parentalLine = isConfirmedAdult ? "" : `<div>Autorisation parentale : <strong>${contact.parentalAuthorization ? "Oui" : "Non renseignée sur la fiche contact"}</strong></div>`;
    const imageLine = `<div>Droit à l'image : <strong>${contact.imageRights ? "Oui" : "Non renseigné sur la fiche contact"}</strong></div>`;
    // Lot Contact/Dossier V2 (règlement) — même principe, intégré à ce résumé existant.
    const rulesLine = `<div>Règlement signé : <strong>${contact.rulesSigned ? "Oui" : "Non renseigné sur la fiche contact"}</strong></div>`;
    const legacyDiffers = ["parentalAuthorization", "imageRights", "rulesSigned"].some((key) => Boolean(row[key]) && Boolean(row[key]) !== Boolean(contact[key]));
    const legacyNote = legacyDiffers
      ? `<p class="muted">Ancienne information présente sur cette inscription. À reporter sur la fiche contact.</p>`
      : "";
    const linkBtn = contactLinkAction(row, "Modifier sur la fiche contact");
    return `${parentalLine}${imageLine}${rulesLine}${legacyNote}
      <p class="muted">Ces informations se renseignent sur la fiche contact.</p>
      ${linkBtn}`;
  }

  function openMembershipDialog(row = {}) {
    // Snapshot des paiements AVANT ouverture (copie profonde, jamais une référence vers state) —
    // même principe que openOrderDialog : vide si l'inscription est neuve.
    const originalMembershipId = row.id || "";
    const beforeMembershipPayments = clone(row.payments || []);
    const contact = contactForMembership(row) || {};
    row = {
      ...row,
      email: row.email || contact.email || "",
      mobile: row.mobile || contact.mobile || "",
      phone: row.phone || contact.phone || "",
      address: row.address || contact.address || "",
      postalCode: row.postalCode || contact.postalCode || "",
      city: row.city || contact.city || "",
      birthDate: dateInputValue(row.birthDate || contact.birthDate || ""),
      category: memberCategory({ birthDate: row.birthDate || contact.birthDate, category: row.category || contact.category || "" }),
      identityPhotoDataUrl: row.identityPhotoDataUrl || contact.identityPhotoDataUrl || "",
      identityAvatarChoice: row.identityAvatarChoice || contact.identityAvatarChoice || "auto",
    };
    // Dossier sportif : autorisation parentale et responsable légal ne concernent que les mineurs.
    // Adulte CONFIRMÉ (date de naissance connue et >= 18 ans) -> on masque ces champs. Mineur ou âge
    // inconnu -> on les affiche (prudent). La cohérence avec les alertes : isMinor (age<18) gère déjà
    // l'alerte « Autorisation parentale manquante » (jamais pour un adulte ni un âge inconnu).
    const dossierAge = getMemberAge(row);
    const isConfirmedAdult = dossierAge !== null && dossierAge >= 18;
    const body = [
      identityPhotoSection(row),
      identityAvatarChoiceField(row),
      customerSelectField(row, "Contact enregistré", "Nouvel adhérent / saisir une fiche"),
      field("lastName", "Nom *", row.lastName, "text", "required"),
      field("firstName", "Prénom *", row.firstName, "text", "required"),
      field("email", "E-mail *", row.email, "email", "required"),
      field("mobile", "Téléphone *", row.mobile || row.phone, "text", "required"),
      field("address", "Adresse *", row.address, "text", "required"),
      field("postalCode", "CP *", row.postalCode, "text", "required"),
      field("city", "Ville *", row.city, "text", "required"),
      field("birthDate", "Date de naissance *", dateInputValue(row.birthDate), "date", "required data-birth-date"),
      field("category", "Adulte / Enfant", memberCategory(row), "text", "readonly data-birth-category"),
      selectField("discipline", "Discipline *", row.discipline, ["", ...state.tariffs.disciplines.map((item) => item.name)]),
      `<input type="hidden" name="frozenDiscipline" value="${esc(row.discipline || "")}" />
       <input type="hidden" name="frozenDisciplinePrice" value="${esc(membershipDisciplinePricing(row).grossTotal)}" />
       <input type="hidden" name="frozenDisciplineLicense" value="${esc(membershipDisciplinePricing(row).license)}" />`,
      selectField("medicalCertificate", "Certificat médical", row.medicalCertificate ? "Oui" : "Non", ["Non", "Oui"]),
      textareaField("pathologies", "Pathologie(s)", row.pathologies || ""),
      `<div class="dialog-section"><h3>Dossier sportif</h3></div>`,
      `<label>Groupe<select name="groupId"><option value="">—</option>${(state.groups || []).filter((g) => !g.archived).map((g) => `<option value="${esc(g.id)}" ${row.groupId === g.id ? "selected" : ""}>${esc(g.name)}</option>`).join("")}</select></label>`,
      // Lot V1 Niveaux — note libre assumée (pas de select, pas d'automatisme, cf. audit
      // Niveaux/Groupes/Disciplines) : libellé et placeholder rendent explicite qu'il s'agit
      // d'une indication saisie librement, affichée ensuite dans le récap de cette inscription.
      `<div class="form-grid compact">${field("level", "Niveau / grade (note libre)", row.level || "", "text", 'placeholder="Ex. Débutant, Confirmé, Ceinture jaune"')}${selectField("practiceType", "Type de pratique", row.practiceType || "", ["", "Loisir", "Compétition", "Stage", "Autre"])}</div>`,
      `<div class="form-grid compact">${field("licenseNumber", "N° de licence", row.licenseNumber || "")}${field("licenseFederation", "Fédération", row.licenseFederation || "")}</div>`,
      `<div class="form-grid compact">${field("licenseStartDate", "Licence — début", dateInputValue(row.licenseStartDate), "date")}${field("licenseEndDate", "Licence — expiration", dateInputValue(row.licenseEndDate), "date")}</div>`,
      `<div class="form-grid compact">${field("medicalCertificateDate", "Certificat — date", dateInputValue(row.medicalCertificateDate), "date")}${field("medicalCertificateEndDate", "Certificat — expiration", dateInputValue(row.medicalCertificateEndDate), "date")}</div>`,
      `<div class="form-grid compact">${field("emergencyName", "Urgence — nom", row.emergencyName || "")}${field("emergencyPhone", "Urgence — téléphone", row.emergencyPhone || "")}${field("emergencyRelation", "Urgence — lien", row.emergencyRelation || "")}</div>`,
      // Lot Contact/Discipline V2 — le contact est la source de vérité du responsable légal : ce
      // bloc n'a plus de champs éditables, seulement un résumé lecture seule (+ lien vers la fiche
      // contact), recalculé par updateDossierGuardianFields() à chaque changement de date de
      // naissance ou de contact lié.
      // Lot Contact/Dossier V2 — même principe étendu à l'autorisation parentale, au droit à
      // l'image, puis (lot règlement) au règlement signé : plus de cases éditables ici, résumé
      // lecture seule dans son propre bloc. Seule l'assurance reste éditable dans ce formulaire.
      `<div class="dialog-section" data-dossier-guardian ${isConfirmedAdult ? "hidden" : ""}>
         <h3>Responsable légal</h3>
         <div data-dossier-guardian-body>${membershipGuardianSummaryHtml(row, contact)}</div>
       </div>
       <p class="muted dossier-adult-note" data-dossier-adult-note ${isConfirmedAdult ? "" : "hidden"}>Adhérent majeur : autorisation parentale et responsable légal non requis.</p>
       <div class="dialog-section">
         <h3>Informations administratives</h3>
         <div data-dossier-admin-body>${membershipAdminInfoSummaryHtml(row, contact, isConfirmedAdult)}</div>
       </div>`,
      `<div class="form-check-grid">
        <label class="form-check"><input type="checkbox" name="insurance" ${row.insurance ? "checked" : ""} /> Assurance</label>
      </div>`,
      contactDocumentsSection(row),
      `<label>Assurance<select name="insuranceChoice">${insuranceChoiceOptions(membershipInsuranceChoice(row))}</select></label>`,
      readonlyMoneyField("Prix assurance", membershipInsurancePrice(row), "data-membership-insurance-price"),
      `<div class="dialog-section"><h3>Paiements discipline</h3></div>`,
      readonlyMoneyField("Prix discipline", membershipTariffValues(row).grossTotal, "data-membership-discipline-price"),
      field("discount", "Remise", row.discount || "", "number", 'step="0.01"'),
      `<div class="dialog-alert-list" data-membership-alerts></div>`,
      membershipTariffSummary(row),
      paymentFields("payment", row.payments || [], membershipTariffValues(row).total, membershipDefaultTaxRate(row)),
    ].join("");
    const footer = contactLinkAction(row);
    setNextWindowKey(row.id ? `membership:${row.id}` : null);
    showDialog(row.id ? "Modifier l'inscription" : "Nouvelle inscription", body, (form, formElement) => {
      if (!validateRequiredContactLike(form, ["discipline", "lastName", "firstName", "email", "mobile", "address", "postalCode", "city", "birthDate"], "Veuillez remplir tous les champs obligatoires avant d'enregistrer l'inscription.")) return false;
      const keptDocumentIds = new Set([...formElement.querySelectorAll('input[name="existingDocuments"]')].map((input) => input.value));
      const documents = [
        ...normalizeContactDocuments(row.documents).filter((doc) => keptDocumentIds.has(doc.id)),
        ...pendingContactDocuments(formElement),
      ];
      const insuranceChoice = insuranceChoiceByKey(form.get("insuranceChoice"));
      const contactLink = parseContactLink(form.get("contactLink"));
      const birthDate = form.get("birthDate") || "";
      const selectedDiscipline = asText(form.get("discipline"));
      const disciplineUnchanged = Boolean(row.id) && asText(form.get("frozenDiscipline")) === selectedDiscipline && asText(form.get("frozenDisciplinePrice")) !== "";
      const disciplineDef = disciplineByName(selectedDiscipline);
      const frozenPrice = disciplineUnchanged ? asNumber(form.get("frozenDisciplinePrice")) : asNumber(disciplineDef.price);
      const frozenLicense = disciplineUnchanged ? asNumber(form.get("frozenDisciplineLicense")) : asNumber(disciplineDef.license);
      const next = {
        ...row,
        id: row.id || id("membership"),
        disciplinePrice: frozenPrice,
        disciplineLicense: frozenLicense,
        contactId: contactLink.kind === "member" ? contactLink.contactId : row.contactId || "",
        lastName: form.get("lastName"),
        firstName: form.get("firstName"),
        email: form.get("email"),
        mobile: form.get("mobile"),
        phone: form.get("mobile"),
        address: form.get("address"),
        postalCode: form.get("postalCode"),
        city: form.get("city"),
        birthDate,
        category: memberCategory({ birthDate, category: row.category }),
        identityPhotoDataUrl: isImageDataUrl(form.get("identityPhotoDataUrl")) ? form.get("identityPhotoDataUrl") : "",
        identityAvatarChoice: normalizeIdentityAvatarChoice(form.get("identityAvatarChoice")),
        discipline: form.get("discipline"),
        medicalCertificate: form.get("medicalCertificate") === "Oui",
        discount: asNumber(form.get("discount")),
        pathologies: form.get("pathologies"),
        insuranceChoice: form.get("insuranceChoice") || "",
        insuranceCategory: insuranceChoice?.category || "",
        insuranceLabel: insuranceChoice?.label || "",
        insurancePrice: asNumber(insuranceChoice?.price),
        payments: readPayments(form, "payment", formElement),
        // Dossier sportif
        groupId: form.get("groupId") || "",
        level: asText(form.get("level")),
        practiceType: form.get("practiceType") || "",
        licenseNumber: asText(form.get("licenseNumber")),
        licenseFederation: asText(form.get("licenseFederation")),
        licenseStartDate: form.get("licenseStartDate") || "",
        licenseEndDate: form.get("licenseEndDate") || "",
        medicalCertificateDate: form.get("medicalCertificateDate") || "",
        medicalCertificateEndDate: form.get("medicalCertificateEndDate") || "",
        emergencyName: asText(form.get("emergencyName")),
        emergencyPhone: asText(form.get("emergencyPhone")),
        emergencyRelation: asText(form.get("emergencyRelation")),
        // Lot Contact/Discipline V2 — responsable légal : le contact est la seule source de vérité,
        // ce formulaire n'a plus de champs éditables pour legalGuardianName/Phone/Email (résumé
        // lecture seule uniquement) -> on préserve systématiquement la valeur déjà présente sur
        // cette inscription, sans jamais l'écraser ni tenter de la synchroniser depuis le contact.
        legalGuardianName: asText(row.legalGuardianName),
        legalGuardianPhone: asText(row.legalGuardianPhone),
        legalGuardianEmail: asText(row.legalGuardianEmail),
        // Lot Contact/Dossier V2 — autorisation parentale, droit à l'image et règlement signé :
        // plus de champs éditables ici (résumé lecture seule uniquement) -> on préserve
        // systématiquement la valeur déjà présente sur cette inscription, sans jamais l'écraser ni
        // la synchroniser depuis le contact. Assurance : reste éditable, inchangée.
        parentalAuthorization: Boolean(row.parentalAuthorization),
        imageRights: Boolean(row.imageRights),
        rulesSigned: Boolean(row.rulesSigned),
        insurance: Boolean(form.get("insurance")),
        documents,
        documentsText: asText(form.get("documentsText")),
      };
      if (!asText(next.discipline)) {
        const prospect = {
          ...next,
          prospectContactId: contactLink.kind === "prospect" ? contactLink.contactId : row.prospectContactId || "",
          phone: next.mobile || next.phone || "",
          category: "Non-membre",
        };
        const prospectId = syncProspectContact(prospect, row);
        if (row.id) removeById(state.memberships, row.id);
        const demoted = demoteMemberContactIfNoDiscipline(next.contactId || row.contactId, prospectId, next);
        return demoted
          ? {
            message: `${personLabel(next)} devient non-adhérent`,
            notice: `${personLabel(next)} est devenu non-adhérent.`,
          }
          : `${personLabel(next)} est enregistré en non-adhérent`;
      }
      next.contactId = syncMemberContact(next, row);
      // Un même adhérent ne doit pas cumuler deux inscriptions dont les cours hebdomadaires se
      // chevauchent le même jour (ex. Judo enfants + Self-défense au même horaire) : blocage à
      // l'enregistrement, avant toute écriture dans state.memberships. row.id exclut l'inscription
      // en cours d'édition (ne jamais se bloquer elle-même).
      const scheduleConflictMessage = memberScheduleConflictMessage(next.contactId, next.groupId, row.id);
      if (scheduleConflictMessage) {
        alert(scheduleConflictMessage);
        return false;
      }
      const promoted = contactLink.kind === "prospect" && promoteProspectContactToMember(contactLink.contactId, next.contactId);
      upsert(state.memberships, next);
      // Journalisation UNIQUEMENT si l'inscription existait déjà avant l'ouverture (jamais pour une
      // création, jamais dans la branche de démotion ci-dessus qui supprime l'inscription).
      if (originalMembershipId) {
        logPaymentAuditTransitions(paymentAuditTransitions(beforeMembershipPayments, next.payments), { module: "membership", id: next.id });
      }
      return promoted ? {
        message: `Inscription de ${personLabel(next)} à la discipline ${next.discipline}`,
        notice: `${personLabel(next)} est devenu adhérent.`,
      } : `${row.id ? "Modification de l'inscription" : "Inscription"} de ${personLabel(next)} à la discipline ${next.discipline}`;
    }, (form) => {
      const update = () => {
        updateMembershipTariffSummary(form);
        updateMembershipFormAlerts(form);
      };
      form.elements.contactLink?.addEventListener("change", () => {
        applyLinkedContactToForm(form);
        updateDossierGuardianFields(form, row); // recalcul enfant/adulte + résumé au changement de contact
      });
      updateBirthCategoryFields(form);
      // Recalcule l'affichage parental/responsable légal quand la date de naissance change.
      form.elements.birthDate?.addEventListener("input", () => updateDossierGuardianFields(form, row));
      form.elements.birthDate?.addEventListener("change", () => updateDossierGuardianFields(form, row));
      updateDossierGuardianFields(form, row); // état initial cohérent
      form.elements.discipline?.addEventListener("change", update);
      form.elements.insuranceChoice?.addEventListener("change", update);
      form.elements.medicalCertificate?.addEventListener("change", update);
      form.elements.discount?.addEventListener("input", update);
      update();
    }, footer);
  }

  function updateMembershipFormAlerts(form) {
    const box = form.querySelector("[data-membership-alerts]");
    if (!box) return;
    const rows = [];
    // Tarif « à définir » (discipline seedée par le wizard, prix vide) : note douce, non bloquante.
    // Uniquement si price === "" — un 0 explicite (gratuité voulue) ne déclenche jamais cette note.
    const selDiscipline = asText(form.elements.discipline?.value);
    if (selDiscipline && disciplineByName(selDiscipline).price === "") rows.push("Tarif à définir : pensez à compléter le tarif de cette discipline avant de facturer.");
    if (form.elements.medicalCertificate?.value !== "Oui") rows.push("Attention : le certificat médical n'a pas encore été fourni.");
    if (!asText(form.elements.insuranceChoice?.value)) rows.push("Attention : pensez à vérifier que le membre possède une assurance.");
    box.innerHTML = rows.map((text) => `<div class="form-warning">${esc(text)}</div>`).join("");
  }

  function orderArticleEditorRow(article, item = {}, stock = {}) {
    const currentQuantity = asNumber(item.quantity);
    const availableForOrder = asNumber(stock?.available) + currentQuantity;
    return `<tr data-order-line="${esc(article.id)}" data-order-had-quantity="${currentQuantity > 0 ? "true" : "false"}">
      <td><div class="shop-editor-article">${articleImage(article, "tiny")}<div><strong>${esc(article.name || "Article")}</strong><span>${esc(article.reference || "")}</span></div></div></td>
      <td class="money">${intValue(availableForOrder)}</td>
      <td>${orderSizeEditor(article, item, stock)}</td>
      <td><input name="price_${esc(article.id)}" data-order-summary-input data-order-price="${esc(article.id)}" class="locked-price" type="number" step="0.01" value="${esc(item.unitPrice ?? article.priceOptions?.[0] ?? article.defaultPrice ?? "")}" readonly title="Prix défini dans la page Tarifs" /></td>
      <td><button class="icon danger" type="button" title="Retirer cet article" data-clear-order-line="${esc(article.id)}">×</button></td>
    </tr>`;
  }

  function updateOrderStockIndicators(form) {
    form?.querySelectorAll("[data-order-stock-input]").forEach((input) => {
      const quantity = asNumber(input.value);
      if (input.dataset.stockAvailable === "") return;
      const available = asNumber(input.dataset.stockAvailable);
      const threshold = asNumber(input.dataset.stockThreshold);
      const rest = available - quantity;
      const message = input.closest(".order-stock-control, .order-size-pill")?.querySelector("[data-order-stock-message]");
      input.classList.remove("stock-qty-warning", "stock-qty-danger");
      if (message) {
        message.textContent = "";
        message.className = "";
        message.dataset.orderStockMessage = "";
      }
      if (!quantity) return;
      if (quantity > available) {
        input.classList.add("stock-qty-danger");
        if (message) {
          message.className = "stock-message danger";
          message.textContent = "Stock insuffisant";
        }
      } else if (threshold > 0 && rest < threshold) {
        input.classList.add("stock-qty-warning");
        if (message) {
          message.className = "stock-message warning";
          message.textContent = "Stock faible";
        }
      }
    });
  }

  function orderArticlePlaceholderRow() {
    return `<tr data-order-empty><td colspan="5" class="empty">Aucun article dans cette commande. Ajoute un article pour le vendre.</td></tr>`;
  }

  function ensureOrderArticlePlaceholder(form) {
    const tbody = form.querySelector("[data-order-article-body]");
    if (tbody && !tbody.querySelector("[data-order-line]")) tbody.innerHTML = orderArticlePlaceholderRow();
  }

  function selectedOrderArticleIds(form) {
    return new Set([...form.querySelectorAll("[data-order-line]")].map((row) => row.dataset.orderLine).filter(Boolean));
  }

  function updateOrderArticleSelect(form) {
    const select = form.elements.addOrderArticle;
    if (!select) return;
    const selectedIds = selectedOrderArticleIds(form);
    const options = state.tariffs.articles
      .filter((article) => !selectedIds.has(article.id))
      .map((article) => `<option value="${esc(article.id)}">${esc(article.name || "Article")} ${article.reference ? `· ${esc(article.reference)}` : ""}</option>`)
      .join("");
    select.innerHTML = `<option value="">Ajouter un article...</option>${options}`;
  }

  function addOrderArticleRow(button) {
    const form = button.closest("form");
    if (!form) return;
    const articleId = form.elements.addOrderArticle?.value;
    const article = articleById(articleId);
    if (!article.id || form.querySelector(`[data-order-line="${CSS.escape(article.id)}"]`)) return;
    const tbody = form.querySelector("[data-order-article-body]");
    const stock = new Map(stockRows().map((item) => [item.article.id, item])).get(article.id) || {};
    tbody?.querySelector("[data-order-empty]")?.remove();
    tbody?.insertAdjacentHTML("beforeend", orderArticleEditorRow(article, {}, stock));
    enhanceNumberSteppers(tbody);
    updateOrderArticleSelect(form);
    updateOrderDialogSummary(form);
  }

  function scrollSaleStep(button) {
    const form = button.closest("form");
    const target = form?.querySelector(`[data-sale-step="${CSS.escape(button.dataset.targetStep || "")}"]`);
    target?.scrollIntoView({ behavior: "smooth", block: "start" });
  }

  function openArticleSaleDialog(articleId) {
    const article = articleById(articleId);
    if (!article.id) return;
    const sizes = article.sizes || [];
    const item = {
      articleId: article.id,
      quantity: sizes.length ? 0 : 1,
      unitPrice: article.priceOptions?.[0] ?? article.defaultPrice ?? 0,
      sizes: sizes.length === 1 ? { [sizes[0]]: 1 } : {},
    };
    if (sizes.length === 1) item.quantity = 1;
    openOrderDialog({ items: [item] });
  }

  function openOrderDialog(row = {}) {
    // Snapshot des paiements AVANT ouverture, pour journaliser (payment.validated/cancelled) les
    // seules transitions réellement persistées à la sauvegarde finale — jamais le clic Payer/Annuler
    // local. Copie profonde (jamais une référence vers state) ; vide si la commande est neuve
    // (row.id absent), auquel cas aucune transition ne sera calculée plus bas.
    const originalOrderId = row.id || "";
    const beforeOrderPayments = clone(row.payments || []);
    const memberContact = contactForOrder(row);
    const prospectContact = prospectForOrder(row);
    const contact = memberContact || prospectContact || {};
    row = {
      ...row,
      contactId: row.contactId || memberContact?.id || "",
      prospectContactId: row.prospectContactId || prospectContact?.id || "",
      lastName: row.lastName || contact.lastName || "",
      firstName: row.firstName || contact.firstName || "",
      email: row.email || contact.email || "",
      phone: row.phone || contact.mobile || contact.phone || "",
      address: row.address || contact.address || "",
      postalCode: row.postalCode || contact.postalCode || "",
      city: row.city || contact.city || "",
    };
    const itemByArticle = new Map((row.items || []).map((item) => [item.articleId, item]));
    const stockByArticle = new Map(stockRows().map((item) => [item.article.id, item]));
    const articleRows = state.tariffs.articles
      .filter((article) => itemByArticle.has(article.id))
      .map((article) => orderArticleEditorRow(article, itemByArticle.get(article.id) || {}, stockByArticle.get(article.id) || {}))
      .join("");
    const calc = calcOrder(row);
    const quantity = orderItemDetails(row).reduce((sum, item) => sum + item.quantity, 0);
    const orderSummary = `<div class="dialog-section tariff-summary order-dialog-summary" data-order-dialog-summary>
      <h3>Total commande</h3>
      <div class="tariff-summary-grid">
        <div><span>Articles</span><strong data-order-summary-value="quantity">${intValue(quantity)}</strong></div>
        <div><span>Total à payer</span><strong data-order-summary-value="total">${money(calc.total)}</strong></div>
        <div><span>Réglé</span><strong data-order-summary-value="paid">${money(calc.paid)}</strong></div>
        <div><span>Reste dû</span><strong data-order-summary-value="due">${money(calc.restDue)}</strong></div>
      </div>
      <div class="order-summary-items" data-order-summary-items>${orderSummaryItemsPreview(row)}</div>
    </div>`;
    const body = [
      `<div class="dialog-section shop-sale-steps">
        <span>1 · Article</span>
        <span>2 · Client</span>
        <span>3 · Paiement</span>
      </div>`,
      orderSummary,
      `<div class="dialog-section shop-order-editor" data-sale-step="articles">
        <h3>1 · Choisir l'article, la taille et la quantité</h3>
        <div class="order-add-line">
          <label>Vendre un article<select name="addOrderArticle" data-order-article-select></select></label>
          <button type="button" data-action="add-order-article-row">Ajouter</button>
        </div>
        <div class="dialog-table-wrap"><div class="dialog-table-scroll"><table class="editable-table order-editor-table">
          <thead><tr><th>Article</th><th class="money">Stock</th><th>Quantités par taille</th><th class="money">Prix vente</th><th></th></tr></thead>
          <tbody data-order-article-body>${articleRows || orderArticlePlaceholderRow()}</tbody>
        </table></div></div>
        <div class="sale-step-actions"><button type="button" class="primary" data-action="scroll-sale-step" data-target-step="client">Suivant : client</button></div>
      </div>`,
      `<div class="dialog-section" data-sale-step="client"><h3>2 · Choisir le client</h3>`,
      customerSelectField(row, "Client enregistré", "Vente libre / créer un non-membre"),
      field("lastName", "Nom", row.lastName),
      field("firstName", "Prénom", row.firstName),
      field("email", "E-mail", row.email, "email"),
      field("phone", "Téléphone", row.phone),
      `<label class="wide">Adresse<input name="address" type="text" value="${esc(row.address || "")}" /></label>`,
      field("postalCode", "CP", row.postalCode),
      field("city", "Ville", row.city),
      `<div class="sale-step-actions"><button type="button" class="primary" data-action="scroll-sale-step" data-target-step="payment">Suivant : paiement</button></div></div>`,
      `<div class="dialog-section" data-sale-step="payment"><h3>3 · Valider le paiement</h3>
        <div class="form-grid compact">${field("orderDiscount", "Remise commande", row.discount || "", "number", 'step="0.01" min="0" data-order-summary-input')}</div>
      </div>`,
      paymentFields("payment", row.payments || [], calc.total, orderDefaultTaxRate(row)),
    ].join("");
    const footer = contactLinkAction(row);
    setNextWindowKey(row.id ? `order:${row.id}` : null);
    showDialog(row.id ? "Modifier la commande" : "Nouvelle commande", body, (data, form) => {
      // Garde de MUTATION (Lot 2B) au MOMENT exact de l'enregistrement : bloque toute écriture de
      // commande (et de ses paiements) si la Boutique a été désactivée pendant que ce dialogue
      // restait ouvert, ou après un changement de club. return false -> aucune mutation, aucun persist.
      if (!ensureFeatureEnabledForMutation("shop")) return false;
      const items = state.tariffs.articles
        .map((article) => {
          const sizes = readOrderSizeQuantities(form, article);
          const quantity = orderQuantityFromForm(form, article, sizes);
          const unitPrice = asNumber(data.get(`price_${article.id}`));
          return { articleId: article.id, quantity, unitPrice, sizes };
        })
        .filter((item) => item.quantity);
      const contactLink = parseContactLink(data.get("contactLink"));
      const next = {
        ...row,
        id: row.id || id("order"),
        contactId: contactLink.kind === "member" ? contactLink.contactId : "",
        lastName: data.get("lastName"),
        firstName: data.get("firstName"),
        email: data.get("email"),
        phone: data.get("phone"),
        address: data.get("address"),
        postalCode: data.get("postalCode"),
        city: data.get("city"),
        items,
        discount: asNumber(data.get("orderDiscount")),
        payments: readPayments(data, "payment", form),
      };
      if (contactLink.kind === "prospect") next.prospectContactId = contactLink.contactId;
      else next.prospectContactId = next.contactId ? "" : syncProspectContact(next, row);
      if (next.contactId || next.prospectContactId) updateLinkedContactCoordinates(next);
      upsert(state.shopOrders, next);
      // Journalisation UNIQUEMENT si la commande existait déjà avant l'ouverture (jamais pour une
      // création) et uniquement pour les transitions réellement persistées par cette sauvegarde.
      if (originalOrderId) {
        logPaymentAuditTransitions(paymentAuditTransitions(beforeOrderPayments, next.payments), { module: "order", id: next.id });
      }
      return {
        message: `${row.id ? "Modification" : "Création"} : commande boutique de ${personLabel(next) || "client"}`,
        orderInvoiceFollowUpId: next.id,
      };
    }, (form) => {
      const update = () => updateOrderDialogSummary(form);
      form.elements.contactLink?.addEventListener("change", () => {
        applyLinkedContactToForm(form);
      });
      form.addEventListener("input", (event) => {
        if (event.target.matches("[data-order-summary-input], input[name^='payment'], select[name^='payment']")) update();
      });
      form.addEventListener("change", (event) => {
        if (event.target.matches("[data-order-summary-input], input[name^='payment'], select[name^='payment']")) update();
      });
      form.addEventListener("click", (event) => {
        const clearButton = event.target.closest("[data-clear-order-line]");
        if (!clearButton) return;
        clearButton.closest("[data-order-line]")?.remove();
        ensureOrderArticlePlaceholder(form);
        updateOrderArticleSelect(form);
        update();
      });
      updateOrderArticleSelect(form);
      update();
    }, footer);
  }

  function applyLinkedContactToForm(form) {
    const contact = contactByLink(form.elements.contactLink?.value);
    if (!contact) return;
    if (form.elements.lastName) form.elements.lastName.value = contact.lastName || "";
    if (form.elements.firstName) form.elements.firstName.value = contact.firstName || "";
    if (form.elements.email) form.elements.email.value = contact.email || "";
    if (form.elements.mobile) form.elements.mobile.value = contact.mobile || contact.phone || "";
    if (form.elements.phone) form.elements.phone.value = contact.mobile || contact.phone || "";
    if (form.elements.address) form.elements.address.value = contact.address || "";
    if (form.elements.postalCode) form.elements.postalCode.value = contact.postalCode || "";
    if (form.elements.city) form.elements.city.value = contact.city || "";
    if (form.elements.birthDate) form.elements.birthDate.value = dateInputValue(contact.birthDate);
    if (form.elements.category) form.elements.category.value = memberCategory(contact);
    if (form.elements.identityAvatarChoice) form.elements.identityAvatarChoice.value = identityAvatarChoice(contact);
    setIdentityPhotoInForm(form, contact.identityPhotoDataUrl || "");
  }

  // Dossier sportif : bascule l'affichage responsable légal selon la date de naissance COURANTE du
  // formulaire (recalcul à chaque changement de contact ou de date). Adulte confirmé (>= 18) ->
  // masqué + note. Mineur ou âge inconnu -> visible. UX uniquement : aucune donnée n'est modifiée ici.
  // `row` (l'inscription) sert uniquement à la note "ancienne information" des résumés lecture seule
  // (Lot Contact/Discipline V2 puis Lot Contact/Dossier V2) — le contact affiché, lui, est toujours
  // relu à chaud via le menu déroulant "Contact enregistré", jamais figé depuis l'ouverture du formulaire.
  function updateDossierGuardianFields(form, row = {}) {
    const guardian = form?.querySelector("[data-dossier-guardian]");
    if (!guardian) return; // pas un formulaire avec dossier sportif
    const age = getMemberAge({ birthDate: form.elements.birthDate?.value || "" });
    const isAdult = age !== null && age >= 18;
    guardian.hidden = isAdult;
    const note = form.querySelector("[data-dossier-adult-note]");
    if (note) note.hidden = !isAdult;
    const linkedContact = contactByLink(form.elements.contactLink?.value) || {};
    if (!isAdult) {
      const body = guardian.querySelector("[data-dossier-guardian-body]");
      if (body) body.innerHTML = membershipGuardianSummaryHtml(row, linkedContact);
    }
    // Lot Contact/Dossier V2 — résumé autorisation parentale / droit à l'image : toujours recalculé
    // (le droit à l'image reste affiché même pour un adulte, contrairement au responsable légal).
    const adminBody = form.querySelector("[data-dossier-admin-body]");
    if (adminBody) adminBody.innerHTML = membershipAdminInfoSummaryHtml(row, linkedContact, isAdult);
  }

  function updateBirthCategoryFields(form) {
    const update = () => {
      const birthDate = form.elements.birthDate?.value || "";
      if (form.elements.category) form.elements.category.value = memberCategory({ birthDate });
      // Lot Contact V2 — bascule le bloc "Responsable légal" (titre + aide + champs, un seul
      // conteneur) en direct au changement de date de naissance, sans fermer/rouvrir le formulaire.
      // No-op si le formulaire n'a pas ce bloc (ex. openMembershipDialog, qui gère le sien via
      // updateDossierGuardianFields).
      const guardian = form.querySelector("[data-contact-guardian]");
      if (guardian) {
        const isChild = memberCategory({ birthDate }) === "Enfant";
        guardian.hidden = !isChild;
        const marker = form.querySelector("[data-guardian-marker]");
        if (marker) marker.disabled = !isChild;
        // Lot Contact/Dossier V2 — autorisation parentale masquée/affichée avec la même règle que
        // le responsable légal (même marqueur). Droit à l'image reste toujours visible, non touché ici.
        const parental = form.querySelector("[data-contact-parental]");
        if (parental) parental.hidden = !isChild;
      }
    };
    form.querySelectorAll("[data-birth-date]").forEach((input) => {
      input.addEventListener("input", update);
      input.addEventListener("change", update);
    });
    update();
  }

  function updateOrderDialogSummary(form) {
    const summary = form.querySelector("[data-order-dialog-summary]");
    if (!summary) return;
    const data = new FormData(form);
    let quantity = 0;
    let total = 0;
    const taxSegments = [];
    for (const article of state.tariffs.articles) {
      const qtyInput = form.elements[`qty_${article.id}`];
      const priceInput = form.elements[`price_${article.id}`];
      const sizeValues = readOrderSizeQuantities(form, article);
      const hasSizeInputs = orderHasSizeInputs(form, article);
      const qty = orderQuantityFromForm(form, article, sizeValues);
      const row = form.querySelector(`[data-order-line="${CSS.escape(article.id)}"]`);
      if (row && qty <= 0 && row.dataset.orderHadQuantity === "true") {
        row.remove();
        updateOrderArticleSelect(form);
        ensureOrderArticlePlaceholder(form);
        continue;
      }
      if (row && qty > 0) row.dataset.orderHadQuantity = "true";
      if (qtyInput && hasSizeInputs) qtyInput.value = qty ? String(qty) : "";
      const sizeTotal = form.querySelector(`[data-order-size-total="${CSS.escape(article.id)}"]`);
      if (sizeTotal) {
        sizeTotal.textContent = intValue(qty);
        const summaryText = sizeTotal.parentElement;
        if (summaryText) summaryText.lastChild.textContent = ` article${qty > 1 ? "s" : ""} · tailles`;
      }
      quantity += qty;
      const lineTotal = qty * asNumber(priceInput?.value);
      total += lineTotal;
      if (lineTotal > 0) taxSegments.push({ amount: lineTotal, rate: tariffTaxRate(article) });
    }
    const discount = asNumber(form.elements.orderDiscount?.value);
    total = Math.max(0, total - discount);
    setupAutoPaymentSplit(form, "payment", total);
    setDefaultPaymentTaxRate(form, "payment", blendedTaxRate(taxSegments));
    const paid = paidAmount(readPayments(data, "payment", form));
    summary.querySelector('[data-order-summary-value="quantity"]').textContent = intValue(quantity);
    summary.querySelector('[data-order-summary-value="total"]').textContent = money(total);
    summary.querySelector('[data-order-summary-value="paid"]').textContent = money(paid);
    summary.querySelector('[data-order-summary-value="due"]').textContent = money(total - paid);
    const summaryItems = summary.querySelector("[data-order-summary-items]");
    if (summaryItems) summaryItems.innerHTML = orderFormItemsPreview(form);
    updateOrderStockIndicators(form);
  }

  function orderSummaryItemsPreview(row) {
    const items = orderItemDetails(row);
    if (!items.length) return `<span class="shop-order-item-chip muted">Aucun article sélectionné</span>`;
    return orderItemChips(items);
  }

  function orderFormItemsPreview(form) {
    const items = [];
    form.querySelectorAll("[data-order-line]").forEach((line) => {
      const articleId = line.dataset.orderLine;
      const article = articleById(articleId);
      if (!article?.id) return;
      const sizes = readOrderSizeQuantities(form, article);
      const quantity = orderQuantityFromForm(form, article, sizes);
      if (quantity <= 0) return;
      const unitPrice = asNumber(form.elements[`price_${article.id}`]?.value);
      const sizesText = Object.entries(sizes)
        .filter(([, value]) => asNumber(value) > 0)
        .map(([size, value]) => `${size}: ${intValue(value)}`)
        .join(", ");
      items.push({ article, quantity, unitPrice, total: unitPrice * quantity, sizesText });
    });
    return items.length ? orderItemChips(items) : `<span class="shop-order-item-chip muted">Aucun article sélectionné</span>`;
  }

  function orderItemChips(items) {
    return items.map((item) => `<span class="shop-order-item-chip">
      <strong>${esc(item.article.name || "Article")}</strong>
      <em>${item.sizesText ? esc(item.sizesText) : `Qté ${intValue(item.quantity)}`}</em>
    </span>`).join("");
  }

  function orderHasSizeInputs(form, article) {
    if (typeof form?.querySelector !== "function") return false;
    return Boolean(form.querySelector(`[data-order-size-qty="${CSS.escape(article.id)}"]`));
  }

  function orderQuantityFromForm(form, article, sizes = readOrderSizeQuantities(form, article)) {
    if (orderHasSizeInputs(form, article)) {
      return Object.values(sizes).reduce((sum, value) => sum + asNumber(value), 0);
    }
    return asNumber(form.get ? form.get(`qty_${article.id}`) : form.elements?.[`qty_${article.id}`]?.value);
  }

  function readOrderSizeQuantities(form, article) {
    const sizes = {};
    for (const size of orderSizeKeys(article)) {
      const quantity = asNumber(formFieldValue(form, sizeQtyFieldName(article.id, size)));
      if (quantity) sizes[size] = quantity;
    }
    return sizes;
  }

  function formFieldValue(source, name) {
    if (typeof source?.get === "function") return source.get(name);
    return source?.elements?.[name]?.value || "";
  }

  function openStageDialog(row = {}, options = {}) {
    // Lot 2D — garde de mutation à l'ouverture : créer/modifier un stage est une mutation métier,
    // bloquée quand la fonctionnalité stages est désactivée pour le club (jamais un simple masquage).
    if (!ensureFeatureEnabledForMutation("stages")) return;
    // Club ciblé (étape 12) : mémorisé à l'ouverture, re-vérifié au submit (dialogue asynchrone).
    const openedClubId = activeClubId();
    const stage = row.id ? row : createStageDefaults();
    const isNewStage = !row.id || options.duplicate;
    const body = [
      field("name", "Nom du stage", stage.name),
      field("startDate", "Date de début", stage.startDate || "", "date"),
      field("endDate", "Date de fin", stage.endDate || "", "date"),
      field("registrationDeadline", "Date limite d'inscription", stage.registrationDeadline || "", "date"),
      `<label>Public autorisé<select name="publicAccess">
        ${["members", "prospects", "all"].map((option) => `<option value="${esc(option)}" ${normalizeStagePublicAccess(stage.publicAccess) === option ? "selected" : ""}>${esc(stagePublicAccessLabel(option))}</option>`).join("")}
      </select></label>`,
      field("unitPrice", "Prix du stage", stage.unitPrice || "", "number", 'step="0.01"'),
      field("taxRate", "TVA stage %", hasSpecificTaxRate(stage) ? tariffTaxRate(stage) : "", "number", `step="0.01" min="0" placeholder="${esc(intValue(effectiveDefaultVatRate()))}"`),
      field("investment", "Investissement stage", stage.investment || "", "number", 'step="0.01"'),
      `<div class="dialog-section"><h3>Encadrement & lieu (facultatif)</h3></div>`,
      `<div data-coach-field>${coachPickerHtml(stage.coachId, "", stage.coach, "Coach / intervenant")}</div>`,
      `<p class="stage-freeform-note">Un intervenant saisi en texte libre est conservé comme information uniquement. Il ne sera pas pris en compte dans les recherches intelligentes, les conflits de planning, les disponibilités ou les statistiques. Pour le suivre comme une vraie ressource, créez-le comme intervenant/coach enregistré.</p>`,
      `<div data-room-field>${roomPickerHtml(stage.roomId, "", stage.location, "Salle / lieu")}</div>`,
      field("lodgingName", "Nom hébergement", stage.lodgingName || ""),
      field("lodgingUnitPrice", "Prix hébergement", stage.lodgingUnitPrice || "", "number", 'step="0.01"'),
      field("lodgingTaxRate", "TVA hébergement %", hasSpecificLodgingTaxRate(stage) ? lodgingTaxRate(stage) : "", "number", `step="0.01" min="0" placeholder="${esc(intValue(effectiveDefaultVatRate()))}"`),
    ].join("");
    setNextWindowKey(isNewStage ? null : `stage:${stage.id}`);
    showDialog(isNewStage ? "Nouveau stage" : "Modifier le stage", body, (form) => {
      // Dialogue périmé (Lot 2D) : la fonctionnalité a pu être désactivée pendant que le dialogue
      // restait ouvert -> aucune mutation, aucun persist, aucun Journal (return false, avant recordHistory
      // effectif). Le club a pu changer -> ne jamais écrire dans un autre club.
      if (!ensureFeatureEnabledForMutation("stages")) return false;
      if (activeClubId() !== openedClubId) { ui.saveMessage = "Opération annulée : le club actif a changé."; return false; }
      const startDate = dateInputValue(form.get("startDate"));
      const endDate = dateInputValue(form.get("endDate"));
      const registrationDeadline = dateInputValue(form.get("registrationDeadline"));
      if (startDate && endDate && endDate < startDate) {
        alert("La date de fin ne peut pas être avant la date de début.");
        return false;
      }
      if (registrationDeadline && endDate && registrationDeadline > endDate) {
        alert("La date limite d'inscription ne peut pas être après la fin du stage.");
        return false;
      }
      const next = {
        ...stage,
        id: stage.id || id("stage"),
        name: asText(form.get("name")) || "Nouveau stage",
        startDate,
        endDate,
        registrationDeadline,
        registrationReopened: Boolean(stage.registrationReopened),
        publicAccess: normalizeStagePublicAccess(form.get("publicAccess")),
        lodgingName: asText(form.get("lodgingName")),
        unitPrice: asNumber(form.get("unitPrice")),
        lodgingUnitPrice: asNumber(form.get("lodgingUnitPrice")),
        investment: asNumber(form.get("investment")),
        coachId: asText(form.get("coachId")),
        coach: asText(form.get("coachId")) ? coachFullName(coachById(asText(form.get("coachId")))) : asText(form.get("coach")),
        roomId: asText(form.get("roomId")),
        location: asText(form.get("roomId")) ? roomName(roomById(asText(form.get("roomId")))) : asText(form.get("location")),
      };
      if (asText(form.get("taxRate"))) next.taxRate = Math.max(0, asNumber(form.get("taxRate")));
      else delete next.taxRate;
      if (asText(form.get("lodgingTaxRate"))) next.lodgingTaxRate = Math.max(0, asNumber(form.get("lodgingTaxRate")));
      else delete next.lodgingTaxRate;
      upsert(state.tariffs.stages, next);
      state.stageRegistrations[next.id] = state.stageRegistrations[next.id] || [];
      syncStageTariffToRegistrations(next);
      ui.stageId = next.id;
      // Lot 5A — journalisation : uniquement après réussite de la sauvegarde, jamais en cas
      // d'échec de validation (retours "return false" ci-dessus, jamais atteints ici).
      if (isNewStage) audit.stageCreated(next);
      else {
        const changes = stageAuditChanges(stage, next);
        if (changes.length) audit.stageUpdated(next, changes);
      }
    });
  }

  function openRegistrationStageChoiceDialog(options = {}) {
    // Lot 2D — garde de mutation : inscrire un participant est une mutation métier (bloquée quand la
    // fonctionnalité stages est désactivée). La régularisation financière d'une inscription EXISTANTE
    // reste possible par la facture de contact (billables historiques inconditionnels).
    if (!ensureFeatureEnabledForMutation("stages")) return;
    const contactLink = asText(options.contactLink || "");
    const contact = contactLink ? contactByLink(contactLink) : null;
    const link = parseContactLink(contactLink);
    const contactKind = link.kind || "member";
    const stages = (state.tariffs.stages || [])
      .filter((stage) => !stageRegistrationClosed(stage))
      .filter((stage) => !contactLink || stageAllowsContactKind(stage, contactKind));
    if (!stages.length) {
      alert(contactLink
        ? "Aucun stage ouvert à ce type de contact n'est disponible pour une nouvelle inscription."
        : "Crée d'abord un stage ouvert aux inscriptions avant d'ajouter un participant.");
      return;
    }
    const seed = contact ? registrationSeedFromContact(contact, contactLink) : {};
    if (stages.length === 1) {
      ui.stageId = stages[0].id;
      navigateTo({ view: "stages", stageId: stages[0].id, stageLetter: "" });
      openRegistrationDialog(stages[0].id, seed);
      return;
    }
    const stageOptions = stages
      .map((stage) => `<option value="${esc(stage.id)}" ${stage.id === ui.stageId ? "selected" : ""}>${esc(stage.name || "Stage")}</option>`)
      .join("");
    dialog.innerHTML = `<form>
      <div class="dialog-header"><h2>Choisir le stage</h2><button class="icon" type="button" data-dialog-close title="Fermer" aria-label="Fermer">×</button></div>
      <div class="dialog-body"><div class="form-grid">
        <label class="wide">Stage<select name="stageId">${stageOptions}</select></label>
      </div></div>
      <div class="dialog-footer">
        <span></span>
        <div class="dialog-footer-actions"><button type="button" data-dialog-close>Annuler</button><button class="primary" type="submit">Continuer</button></div>
      </div>
    </form>`;
    dialog.querySelectorAll("[data-dialog-close]").forEach((button) => button.addEventListener("click", () => dialog.close()));
    dialog.querySelector("form").addEventListener("submit", (event) => {
      event.preventDefault();
      const stageId = event.currentTarget.elements.stageId.value;
      dialog.close();
      ui.stageId = stageId;
      navigateTo({ view: "stages", stageId, stageLetter: "" });
      openRegistrationDialog(stageId, seed);
    });
    showFloatingDialog(dialog, "select[name='stageId']");
  }

  function openRegistrationDialog(stageId, row = {}) {
    // Lot 2D — garde de mutation à l'ouverture : créer/modifier une inscription est une mutation métier.
    // Bloquée quand la fonctionnalité stages est désactivée (jamais un simple masquage d'affichage). La
    // créance d'une inscription EXISTANTE reste facturable/soldable via la facture de contact générique
    // (billableItemsForContact inconditionnel) et payable via le tiroir de paiement / la facture émise.
    if (!ensureFeatureEnabledForMutation("stages")) return;
    // Club ciblé (étape 12) : mémorisé à l'ouverture, re-vérifié au submit.
    const openedClubId = activeClubId();
    // Lot 5A — capturée AVANT le merge d'affichage ci-dessous (qui complète les champs vides avec
    // le contact lié pour préremplir le formulaire) : sert de "before" fidèle pour le diff d'audit.
    const originalRegistration = row;
    // Snapshots des paiements événement/hébergement AVANT ouverture (copie profonde, jamais une
    // référence vers state), pour journaliser payment.validated/cancelled à la sauvegarde finale.
    const originalRegistrationId = row.id || "";
    const beforeEventPayments = clone(row.event?.payments || []);
    const beforeLodgingPayments = clone(row.lodging?.payments || []);
    const linkedContact = contactByLink(contactLinkForRow(row)) || {};
    row = {
      ...row,
      lastName: row.lastName || linkedContact.lastName || "",
      firstName: row.firstName || linkedContact.firstName || "",
      phone: row.phone || linkedContact.mobile || linkedContact.phone || "",
      email: row.email || linkedContact.email || "",
      address: row.address || linkedContact.address || "",
      postalCode: row.postalCode || linkedContact.postalCode || "",
      city: row.city || linkedContact.city || "",
      identityPhotoDataUrl: row.identityPhotoDataUrl || linkedContact.identityPhotoDataUrl || "",
      identityAvatarChoice: row.identityAvatarChoice || linkedContact.identityAvatarChoice || "auto",
    };
    const stage = stageById(stageId);
    if (!row.id && stageRegistrationClosed(stage)) {
      alert("Les inscriptions de ce stage sont fermées. Les paiements existants restent modifiables.");
      return;
    }
    const event = row.event || {};
    const lodging = row.lodging || {};
    const eventTotal = calcStageSegment({
      quantity: event.quantity,
      unitPrice: event.unitPrice ?? stage.unitPrice,
      discount: event.discount,
      payments: event.payments || [],
    }).subtotal;
    const lodgingTotal = calcStageSegment({
      quantity: lodging.quantity,
      unitPrice: lodging.unitPrice ?? stage.lodgingUnitPrice,
      discount: lodging.discount,
      payments: lodging.payments || [],
    }).subtotal;
    const body = [
      identityPhotoSection(row),
      identityAvatarChoiceField(row),
      stageParticipantSelectField(row, stage),
      field("lastName", "Nom *", row.lastName, "text", "required"),
      field("firstName", "Prénom *", row.firstName, "text", "required"),
      field("phone", "Téléphone *", row.phone, "text", "required"),
      field("email", "E-mail *", row.email, "email", "required"),
      `<label class="wide">${labelHtml("Adresse *")}<input name="address" type="text" value="${esc(row.address || "")}" required /></label>`,
      field("postalCode", "CP *", row.postalCode, "text", "required"),
      field("city", "Ville *", row.city, "text", "required"),
      `<div class="dialog-section"><h3>${esc(stage.name)}</h3></div>`,
      `<div class="form-grid compact stage-price-line">
        ${field("eventQty", "Nbr", event.quantity || (asNumber(stage.unitPrice) ? 1 : ""), "number", 'step="1" min="0"')}
        ${field("eventUnit", "Prix U", event.unitPrice ?? stage.unitPrice, "number", 'step="0.01" class="locked-price" readonly title="Prix défini dans la page Tarifs"')}
        ${field("eventDiscount", "Remise", event.discount || "", "number", 'step="0.01"')}
        ${paymentDueField("eventPayment", eventTotal, event.payments || [])}
      </div>`,
      paymentFields("eventPayment", event.payments || [], eventTotal, stageDefaultTaxRate(stage)),
      `<div class="dialog-section"><h3>${esc(stage.lodgingName || "Hébergement")}</h3></div>`,
      `<div class="form-grid compact stage-price-line">
        ${field("lodgingQty", "Nbr", lodging.quantity || (asNumber(stage.lodgingUnitPrice) ? 1 : ""), "number", 'step="1" min="0"')}
        ${field("lodgingUnit", "Prix U", lodging.unitPrice ?? stage.lodgingUnitPrice, "number", 'step="0.01" class="locked-price" readonly title="Prix défini dans la page Tarifs"')}
        ${field("lodgingDiscount", "Remise", lodging.discount || "", "number", 'step="0.01"')}
        ${paymentDueField("lodgingPayment", lodgingTotal, lodging.payments || [])}
      </div>`,
      paymentFields("lodgingPayment", lodging.payments || [], lodgingTotal, lodgingDefaultTaxRate(stage)),
      registrationTotalSummary(eventTotal, lodgingTotal, stage),
    ].join("");
    const footerButtons = [
      row.id ? `<button type="button" class="danger" data-action="delete-current-registration" data-stage-id="${esc(stageId)}" data-id="${esc(row.id)}">Supprimer ce participant</button>` : "",
      // Action secondaire : enregistre l'inscription, crée/récupère sa facture puis l'imprime.
      // type="button" (pas submit) pour ne PAS devenir le bouton par défaut (touche Entrée -> Enregistrer).
      `<button type="button" data-registration-print>Imprimer la facture</button>`,
      contactLinkAction(row),
    ].filter(Boolean).join("");
    setNextWindowKey(row.id ? `stage-registration:${row.id}` : null);
    showDialog(row.id ? "Modifier l'inscription stage" : "Nouvelle inscription stage", body, (form, formElement) => {
      // Dialogue périmé (Lot 2D) : re-vérifier au submit — la fonctionnalité a pu être désactivée
      // pendant que le dialogue restait ouvert -> aucune mutation, aucun persist, aucun Journal. Club
      // ciblé : ne jamais écrire dans un autre club si le club actif a changé depuis l'ouverture.
      if (!ensureFeatureEnabledForMutation("stages")) return false;
      if (activeClubId() !== openedClubId) { ui.saveMessage = "Opération annulée : le club actif a changé."; return false; }
      // Drapeau « Imprimer la facture » (posé par le bouton dédié) : lu puis effacé d'emblée, même si la
      // validation échoue, pour ne pas déclencher une impression au prochain Enregistrer normal.
      const wantsPrintInvoice = formElement.dataset.printRegistrationInvoice === "1";
      delete formElement.dataset.printRegistrationInvoice;
      if (!validateRequiredContactLike(form, ["lastName", "firstName", "phone", "email", "address", "postalCode", "city"], "Veuillez remplir tous les champs obligatoires avant d'enregistrer l'inscription au stage.")) return false;
      const contactLink = parseContactLink(form.get("contactLink"));
      if (contactLink.kind === "prospect" && !stageAllowsContactKind(stage, "prospect")) {
        alert("Ce stage est réservé aux adhérents. Choisis un stage ouvert aux non-adhérents pour ce contact.");
        return false;
      }
      if (contactLink.kind === "member" && !stageAllowsContactKind(stage, "member")) {
        alert("Ce stage est réservé aux non-adhérents.");
        return false;
      }
      const next = {
        ...row,
        id: row.id || id(`${stageId}-registration`),
        contactId: contactLink.kind === "member" ? contactLink.contactId : "",
        lastName: form.get("lastName"),
        firstName: form.get("firstName"),
        phone: form.get("phone"),
        email: form.get("email"),
        address: form.get("address"),
        postalCode: form.get("postalCode"),
        city: form.get("city"),
        identityPhotoDataUrl: isImageDataUrl(form.get("identityPhotoDataUrl")) ? form.get("identityPhotoDataUrl") : "",
        identityAvatarChoice: normalizeIdentityAvatarChoice(form.get("identityAvatarChoice")),
        event: {
          quantity: asNumber(form.get("eventQty")),
          unitPrice: asNumber(form.get("eventUnit")),
          discount: asNumber(form.get("eventDiscount")),
          payments: readPayments(form, "eventPayment", formElement),
        },
        lodging: {
          quantity: asNumber(form.get("lodgingQty")),
          unitPrice: asNumber(form.get("lodgingUnit")),
          discount: asNumber(form.get("lodgingDiscount")),
          payments: readPayments(form, "lodgingPayment", formElement),
        },
      };
      if (contactLink.kind === "prospect") next.prospectContactId = contactLink.contactId;
      else next.prospectContactId = next.contactId ? "" : syncProspectContact(next, row);
      if (next.contactId || next.prospectContactId) updateLinkedContactCoordinates(next);
      upsert(state.stageRegistrations[stageId], next);
      // Lot 5A — journalisation : uniquement après réussite de la sauvegarde (les "return false"
      // de validation ci-dessus ne descendent jamais jusqu'ici).
      if (!originalRegistration.id) audit.stageRegistrationCreated(next, stage);
      else {
        const changes = registrationAuditChanges(originalRegistration, next, stage);
        if (changes.length) audit.stageRegistrationUpdated(next, stage, changes);
      }
      // Paiements événement/hébergement : journalisation UNIQUEMENT si l'inscription existait déjà
      // avant l'ouverture, et uniquement pour les transitions réellement persistées. moduleKind
      // "registration" pour l'événement, "lodging" pour l'hébergement (résolu par paymentAuditContext
      // via context.part === "lodging" — jamais un moduleKind inventé).
      if (originalRegistrationId) {
        logPaymentAuditTransitions(paymentAuditTransitions(beforeEventPayments, next.event.payments), { module: "registration", id: next.id, stageId });
        logPaymentAuditTransitions(paymentAuditTransitions(beforeLodgingPayments, next.lodging.payments), { module: "registration", part: "lodging", id: next.id, stageId });
      }
      const message = `${row.id ? "Modification de l'inscription stage" : "Inscription stage"} de ${personLabel(next)} au stage ${stage.name || "Stage"}`;
      // Bouton « Imprimer la facture » : l'inscription est désormais enregistrée -> on déclenche la
      // création/récupération puis l'impression de sa facture après la sauvegarde.
      return wantsPrintInvoice
        ? { message, printRegistrationInvoice: { stageId, registrationId: next.id } }
        : message;
    }, (form) => {
      // « Imprimer la facture » : pose le drapeau puis déclenche la sauvegarde normale (mêmes
      // validations). Après save, le flux générique enchaîne création/récupération + impression.
      form.querySelector("[data-registration-print]")?.addEventListener("click", () => {
        form.dataset.printRegistrationInvoice = "1";
        if (typeof form.requestSubmit === "function") form.requestSubmit();
        else form.querySelector("button[type='submit']")?.click();
      });
      form.elements.contactLink?.addEventListener("change", () => {
        applyLinkedContactToForm(form);
      });
      // Uniquement les champs de segment (qté/prix/remise) : ils sont hors du bloc de paiement et
      // doivent redéclencher un recalcul complet du total (via updateRegistrationPaymentSplits).
      // Les champs de paiement eux-mêmes (montant/chèque/date/état) NE DOIVENT PAS être écoutés ici :
      // setupAutoPaymentSplit leur attache déjà ses propres écouteurs avec le bon contexte
      // "changedInput". Les réécouter ici en plus appelait distributePaymentSplit SANS changedInput
      // à chaque frappe dans le champ montant lui-même, ce qui le vidait puis le regénérait avec la
      // suggestion automatique — effaçant silencieusement une saisie manuelle en cours, exactement la
      // suppression interdite par la décision produit.
      form.querySelectorAll("[name='eventQty'], [name='eventUnit'], [name='eventDiscount'], [name='lodgingQty'], [name='lodgingUnit'], [name='lodgingDiscount']").forEach((input) => {
        input.addEventListener("input", () => updateRegistrationPaymentSplits(form, stage));
        input.addEventListener("change", () => updateRegistrationPaymentSplits(form, stage));
      });
      updateRegistrationPaymentSplits(form, stage);
    }, footerButtons);
  }

  function registrationTotalSummary(eventSubtotal, lodgingSubtotal, stage = {}) {
    const combined = eventSubtotal + lodgingSubtotal;
    const visible = eventSubtotal > 0;
    return `<div class="dialog-section tariff-summary registration-total-summary" data-registration-total-summary ${visible ? "" : "hidden"}>
      <div class="registration-total-grid">
        <div><span>${esc(stage.name || "Stage")}</span><strong data-reg-total="event">${money(eventSubtotal)}</strong></div>
        <div><span>${esc(stage.lodgingName || "Hébergement")}</span><strong data-reg-total="lodging">${money(lodgingSubtotal)}</strong></div>
        <div><span>Total inscription</span><strong data-reg-total="combined">${money(combined)}</strong></div>
      </div>
    </div>`;
  }

  function registrationSegmentTotalFromForm(form, segment) {
    const quantity = asNumber(form.elements[`${segment}Qty`]?.value);
    const unitPrice = asNumber(form.elements[`${segment}Unit`]?.value);
    const discount = asNumber(form.elements[`${segment}Discount`]?.value);
    return Math.max(0, quantity * unitPrice - discount);
  }

  function updateRegistrationPaymentSplits(form, stage = {}) {
    const eventTotal = registrationSegmentTotalFromForm(form, "event");
    const lodgingTotal = registrationSegmentTotalFromForm(form, "lodging");
    setupAutoPaymentSplit(form, "eventPayment", eventTotal);
    setDefaultPaymentTaxRate(form, "eventPayment", stageDefaultTaxRate(stage));
    setupAutoPaymentSplit(form, "lodgingPayment", lodgingTotal);
    setDefaultPaymentTaxRate(form, "lodgingPayment", lodgingDefaultTaxRate(stage));
    const summary = form.querySelector("[data-registration-total-summary]");
    if (summary) {
      summary.querySelector('[data-reg-total="event"]').textContent = money(eventTotal);
      summary.querySelector('[data-reg-total="lodging"]').textContent = money(lodgingTotal);
      summary.querySelector('[data-reg-total="combined"]').textContent = money(eventTotal + lodgingTotal);
      summary.hidden = !eventTotal;
    }
  }

  function upsert(list, row) {
    stampRecordClubId(row);
    const index = list.findIndex((item) => item.id === row.id);
    if (index >= 0) list[index] = row;
    else list.push(row);
  }

  function syncMemberContact(membership, previous = {}) {
    const contacts = state.contacts.members;
    if (!asText(membership.lastName) && !asText(membership.firstName)) {
      return membership.contactId || previous.contactId || "";
    }

    const previousKey = personKey(previous);
    const currentKey = personKey(membership);
    let contact = contacts.find((item) => item.id && item.id === (membership.contactId || previous.contactId));
    if (!contact && previousKey !== "|") contact = contacts.find((item) => personKey(item) === previousKey);
    if (!contact && currentKey !== "|") contact = contacts.find((item) => personKey(item) === currentKey);

    if (!contact) {
      contact = {
        id: id("member"),
        email: "",
        mobile: "",
        phone: "",
        city: "",
        postalCode: "",
        address: "",
        birthDate: "",
        birthPlace: "",
        nationality: "",
      };
      contacts.push(stampRecordClubId(contact));
    }

    contact.lastName = membership.lastName;
    contact.firstName = membership.firstName;
    contact.email = membership.email || contact.email || "";
    contact.mobile = membership.mobile || contact.mobile || "";
    contact.phone = membership.phone || contact.phone || "";
    contact.address = membership.address || contact.address || "";
    contact.postalCode = membership.postalCode || contact.postalCode || "";
    contact.city = membership.city || contact.city || "";
    contact.birthDate = dateInputValue(membership.birthDate || contact.birthDate);
    contact.identityPhotoDataUrl = Object.prototype.hasOwnProperty.call(membership, "identityPhotoDataUrl") ? membership.identityPhotoDataUrl : (contact.identityPhotoDataUrl || "");
    contact.identityAvatarChoice = Object.prototype.hasOwnProperty.call(membership, "identityAvatarChoice") ? normalizeIdentityAvatarChoice(membership.identityAvatarChoice) : normalizeIdentityAvatarChoice(contact.identityAvatarChoice);
    contact.category = memberCategory(contact);
    return contact.id;
  }

  function updateLinkedContactCoordinates(source = {}) {
    const memberContact = source.contactId
      ? state.contacts.members.find((contact) => contact.id === source.contactId)
      : null;
    const prospectContact = !memberContact && source.prospectContactId
      ? state.contacts.prospects.find((contact) => contact.id === source.prospectContactId)
      : null;
    const contact = memberContact || prospectContact;
    if (!contact) return "";

    const assignIfFilled = (field, value) => {
      const text = asText(value);
      if (text) contact[field] = text;
    };
    assignIfFilled("lastName", source.lastName);
    assignIfFilled("firstName", source.firstName);
    assignIfFilled("email", source.email);
    assignIfFilled("address", source.address);
    assignIfFilled("postalCode", source.postalCode);
    assignIfFilled("city", source.city);
    const phone = asText(source.mobile || source.phone);
    if (phone) {
      contact.mobile = phone;
      contact.phone = phone;
    }
    const birthDate = dateInputValue(source.birthDate);
    if (birthDate) contact.birthDate = birthDate;
    if (isImageDataUrl(source.identityPhotoDataUrl)) contact.identityPhotoDataUrl = source.identityPhotoDataUrl;
    if (Object.prototype.hasOwnProperty.call(source, "identityAvatarChoice")) contact.identityAvatarChoice = normalizeIdentityAvatarChoice(source.identityAvatarChoice);
    if (memberContact) contact.category = memberCategory(contact);
    else contact.category = contact.category || "Non-membre";
    stampRecordClubId(contact);
    return contact.id;
  }

  function promoteProspectContactToMember(prospectId, memberId) {
    if (!prospectId || !memberId) return false;
    const existed = state.contacts.prospects.some((contact) => contact.id === prospectId);
    state.shopOrders.forEach((order) => {
      if (order.prospectContactId === prospectId) {
        order.contactId = memberId;
        order.prospectContactId = "";
      }
    });
    Object.values(state.stageRegistrations || {}).forEach((registrations) => {
      (registrations || []).forEach((registration) => {
        if (registration.prospectContactId === prospectId) {
          registration.contactId = memberId;
          registration.prospectContactId = "";
        }
      });
    });
    removeById(state.contacts.prospects, prospectId);
    return existed;
  }

  function demoteMemberContactIfNoDiscipline(memberId, prospectId, source = {}) {
    if (!memberId || !prospectId) return false;
    const hasDiscipline = state.memberships.some((membership) => membership.contactId === memberId && membership.id !== source.id && asText(membership.discipline));
    if (hasDiscipline) return false;
    const existed = state.contacts.members.some((contact) => contact.id === memberId);
    state.shopOrders.forEach((order) => {
      if (order.contactId === memberId) {
        order.prospectContactId = prospectId;
        order.contactId = "";
      }
    });
    Object.values(state.stageRegistrations || {}).forEach((registrations) => {
      (registrations || []).forEach((registration) => {
        if (registration.contactId === memberId) {
          registration.prospectContactId = prospectId;
          registration.contactId = "";
        }
      });
    });
    removeById(state.contacts.members, memberId);
    return existed;
  }

  function syncProspectContact(order, previous = {}) {
    const contacts = state.contacts.prospects;
    const hasIdentity = [order.lastName, order.firstName, order.email, order.phone, order.address, order.city].some(asText);
    if (!hasIdentity) return order.prospectContactId || previous.prospectContactId || "";

    const previousKey = personKey(previous);
    const currentKey = personKey(order);
    let contact = contacts.find((item) => item.id && item.id === (order.prospectContactId || previous.prospectContactId));
    if (!contact && previousKey !== "|") contact = contacts.find((item) => personKey(item) === previousKey);
    if (!contact && currentKey !== "|") contact = contacts.find((item) => personKey(item) === currentKey);
    if (!contact && order.email) contact = contacts.find((item) => normalizedPersonText(item.email) === normalizedPersonText(order.email));
    if (!contact && order.phone) {
      const phone = asText(order.phone).replace(/\D/g, "");
      contact = contacts.find((item) => asText(item.mobile || item.phone).replace(/\D/g, "") === phone);
    }

    if (!contact) {
      contact = {
        id: id("prospect"),
        category: "Non-membre",
        birthDate: "",
        birthPlace: "",
        nationality: "",
      };
      contacts.push(stampRecordClubId(contact));
    }

    contact.lastName = order.lastName;
    contact.firstName = order.firstName;
    contact.email = order.email || contact.email || "";
    contact.mobile = order.phone || contact.mobile || "";
    contact.phone = order.phone || contact.phone || "";
    contact.address = order.address || contact.address || "";
    contact.postalCode = order.postalCode || contact.postalCode || "";
    contact.city = order.city || contact.city || "";
    contact.identityPhotoDataUrl = Object.prototype.hasOwnProperty.call(order, "identityPhotoDataUrl") ? order.identityPhotoDataUrl : (contact.identityPhotoDataUrl || "");
    contact.identityAvatarChoice = Object.prototype.hasOwnProperty.call(order, "identityAvatarChoice") ? normalizeIdentityAvatarChoice(order.identityAvatarChoice) : normalizeIdentityAvatarChoice(contact.identityAvatarChoice);
    contact.category = contact.category || "Non-membre";
    return contact.id;
  }

  function removeById(list, rowId) {
    if (!Array.isArray(list)) return;
    const index = list.findIndex((item) => item.id === rowId);
    if (index >= 0) list.splice(index, 1);
  }

  function download(filename, content, type) {
    const isCsv = asText(type).toLowerCase().startsWith("text/csv");
    const normalizedContent = typeof content === "string" ? content.normalize("NFC") : content;
    const payload = isCsv && typeof normalizedContent === "string" && !normalizedContent.startsWith("\uFEFF")
      ? `\uFEFF${normalizedContent}`
      : normalizedContent;
    const blob = new Blob([payload], { type });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    link.remove();
    URL.revokeObjectURL(url);
  }

  function fileBlobToDataUrl(blob) {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result);
      reader.onerror = () => reject(reader.error);
      reader.readAsDataURL(blob);
    });
  }

  async function imageSourceToDataUrl(source) {
    if (isLogoDataUrl(source)) return source;
    try {
      const response = await fetch(source);
      if (!response.ok) return "";
      const blob = await response.blob();
      if (!blob.type.startsWith("image/")) return "";
      return await fileBlobToDataUrl(blob);
    } catch (error) {
      return "";
    }
  }

  // Retire explicitement les secrets de sécurité d'un objet settings destiné à l'export (Lot 4A).
  // Ne jamais exporter : hash/sel du mot de passe général, hash/sel du code de récupération. Les
  // credentials PIN ne transitent de toute façon jamais par `settings` (fichier main process séparé).
  // On ne se contente pas de « supposer qu'ils sont absents » : on les supprime activement.
  function scrubSecuritySettingsForExport(settingsObj) {
    if (!settingsObj || typeof settingsObj !== "object") return settingsObj;
    const security = settingsObj.security && typeof settingsObj.security === "object" ? { ...settingsObj.security } : {};
    delete security.passwordHash;
    delete security.passwordSalt;
    delete security.recoveryHash;
    delete security.recoverySalt;
    delete security.recoveryUpdatedAt;
    settingsObj.security = security;
    return settingsObj;
  }

  async function backupPayload() {
    saveCurrentClubPayload({ reloadActive: false });
    const backupSettings = clone(settings);
    const activeLogo = settings.logoDataUrl || await imageSourceToDataUrl(DEFAULT_LOGO);
    if (!backupSettings.logoDataUrl && isLogoDataUrl(activeLogo)) backupSettings.logoDataUrl = activeLogo;
    scrubSecuritySettingsForExport(backupSettings);
    // Le clubStore embarque les settings de CHAQUE club (donc leurs secrets de sécurité par club) :
    // on les scrub tous avant export, pas seulement ceux du club actif.
    const exportClubStore = normalizeClubStore(clubStore || rawClubStoreFromStorage());
    Object.values(exportClubStore.data || {}).forEach((payload) => {
      if (payload && payload.settings) scrubSecuritySettingsForExport(payload.settings);
    });
    return {
      kind: "mongestaclub-backup",
      version: 3,
      exportedAt: new Date().toISOString(),
      activeClubId: activeClubId(),
      clubStore: exportClubStore,
      // Utilisateurs/appartenances : données métier sauvegardables (décision produit), mais
      // jamais l'utilisateur actif de LA machine ni le système (recréé par normalisation).
      userStore: userStoreForExport(),
      // Journal d'activité : données métier exportées intégralement (aucune session locale à exclure ici).
      auditLog: auditLogForExport(),
      state: normalizeState(clone(state)),
      settings: normalizeSettings(backupSettings),
      assets: {
        logoDataUrl: isLogoDataUrl(activeLogo) ? activeLogo : "",
      },
    };
  }

  async function downloadBackupBeforeDemoData() {
    try {
      const payload = await backupPayload();
      download(DEMO_BACKUP_FILENAME, JSON.stringify(payload, null, 2), "application/json");
      return true;
    } catch (error) {
      console.error(error);
      alert("Impossible de créer la sauvegarde automatique. Les données exemple ne seront pas créées pour éviter toute perte.");
      return false;
    }
  }

